INSERT INTO public.alt_olcutler (id, kod, olcut_adi, olcut_adi_en, olcut_adi_ar, ana_baslik_id, kalite_el_kitabi) VALUES (6, 'A.1.1', 'Misyon, Vizyon, Stratejik Amaçlar ve Hedefler', 'Mission, Vision, Strategic Goals and Objectives', 'الرسالة والرؤية والأهداف والغايات الاستراتيجية', 1, '{"bgs_yeri":"Akreditasyon Bilgi Yönetim Sistemi (ABYS), Esogü İlahiyat Fakültesi Resmi İnternet Sitesi Kalite Başlığı (https://ilahiyat.ogu.edu.tr/Sayfa/Index/237/ilahiyat-fakultesi-misyon-vizyon-ve-temel-degerleri)","ic_paydaslar":"Fakülte Yönetim Birimleri, Fakülte Akademik ve İdârî Personeli, Öğrenciler, Fakülte Bünyesindeki Diğer Birimler.","dis_paydaslar":"Eskişehir İl Müftülüğü ve İlgili Birimleri, Eskişehir İl Milli Eğitim Müdürlüğü ve İlgili Birimleri, Eskişehir Gençlik ve Spor İl Müdürlüğü ve İlgili Birimleri, Eskişehir İslam İlimler Vakfı, ESOGÜ İlahiyat Fakültesi Mezun ve Mensupları Derneği(ESİLDER)","sorumlu_birim":"Kalite Güvence Sistemi Komisyonu","aciklama_metni":"Planlama Aşaması: Fakülte yönetimi tarafından akreditasyon sürecini yürütmek üzere oluşturulan komisyonun alt birimi kalite güvence sistemi birimi kurumun misyon, vizyon, stratejik amaç ve hedeflerinin belirlenmesi için planlama yapar ve çalışmalara başlar. Bu çerçevede komisyon iç, dış ve uluslararası paydaşlarıyla iş birliği çerçevesinde fakültenin misyon, vizyon, stratejik amaç ve hedeflerini belirler. Bu işbirliği, paydaşların görüşlerinin anket yoluyla alınması ve paydaşlarla toplantılar yapılması yoluyla yürütülür. İmkânlar doğrultusunda misyon ve stratejik amaçlara yönelik işlemler çalıştaylar aracılığıyla da planlanır. Ortaya çıkan planların örtüşmesi ve uyumunda fakültenin bağlı bulunduğu üniversitenin misyon, vizyon, stratejik amaç ve hedefler dikkate alınır ve planlar ona göre oluşturulur. Kurumun misyon, vizyon, stratejik amaç ve hedefleri beş yılda bir üniversitenin misyon ve stratejik amaçları gözetilerek güncellenir veya yenilenir. Misyon, vizyon, stratejik amaç ve hedeflerin belirlenmesine yönelik yöntem ve birimler açıkça tanımlanarak belirtilir.\nUygulama Aşaması: Tespit edilen yöntem ve planlar çerçevesinde çalıştay, toplantı ve görüşme faaliyetleri gerçekleştirilir. Bu süreçte, fakültenin iç, dış ve uluslararası paydaşları bu sürece dâhil edilir. Misyon, vizyon, stratejik amaç ve hedeflerin taslağı bu paydaşların görüşlerine açılır ve geri bildirimler toplanır. Toplanan geri bildirimler değerlendirilerek nihai metin oluşturulur ve akreditasyon komisyonu tarafından Fakülte Kuruluna sunulur. Fakülte Kurulu tarafından onaylanan metin kamuoyuyla paylaşılır; web sayfası, sosyal medya, afiş gibi çeşitli platformlarda yayınlanır. Fakültenin tüm iç, dış ve uluslararası paydaşlarına bilgilendirme yapılır, metnin aynı platformlarla dağılması ve yayılması sağlanır.\nKontrol Etme (İzleme-Değerlendirme) Aşaması: Akreditasyon komisyonu, fakültenin tespit edilen misyon, vizyon, stratejik amaç ve hedeflere yönelik performans göstergelerini paydaşlarının görüşlerini de dikkate alarak yılda bir olmak üzere düzenli aralıklarla izler ve gözden geçirir. Paydaşların görüşleri ve memnuniyet düzeyi anketler aracılığıyla ölçülür ve değerlendirilir. İzleme sonuçları akreditasyon komisyonu tarafından raporlanarak Fakülte Yönetim Kuruluna sunulur. \nÖnlem Alma Aşaması: İzleme ve değerlendirme sürecinden elde edilen sonuçlara göre gerekli görülen revizyon ve iyileştirme alanları belirlenir. Bu alanlara göre iyileştirme planları hazırlanır, sorumlular belirlenir ve uygulanır. Bu çerçevede misyon, vizyon, stratejik amaç ve hedeflere yönelik iyileştirmeler ve güncellemeler yapılır. İyileştirme faaliyetlerinin etkinliği takip edilir ve sonuçlar tekrar değerlendirilir ve neticeye göre önlem alınması sağlanır. \n","aciklama_metni_en":"Planning Phase:\nThe sub-unit of the Quality Assurance System, established under the commission formed by the faculty administration to carry out the accreditation process, conducts planning and initiates studies to determine the institution’s mission, vision, and strategic goals and objectives. Within this framework, the commission collaborates with internal, external, and international stakeholders to define the faculty’s mission, vision, and strategic goals and objectives. This collaboration is carried out through collecting stakeholders’ opinions via surveys and organizing meetings with stakeholders.\nWhere feasible, activities related to the mission and strategic goals are also planned through workshops. In ensuring the alignment and coherence of the resulting plans, the mission, vision, and strategic goals of the university to which the faculty is affiliated are taken into consideration, and plans are developed accordingly. The institution’s mission, vision, and strategic goals and objectives are updated or renewed every five years in accordance with the university’s mission and strategic priorities. The methods and responsible units for determining the mission, vision, and strategic objectives are clearly defined and stated.\n\nImplementation Phase:\nIn line with the identified methods and plans, workshops, meetings, and consultation activities are conducted. During this process, the faculty’s internal, external, and international stakeholders are actively involved. Draft versions of the mission, vision, strategic goals, and objectives are presented to these stakeholders for their input, and feedback is collected. The collected feedback is evaluated, and the final version is prepared and submitted to the Faculty Board by the accreditation commission. The text approved by the Faculty Board is shared with the public through various platforms such as the website, social media, and posters. All internal, external, and international stakeholders of the faculty are informed, and the dissemination of the text is ensured through these platforms.\n\nMonitoring and Evaluation (Control) Phase:\nThe accreditation commission regularly monitors and reviews, at least annually, the performance indicators related to the faculty’s mission, vision, and strategic goals and objectives, taking into account the opinions of stakeholders. Stakeholders’ opinions and satisfaction levels are measured and evaluated through surveys. Monitoring results are reported by the accreditation commission and submitted to the Faculty Executive Board.\n\nAction (Improvement) Phase:\nBased on the results obtained from the monitoring and evaluation process, necessary revisions and areas for improvement are identified. Improvement plans are prepared in line with these areas, responsibilities are assigned, and implementation is carried out. Within this framework, improvements and updates are made regarding the mission, vision, and strategic goals and objectives. The effectiveness of improvement activities is monitored, results are reassessed, and further actions are taken accordingly.","uygulama_alanlari":"Akademik ve İdari Personel, Öğrenciler ve Paydaşlar","ilk_planlama_tarihi":"2025-10-28","izleme_mekanizmalari":"Yüz yüze ve çevrimiçi toplantılar, anketler, toplantı ve görüşmeler","uluslararasi_paydaslar":"Uluslararası Üniversiteler ve İlahiyat Fakülteleri, Uluslararası Öğrenci ve Akademisyenler, Uluslararası Dil Kursları, Uluslararası İslam Araştırmaları Enstitüleri, Uluslararası Öğrenci Değişim Programları","performans_gostergeleri":"Görüşme ve toplantı raporları ile görüşme sonuçları","degerlendirme_iyilestirme_tarihi":"2026-06-24"}'::jsonb) ON CONFLICT (id) DO UPDATE SET olcut_adi = EXCLUDED.olcut_adi, kalite_el_kitabi = EXCLUDED.kalite_el_kitabi;
INSERT INTO public.alt_olcutler (id, kod, olcut_adi, olcut_adi_en, olcut_adi_ar, ana_baslik_id, kalite_el_kitabi) VALUES (7, 'A.1.2', 'Kalite Güvencesi, Eğitim Öğretim, Araştırma Geliştirme, Toplumsal Katkı ve Yönetim Sistemi Politikaları', 'Quality Assurance, Education and Training, Research and Development, Social Contribution and Management System Policies', 'ضمان الجودة، التعليم والتدريب، البحث والتطوير، المساهمة الاجتماعية وسياسات نظام الإدارة', 1, '{"bgs_yeri":"Akreditasyon Bilgi Yönetim Sistemi (ABYS), Esogü İlahiyat Fakültesi Resmi İnternet Sitesi Kalite Başlığı https://ilahiyat.ogu.edu.tr/Sayfa/Index/238/fakultemiz-kalite-politikasi","ic_paydaslar":"Fakülte Yönetim Birimleri, Fakülte Akademik ve İdârî Personeli, Öğrenciler, Fakülte Bünyesindeki Diğer Birimler.","dis_paydaslar":"Eskişehir İl Müftülüğü ve İlgili Birimleri, Eskişehir İl Milli Eğitim Müdürlüğü ve İlgili Birimleri, Eskişehir Gençlik ve Spor İl Müdürlüğü ve İlgili Birimleri, Eskişehir İslam İlimler Vakfı, ESOGÜ İlahiyat Fakültesi Mezun ve Mensupları Derneği(ESİLDER)","sorumlu_birim":"Kalite Güvence Sistemi Komisyonu","aciklama_metni":"Planlama Aşaması: Fakülte kalite güvencesi, eğitim-öğretim, araştırma-geliştirme, toplumsal katkı ve yönetim sistemine yönelik politikalarını belirleme noktasında bağlı olduğu üniversitenin politikalarını esas alır. Bu politikalar, fakültenin misyon, vizyon, stratejik amaç ve hedefleri doğrultusunda belirlenir ve uyarlanır. Kurumun politikalarının belirlenmesinde iç, dış ve uluslararası paydaşların işbirliğiyle hareket edilir. Bu politikaların belirlenmesinde akreditasyon komisyonunun alt birimi kalite güvence sistemi birimi sorumludur. Bu politikalar da stratejik amaç ve hedefler gibi beş yılda bir güncellenir veya üniversitenin politikalarla ilgili süreci aynen takip edilir.\nUygulama Aşaması: Üniversitenin politikalarını esas alan fakülte, politikaları paydaşlara bildirir. Bu politikaların uygulanacağı sahalar paydaşlarla işbirliği çerçevesinde görüşme, anket çalışması ve toplantılar yoluyla tespit edilerek uygulamaya konulur.\nKontrol Etme (İzleme-Değerlendirme) Aşaması: Politikalarla ilgili bahsi geçen süreçlerin takibi, kontrol ve değerlendirilmesi ilgili alt birimin sorumluluğundadır. Bu aşamanın her bir süreci paydaşlarla işbirliği çerçevesinde yürütülür. Paydaşlardan izleme, takip, iyileştirme ve güncelleme gibi konularda doğrudan destek alınarak sürece aktif bir şekilde katılmaları sağlanır.\nÖnlem Alma Aşaması: İzleme ve takip sürecinden geçirilen politikalarda sunulan raporlara göre gerekirse değişiklik ve iyileştirme yapılır. Önlem almaya dair kalite güvence sistemi biriminin yürüttüğü veya gerçekleştirdiği her faaliyet paydaşlara sunulur. Bu takdirde paydaşların önlem alma sürecine de katılmaları sağlanmış olur. Kurumun politikalarındaki eksikliklerin giderilmesi ve güncellemelerin yapılması kurumun gelişmesi ve geleceği için büyük önem arz eder.\n","aciklama_metni_en":"Planning Phase:\nIn determining its policies related to quality assurance, education and training, research and development, social contribution, and management systems, the faculty takes the policies of the affiliated university as a basis. These policies are shaped and adapted in line with the faculty’s mission, vision, strategic goals, and objectives. In the formulation of these policies, collaboration with internal, external, and international stakeholders is ensured. The unit responsible for the development of these policies is the Quality Assurance System Unit, which operates under the accreditation committee. Similar to strategic goals and objectives, these policies are updated every five years or in accordance with the university’s policy update processes.\n\nImplementation Phase:\nThe faculty, which adopts the university’s policies as a foundation, communicates these policies to its stakeholders. The areas in which these policies will be implemented are determined in cooperation with stakeholders through meetings, surveys, and consultations, and are then put into practice.\n\nControl (Monitoring and Evaluation) Phase:\nThe monitoring, control, and evaluation of the processes related to these policies are the responsibility of the relevant sub-unit. Each stage of this phase is carried out in collaboration with stakeholders. Stakeholders are actively involved in the process by providing direct input on monitoring, tracking, improvement, and updating activities.\n\nAction (Improvement) Phase:\nBased on the reports obtained through the monitoring and evaluation process, necessary revisions and improvements are made to the policies when required. All activities carried out by the Quality Assurance System Unit regarding corrective actions are shared with stakeholders. In this way, stakeholders are also ensured to be actively involved in the improvement process. Eliminating deficiencies in institutional policies and carrying out updates are of great importance for the development and future of the institution.","uygulama_alanlari":"Akademik ve İdari Personel, Öğrenciler ve Paydaşlar","ilk_planlama_tarihi":"2025-10-28","izleme_mekanizmalari":"Yüz yüze ve çevrimiçi toplantılar, anketler, toplantı ve görüşmeler","uluslararasi_paydaslar":"Uluslararası Üniversiteler ve İlahiyat Fakülteleri, Uluslararası Öğrenci ve Akademisyenler, Uluslararası Dil Kursları, Uluslararası İslam Araştırmaları Enstitüleri, Uluslararası Öğrenci Değişim Programları","performans_gostergeleri":"Görüşme ve Toplantı raporları ile anket sonuçları","degerlendirme_iyilestirme_tarihi":"2026-06-24"}'::jsonb) ON CONFLICT (id) DO UPDATE SET olcut_adi = EXCLUDED.olcut_adi, kalite_el_kitabi = EXCLUDED.kalite_el_kitabi;
INSERT INTO public.alt_olcutler (id, kod, olcut_adi, olcut_adi_en, olcut_adi_ar, ana_baslik_id, kalite_el_kitabi) VALUES (8, 'A.1.3', 'Kurumsal Performans Yönetimi', 'Corporate Performance Management', 'إدارة أداء الشركات', 1, '{"bgs_yeri":"Üniversite Bilgi Yönetim Sistemi (EBYS EnVision)","ic_paydaslar":"Fakülte Akademik ve İdari Personeli, Kalite ve Akreditasyon Komisyonu, Akademik Kurul, Öğrenci Temsilciliği","dis_paydaslar":"Eskişehir İl Müftülüğü ve İlgili Birimleri, Milli Eğitim Müdürlüğü Din Öğretimi Şubesi, Gençlik ve Spor İl Müdürlüğü, Aile ve Sosyal Hizmetler İl Müdürlüğü, Anadolu Üniversitesi Açık Öğretim Fakültesi İlahiyat Ön lisans Temsilcisi, İslam İlimler Vakfı, Mezunlar Derneği (ESİLDER), TUBİTAK ","sorumlu_birim":"Planlama: Kalite ve Akreditasyon Komisyonu Uygulama: Dekanlık Kontrol Etme: Kalite ve Akreditasyon Komisyonu Önlem alma: Dekanlık Onay: Fakülte Yönetim Kurulu","aciklama_metni":"A.1.3. Kurumsal performans yönetimi\nPlanlama Aşaması: Eskişehir Osmangazi Üniversitesi İlahiyat Fakültesi, kurumsal performans yönetimini stratejik plan, hedefler ve misyon-vizyon doğrultusunda yapılandırır. Bu kapsamda performans göstergeleri, Üniversite stratejik planıyla uyumlu şekilde belirlenir. Göstergelerin tespitinde iç ve dış paydaşların görüşleri alınır ve Fakülte Kurulu, Yönetim Kurulu, ilgili Bölüm/Anabilim Dalı Başkanlıkları, Fakülte Kalite Komisyonu gibi birimlerle iş birliği sağlanır. Fakülte özelinde yıllık hedefler ve izleme göstergeleri, Üniversitenin Kalite Komisyonu ve Üniversite Bilgi Yönetim Sistemi (EBYS EnVision) süreçleriyle entegre olarak planlanır.  \nUygulama Aşaması: Belirlenen performans göstergelerine göre akademik ve idari uygulamalar hayata geçirilir. Her öğretim yılı başında öğretim elemanları için stratejik hedeflerle uyumlu bireysel ve kurumsal eylemler tanımlanır. Yıllık faaliyet raporları ile öz değerlendirme raporları hazırlanarak hem Üniversite düzeyinde hem de Fakülte bünyesinde performans verilerinin uygulamaya etkisi kayıt altına alınır. Öğretim elemanlarının akademik faaliyetleri (yayın, proje, etkinlik katılımı vb.) ve teşvik başvuruları dijital sistemler aracılığıyla izlenir. Ayrıca personel web sayfalarında YÖKSİS ile entegre biçimde performans verileri güncellenir.\nKontrol Etme (İzleme-Değerlendirme) Aşaması: Kurumsal performans göstergeleri ve uygulamalar, Fakülte Kalite Koordinatörlüğü tarafından Haziran ve Kasım aylarında sistematik olarak izlenir ve değerlendirilir. Bu süreçte elde edilen nicel ve nitel veriler analiz edilerek rapor hâline getirilir ve Kalite Komisyonuna sunulur. Kalite Komisyonu Temmuz ve Aralık aylarında toplanarak koordinatörlüklerden gelen raporları değerlendirir. Ayrıca, iç ve dış paydaşlara yönelik memnuniyet anketleri düzenlenerek kurum algısı ve performansın paydaşlar nezdindeki yansımaları izlenir. Elde edilen izleme sonuçları, iç değerlendirme raporlarıyla birlikte performans sistemiyle entegre biçimde Üniversite Bilgi Yönetim Sistemi’ne (EBYS) işlenir.\nÖnlem Alma Aşaması: Değerlendirme ve geri bildirimler sonucunda tespit edilen aksaklıklar ve iyileştirme alanlarına yönelik düzeltici ve önleyici faaliyetler planlanır. Kalite Komisyonunun önerileri doğrultusunda Dekanlık, ilgili akademik ve idari birimlerle koordineli şekilde süreci yeniden yapılandırır. Performansın artırılmasına yönelik olarak süreçlerde revizyonlar yapılır, hedefler güncellenir, personel eğitimleri planlanır ve paydaş beklentilerine uygun yeni stratejiler geliştirilir. Böylece sürekli iyileştirme ilkesi doğrultusunda performans yönetim döngüsü sürdürülebilir hâle getirilir.\n\n\nA.1.3. Institutional Performance Management \nPlanning Phase: \nThe Faculty of Theology at Eskişehir Osmangazi University structures its institutional performance management in line with its strategic plan, objectives, and mission-vision. Within this scope, performance indicators are determined in accordance with the University''s strategic plan. The opinions of internal and external stakeholders are taken into account in determining the indicators, and cooperation is ensured with units such as the Faculty Board, the Board of Directors, the relevant Department/Division Heads, and the Faculty Quality Commission. Annual targets and monitoring indicators specific to the Faculty are planned in integration with the University''s Quality Commission and the University Information Management System (EBYS EnVision) processes. \nImplementation Phase: Academic and administrative practices are implemented according to the determined performance indicators. At the beginning of each academic year, individual and institutional actions aligned with strategic objectives are defined for faculty members. Annual activity reports and self-assessment reports are prepared to record the impact of performance data on implementation at both the University and Faculty levels. Faculty members'' academic activities (publications, projects, event participation, etc.) and incentive applications are monitored through digital systems. Furthermore, performance data is updated on personnel web pages in an integrated manner with YÖKSİS (Higher Education Information System).\nMonitoring and Evaluation Phase: Institutional performance indicators and practices are systematically monitored and evaluated by the Faculty Quality Coordination Office in June and November. Quantitative and qualitative data obtained during this process are analyzed, compiled into a report, and submitted to the Quality Commission. The Quality Commission meets in July and December to evaluate the reports received from the coordination offices. Additionally, satisfaction surveys are conducted for internal and external stakeholders to monitor institutional perception and the impact of performance on stakeholders. The monitoring results, along with internal evaluation reports, are integrated into the University Information \nManagement System (EBYS) in a manner consistent with the performance system. Action Plan: Corrective and preventive actions are planned for the identified shortcomings and areas for improvement based on the evaluation and feedback. In line with the recommendations of the Quality Commission, the Dean''s Office, in coordination with relevant academic and administrative units, restructures the process. Revisions are made to processes to improve performance, targets are updated, personnel training is planned, and new strategies are developed in line with stakeholder expectations. Thus, the performance management cycle is made sustainable in accordance with the principle of continuous improvement.","uygulama_alanlari":"Tüm Fakülte","ilk_planlama_tarihi":"2025-07-01","izleme_mekanizmalari":"İç ve dış paydaş memnuniyet anketleri, Odak grup görüşmeleri, Etkinlik değerlendirme formları, Yıllık faaliyet raporları","uluslararasi_paydaslar":"Erasmus/Mevlana kapsamında anlaşmalı yurtdışı üniversiteler, Diyanet İşleri Başkanlığı Dış İlişkiler Birimi, Yurtdışı Türkler ve Akraba Toplulukları Başkanlığı (YTB), İslam dünyasındaki İlahiyat Fakülteleri","performans_gostergeleri":"Akademik Teşvik sıralamaları, AVESİS Verileri","degerlendirme_iyilestirme_tarihi":"2026-07-01"}'::jsonb) ON CONFLICT (id) DO UPDATE SET olcut_adi = EXCLUDED.olcut_adi, kalite_el_kitabi = EXCLUDED.kalite_el_kitabi;
INSERT INTO public.alt_olcutler (id, kod, olcut_adi, olcut_adi_en, olcut_adi_ar, ana_baslik_id, kalite_el_kitabi) VALUES (9, 'A.2.1', 'Birim Kalite Komisyonu', 'Unit Quality Commission', 'لجنة الجودة بالوحدة', 1, '{"bgs_yeri":"Üniversite Bilgi Yönetim Sistemi (EBYS EnVision)","ic_paydaslar":"Fakülte Akademik ve İdari Personeli, Kalite ve Akreditasyon Komisyonu, Akademik Kurul, Öğrenci Temsilciliği","dis_paydaslar":"Eskişehir İl Müftülüğü ve İlgili Birimleri, Milli Eğitim Müdürlüğü Din Öğretimi Şubesi, Gençlik ve Spor İl Müdürlüğü, Aile ve Sosyal Hizmetler İl Müdürlüğü, Anadolu Üniversitesi Açık Öğretim Fakültesi İlahiyat Ön lisans Temsilcisi, İslam İlimler Vakfı, Mezunlar Derneği (ESİLDER), TUBİTAK ","sorumlu_birim":"Planlama: Kalite ve Akreditasyon Komisyonu Uygulama: Dekanlık Kontrol Etme: Kalite ve Akreditasyon Komisyonu Önlem alma: Dekanlık Onay: Fakülte Yönetim Kurulu","aciklama_metni":"Planlama Aşaması: Eskişehir Osmangazi Üniversitesi İlahiyat Fakültesi Kalite Komisyonu, Üniversitenin kalite politikaları, stratejik hedefleri ve İlahiyat Fakültesi özelinde planlanarak oluşturulur. Komisyon; Dekan, ilgili Dekan Yardımcısı, Bölüm/Anabilim Dalı temsilcileri, Fakülte Sekreteri, öğrenci temsilcisi ve Kalite Koordinatörlüğü üyelerinden oluşur. Komisyonun yapılanması, Rektörlük Kalite Ofisi ile uyumlu biçimde belirlenir. Fakültenin kalite kültürünü geliştirmeye yönelik temel ilkeler, bu aşamada komisyon üyelerinin görev tanımları ve alt komisyonların (eğitim-öğretim, araştırma, toplumsal katkı, idari süreçler vb.) yapılandırılması ile netleştirilir.\nUygulama Aşaması: Kalite Komisyonu, Fakülte düzeyindeki kalite güvencesi süreçlerini yürütmekle yükümlüdür. Bu kapsamda, iç kalite güvencesi mekanizmalarını işletir; stratejik planla uyumlu şekilde performans hedeflerinin belirlenmesine katkı sunar. Alt komisyonlarla iş birliği içinde akademik, idari ve öğrenci odaklı süreçlerin kalite güvence esaslarına göre yürütülmesini sağlar. Üniversitenin kalite yönetim sistemi çerçevesinde düzenlenen eğitim, seminer ve çalıştaylara aktif katılım gösterir. Ayrıca komisyon, kalite süreçlerinin fakültedeki tüm çalışanlar tarafından benimsenmesi için fakülte içi bilgilendirme, yönlendirme ve bilinçlendirme faaliyetleri yürütür.\nKontrol Etme (İzleme-Değerlendirme) Aşaması: Kalite Komisyonu, her yıl Temmuz ve Aralık aylarında olmak üzere en az iki kez toplanarak kalite süreçlerinin ilerleyişini, performans göstergelerinin gerçekleşme durumunu ve paydaş memnuniyet verilerini değerlendirir. Alt komisyonlar ve ilgili koordinatörlükler tarafından hazırlanan raporlar incelenir. Bu süreçte elde edilen bulgular doğrultusunda, eğitim-öğretim, araştırma, toplumsal katkı ve idari işleyişin iyileştirilmesine dair değerlendirmeler yapılır. Komisyon ayrıca, kalite göstergelerine yönelik gelişim eğilimlerini ve Üniversitenin Kalite Komisyonundan gelen kararların fakülte içindeki yansımalarını takip eder.\nÖnlem Alma Aşaması: Kalite Komisyonu, izleme ve değerlendirme sonucunda tespit edilen gelişim alanlarına yönelik düzeltici ve önleyici faaliyet önerilerini rapor hâlinde Dekanlığa sunar. Bu öneriler, ilgili fakülte kurulları ile birlikte ele alınır, iç ve dış paydaşlardan alınan görüşlerle desteklenir ve karar alma süreçlerine dâhil edilir. Sürekli iyileştirme döngüsünün bir parçası olarak komisyon, kalite güvence sistemine entegre biçimde yeniden yapılandırma, görev güncelleme, süreç revizyonu ve kurumsal öğrenme yoluyla fakülte kalite kültürünün gelişimine katkıda bulunur.\n","aciklama_metni_en":"Planning Phase: The Quality Commission of Eskişehir Osmangazi University Faculty of Theology is established based on the university''s quality policies, strategic goals, and a plan specific to the Faculty of Theology. The commission consists of the Dean, the relevant Vice Dean, department/sub-department representatives, the Faculty Secretary, a student representative, and members of the Quality Coordination Office. The structure of the commission is determined in coordination with the Rectorate''s Quality Office. The fundamental principles for developing the faculty''s quality culture are clarified at this stage through the job descriptions of the commission members and the structuring of sub-commissions (education, research, community contribution, administrative processes, etc.). Implementation Phase: The Quality Commission is responsible for managing quality assurance processes at the faculty level. In this context, it operates internal quality assurance mechanisms; contributes to the determination of performance targets in line with the strategic plan; and, in cooperation with sub-commissions, ensures that academic, administrative, and student-focused processes are carried out according to quality assurance principles. It actively participates in training, seminars, and workshops organized within the framework of the university''s quality management system. Furthermore, the commission conducts internal faculty information, guidance, and awareness activities to ensure that quality processes are adopted by all faculty members.\nMonitoring and Evaluation Phase: The Quality Commission meets at least twice a year, in July and December, to evaluate the progress of quality processes, the status of performance indicators, and stakeholder satisfaction data. Reports prepared by subcommittees and relevant coordinators are reviewed. Based on the findings obtained in this process, evaluations are made regarding the improvement of education, research, community contribution, and administrative operations. The commission also monitors development trends regarding quality indicators and the reflection of decisions from the University''s Quality Commission within the faculty. Action Phase: The Quality Commission submits a report to the Dean''s Office with recommendations for corrective and preventive actions for the areas of development identified as a result of monitoring and evaluation. These recommendations are discussed with the relevant faculty boards, supported by opinions from internal and external stakeholders, and included in the decision-making processes. As part of a continuous improvement cycle, the commission contributes to the development of a faculty quality culture through restructuring, task updating, process revision, and organizational learning, all integrated into the quality assurance system.","uygulama_alanlari":"Akademik ve idari personel, tüm bölümler","ilk_planlama_tarihi":"2025-10-01","izleme_mekanizmalari":"İç ve dış paydaş memnuniyet anketleri, Odak grup görüşmeleri, Etkinlik değerlendirme formları, Yıllık faaliyet raporları","uluslararasi_paydaslar":"Erasmus/Mevlana kapsamında anlaşmalı yurtdışı üniversiteler, Diyanet İşleri Başkanlığı Dış İlişkiler Birimi, Yurtdışı Türkler ve Akraba Toplulukları Başkanlığı (YTB), İslam dünyasındaki İlahiyat Fakülteleri","performans_gostergeleri":"Kurumun iç ve dış paydaşları ile kalite süreçleri kapsamında gerçekleştirdiği yıllık geribildirim ve değerlendirme toplantılarının sayısı, Anket sonuçlarının yıllara göre dağılımı ","degerlendirme_iyilestirme_tarihi":"2026-07-01"}'::jsonb) ON CONFLICT (id) DO UPDATE SET olcut_adi = EXCLUDED.olcut_adi, kalite_el_kitabi = EXCLUDED.kalite_el_kitabi;
INSERT INTO public.alt_olcutler (id, kod, olcut_adi, olcut_adi_en, olcut_adi_ar, ana_baslik_id, kalite_el_kitabi) VALUES (10, 'A.2.2', 'İç Kalite Güvencesi Mekanizmaları', 'Internal Quality Assurance Mechanisms', 'آليات ضمان الجودة الداخلية', 1, NULL) ON CONFLICT (id) DO UPDATE SET olcut_adi = EXCLUDED.olcut_adi, kalite_el_kitabi = EXCLUDED.kalite_el_kitabi;
INSERT INTO public.alt_olcutler (id, kod, olcut_adi, olcut_adi_en, olcut_adi_ar, ana_baslik_id, kalite_el_kitabi) VALUES (11, 'A.2.3', 'Liderlik ve Kalite Güvencesi Kültürü', 'Culture of Leadership and Quality Assurance', 'ثقافة القيادة وضمان الجودة', 1, NULL) ON CONFLICT (id) DO UPDATE SET olcut_adi = EXCLUDED.olcut_adi, kalite_el_kitabi = EXCLUDED.kalite_el_kitabi;
INSERT INTO public.alt_olcutler (id, kod, olcut_adi, olcut_adi_en, olcut_adi_ar, ana_baslik_id, kalite_el_kitabi) VALUES (12, 'A.3.1', 'İç Paydaşlar (Çalışanlar - Akademik ve İdari Personel)', 'Internal Stakeholders (Employees - Academic and Administrative Staff)', 'أصحاب المصلحة الداخليون (الموظفون - أعضاء هيئة التدريس والإداريون)', 1, '{"bgs_yeri":"Üniversite Bilgi Yönetim Sistemi (EBYS EnVision)","ic_paydaslar":"Üniversite ve Fakülte Yönetim Birimleri, Fakülte Personeli (Akademik ve İdari), Öğrenciler, Fakülte Bünyesindeki Birimler, Üniversite İdari Birimleri, Üniversitenin Diğer Birimleri","dis_paydaslar":"Eskişehir İl Müftülüğü ve İlgili Birimleri, Milli Eğitim Müdürlüğü Din Öğretimi Şubesi, Gençlik ve Spor İl Müdürlüğü, Aile ve Sosyal Hizmetler İl Müdürlüğü, Anadolu Üniversitesi Açık Öğretim Fakültesi İlahiyat Ön lisans Temsilcisi, İslam İlimler Vakfı, Mezunlar Derneği (ESİLDER), TÜBİTAK","sorumlu_birim":"Kalite Güvence Sistemi Komisyonu","aciklama_metni":"Planlama Aşaması: Eskişehir Osmangazi Üniversitesi İlahiyat Fakültesi, iç paydaşların (üniversite ve fakülte yönetim birimleri, fakülte personeli, öğrenciler, fakülte bünyesindeki birimler, üniversite idari ve diğer birimleri) kalite güvencesi süreçlerine etkin katılımını sağlamak amacıyla sistematik bir plânlama süreci yürütmektedir. Kalite politikası ve stratejik hedefler, iç paydaş analizi ve ihtiyaç değerlendirmesi doğrultusunda şekillendirilmektedir. Fakülte öğretim elemanları, idari personel ve öğrenciler; stratejik plân, öz değerlendirme raporları ve birim faaliyet raporlarının hazırlanmasında doğrudan görev almaktadır. Öğrenci geri bildirimleri, ders değerlendirme anketleri ve iç kalite toplantılarında akademik/idari personelden alınan öneriler plânlama süreçlerinde temel veri kaynağıdır. \nUygulama Aşaması: Plânlanan stratejiler doğrultusunda, iç paydaşların katılımı çeşitli uygulamalarla aktif şekilde sağlanmaktadır. Güncellenen müfredatlar, öğrencilerin ve öğretim elemanlarının görüşleri doğrultusunda şekillendirilmekte, uluslararası kıstaslara uygun olarak öğrenme çıktılarına dayalı programlar uygulanmaktadır. Öğretim üyeleri TÜBİTAK, BAP ve kurum içi/dışı projelerde aktif olarak yer almakta, öğrencilere araştırma süreçlerinde danışmanlık yapılmaktadır. Fakülte yönetimi karar alma süreçlerine iç paydaşları dâhil etmekte; düzenli kurul toplantıları ve kalite komisyonu faaliyetleriyle şeffaf bir yönetişim ortamı oluşturmaktadır. Erasmus+ gibi programlarla öğrenci ve akademisyen hareketliliği desteklenmekte, uluslararası öğrenci ve akademisyenlerin fakülte süreçlerine uyumu sağlanmaktadır. \nKontrol Etme (İzleme-Değerlendirme) Aşaması: Yürütülen faaliyetlerin etkinliği, iç paydaşların katkı düzeyi ve kalite hedeflerine ulaşma durumu düzenli olarak ölçülmekte ve değerlendirilmektedir. Öğrenci memnuniyet anketleri, personel memnuniyet formları ve ders değerlendirme formları gibi araçlarla sistematik veri toplanmaktadır. Mezuniyet oranları, proje çıktıları, kurum içi kurulların çalışma raporları ve uluslararası değişim sayıları gibi performans göstergeleri belirlenmiş ve izlenmektedir. Kalite komisyonu ve bölüm kurulları toplantıları ile iç paydaşlardan alınan geri bildirimler değerlendirilmekte; süreçlerin güçlü ve geliştirilmesi gereken yönleri tespit edilmektedir. \nÖnlem Alma Aşaması: İç paydaşlardan elde edilen değerlendirme sonuçları doğrultusunda gerekli iyileştirme ve güncellemeler yapılmakta, kurum içi kalite kültürü sürekli olarak geliştirilmektedir. Tespit edilen eksiklikler ve personel/öğrenci talepleri için somut eylem plânları hazırlanmakta, ilgili birimlerce uygulamaya konulmaktadır. İç paydaş geri bildirimlerine ve değişen akademik koşullara göre kalite politikaları ve yönetim süreçleri revize edilmektedir. Her eğitim-öğretim dönemi sonunda yapılan değerlendirmeler ışığında programlar, ders içerikleri ve yönetim uygulamaları yeniden şekillendirilmektedir. \n","aciklama_metni_en":"Planning Phase\nEskişehir Osmangazi University Faculty of Theology conducts a systematic planning process to ensure the active participation of internal stakeholders (university and faculty management units, faculty staff, students, internal units of the faculty, as well as university administrative and other departments) in quality assurance processes. The quality policy and strategic goals are shaped in line with internal stakeholder analysis and needs assessment. Faculty members, administrative staff, and students take part directly in the preparation of the strategic plan, self-assessment reports, and unit activity reports. Student feedback, course evaluation surveys, and suggestions gathered from academic/administrative staff during internal quality meetings serve as the primary data sources for the planning processes.\n\nImplementation Phase\nIn line with the planned strategies, the active participation of internal stakeholders is ensured through various practices. Updated curricula are shaped according to the views of students and faculty members, and programs based on learning outcomes are implemented in accordance with international criteria. Faculty members actively participate in TÜBİTAK, BAP (Scientific Research Projects), and other internal/external projects, providing mentorship to students throughout their research processes. The faculty management involves internal stakeholders in decision-making processes, fostering a transparent governance environment through regular board meetings and quality commission activities. Student and academic mobility is supported through programs like Erasmus+, and the integration of international students and academics into faculty processes is ensured.\n\nControlling (Monitoring and Evaluation) Phase\nThe effectiveness of the conducted activities, the contribution levels of internal stakeholders, and the status of achieving quality goals are regularly measured and evaluated. Systematic data is collected through tools such as student satisfaction surveys, staff satisfaction forms, and course evaluation forms. Performance indicators—including graduation rates, project outputs, working reports of internal boards, and international exchange numbers—have been established and are continuously monitored. Feedback received from internal stakeholders is evaluated through quality commission and department board meetings, allowing the identification of the strengths and areas open to improvement in the processes.\n\nAct (Improvement) Phase\nNecessary improvements and updates are carried out in line with the evaluation results obtained from internal stakeholders, and the institutional quality culture is continuously enhanced. Concrete action plans are prepared for identified deficiencies and staff/student demands, which are then put into practice by the relevant units. Quality policies and management processes are revised based on internal stakeholder feedback and changing academic conditions. Programs, course contents, and management practices are reshaped in light of the evaluations conducted at the end of each academic semester.","uygulama_alanlari":"Akademik ve İdari Personel, Öğrenciler","ilk_planlama_tarihi":"2025-07-27","izleme_mekanizmalari":"Akademik kurul toplantıları, birim kalite komisyonu toplantıları, öğrenci ve personel memnuniyet anketleri, ders değerlendirme formları, yüz yüze ve çevrimiçi görüşmeler","uluslararasi_paydaslar":"Erasmus+ ve Mevlana Değişim Programları, Uluslararası Üniversiteler ve İlahiyat Fakülteleri, Uluslararası Öğrenci ve Akademisyenler, Uluslararası Dil Kursları, Uluslararası İslam Araştırmaları Enstitüleri, Uluslararası Öğrenci Değişim Programları","performans_gostergeleri":"Kurul/komisyon toplantı raporları, anket analiz sonuçları, öz değerlendirme ve birim faaliyet raporları veri çıktıları","degerlendirme_iyilestirme_tarihi":"2026-07-27"}'::jsonb) ON CONFLICT (id) DO UPDATE SET olcut_adi = EXCLUDED.olcut_adi, kalite_el_kitabi = EXCLUDED.kalite_el_kitabi;
INSERT INTO public.alt_olcutler (id, kod, olcut_adi, olcut_adi_en, olcut_adi_ar, ana_baslik_id, kalite_el_kitabi) VALUES (13, 'A.3.2', 'Dış Paydaşlar', 'External Stakeholders', 'أصحاب المصلحة الخارجيين', 1, '{"bgs_yeri":"Üniversite Bilgi Yönetim Sistemi (EBYS EnVision)","ic_paydaslar":"Üniversite ve Fakülte Yönetim Birimleri, Fakülte Personeli (Akademik ve İdari), Öğrenciler, Fakülte Bünyesindeki Birimler, Üniversite İdari Birimleri, Üniversitenin Diğer Birimleri","dis_paydaslar":"Eskişehir İl Müftülüğü ve İlgili Birimleri, Milli Eğitim Müdürlüğü Din Öğretimi Şubesi, Gençlik ve Spor İl Müdürlüğü, Aile ve Sosyal Hizmetler İl Müdürlüğü, Anadolu Üniversitesi Açık Öğretim Fakültesi İlahiyat Ön lisans Temsilcisi, İslam İlimler Vakfı, Mezunlar Derneği (ESİLDER), TÜBİTAK","sorumlu_birim":"Kalite Güvence Sistemi Komisyonu","aciklama_metni":"Planlama Aşaması: Fakültemiz, dış paydaşların (Eskişehir İl Müftülüğü, Milli Eğitim Müdürlüğü Din Öğretimi Şubesi, Gençlik ve Spor İl Müdürlüğü, Aile ve Sosyal Hizmetler İl Müdürlüğü, Anadolu Üniversitesi AÖF İlahiyat Ön lisans Temsilcisi, İslam İlimler Vakfı, ESİLDER, TÜBİTAK ve uluslararası ortaklar) kalite süreçlerine katılımını sağlamak amacıyla kurumsal bir plânlama yürütmektedir. Mezunlar, müftülükler, Diyanet İşleri Başkanlığı temsilcileri, STK''lar ve sektör paydaşları ile gerçekleştirilen çalıştaylar, anketler ve iş birliği protokolleri sayesinde dış paydaşların beklentileri sistematik olarak analiz edilmekte; bu bilgiler program hedefleri, stratejik plân ve faaliyet plânlarına yansıtılmaktadır. \nUygulama Aşaması: Dış paydaşların beklentileri doğrultusunda şekillendirilen stratejiler; eğitim-öğretim, toplumsal katkı, araştırma-geliştirme ve uluslararasılaşma faaliyetleri kapsamında hayata geçirilmektedir. Güncellenen müfredatlar ve program çıktıları, dış paydaş ve mezun görüşleri doğrultusunda din hizmetleri ve eğitim sektörünün ihtiyaçlarına uygun hale getirilmektedir. TÜBİTAK ve dış kaynaklı projelerde dış paydaşlarla ortak çalışmalar yürütülmektedir. Erasmus+ ve Mevlana değişim programları kapsamında yabancı üniversiteler ve uluslararası ilahiyat fakülteleri ile iş birlikleri oluşturulmakta, uluslararası seminerler, dil kursları ve uluslararası İslam araştırmaları enstitüleri ile ortak faaliyetler düzenlenmektedir. \nKontrol Etme (İzleme-Değerlendirme) Aşaması: Dış paydaşların süreçlere katkı düzeyi, yürütülen kurumsal iş birliklerinin etkinliği ve toplumsal katkı hedeflerine ulaşma durumu düzenli olarak izlenmektedir. Mezun izleme çalışmaları (ESİLDER vasıtasıyla), dış paydaş memnuniyet anketleri, paydaş kurum görüşmeleri ve uluslararası ortaklardan alınan geri bildirimler veri toplama araçları olarak kullanılmaktadır. Mezunların iş bulma süreleri, paydaş kurumların mezun memnuniyet düzeyleri ve uluslararası değişim programı raporları gibi performans göstergeleri yakından takip edilmektedir. Geniş katılımlı paydaş toplantıları ile alınan geri bildirimler neticesinde dış ilişkilerin güçlü ve geliştirilmesi gereken yönleri raporlanmaktadır. \nÖnlem Alma Aşaması: Dış paydaş ve mezun anketlerinden/çalıştaylarından elde edilen değerlendirme sonuçları doğrultusunda gerekli kurumsal iyileştirmeler yapılmaktadır. Sahanın ve sektörün değişen ihtiyaçlarına, dış paydaş geri bildirimlerine göre kalite politikaları, kurumlar arası iş birliği protokolleri ve yönetim süreçleri revize edilmektedir. Her eğitim-öğretim dönemi veya faaliyet yılı sonunda yapılan bu dış değerlendirmeler ışığında müfredat yapıları, mesleki uygulama derslerinin içerikleri, uluslararası hareketlilik plânları ve toplumsal katkı odaklı yönetim uygulamaları yeniden şekillendirilmektedir. \n","aciklama_metni_en":"Planning Phase\nOur Faculty conducts institutional planning to ensure the participation of external stakeholders (Eskişehir Provincial Mufti''s Office, Provincial Directorate of National Education - Religious Education Branch, Provincial Directorate of Youth and Sports, Provincial Directorate of Family and Social Services, Anadolu University OEF Open Education Associate Degree in Theology Representative, Islamic Sciences Foundation, ESİLDER, TÜBİTAK, and international partners) in quality assurance processes. Through workshops, surveys, and cooperation protocols conducted with alumni, mufti’s offices, representatives of the Directorate of Religious Affairs, NGOs, and sectoral stakeholders, the expectations of external stakeholders are systematically analyzed. This information is subsequently reflected in program objectives, strategic plans, and action plans.\n\nImplementation Phase\nStrategies shaped in line with the expectations of external stakeholders are implemented within the scope of education-training, social contribution, research and development (R&D), and internationalization activities. Updated curricula and program outcomes are aligned with the needs of the religious services and education sectors based on external stakeholder and alumni feedback. Joint studies are carried out with external stakeholders in TÜBİTAK and externally funded projects. Within the framework of Erasmus+ and Mevlana exchange programs, collaborations are established with foreign universities and international faculties of theology, and joint activities are organized with international seminars, language courses, and international institutes of Islamic studies.\n\nControl (Monitoring and Evaluation) Phase\nThe contribution level of external stakeholders to the processes, the effectiveness of institutional collaborations, and the status of achieving social contribution goals are regularly monitored. Alumni tracking studies (via ESİLDER), external stakeholder satisfaction surveys, stakeholder institution interviews, and feedback received from international partners are utilized as data collection tools. Performance indicators such as the employment duration of graduates, the satisfaction levels of stakeholder institutions with graduates, and international exchange program reports are closely monitored. The strengths and areas of external relations that need improvement are reported as a result of feedback obtained through broad-participation stakeholder meetings.\n\nAction Phase (Continuous Improvement)\nNecessary institutional improvements are made in line with the evaluation results obtained from external stakeholder and alumni surveys/workshops. Quality policies, inter-institutional cooperation protocols, and management processes are revised according to the changing needs of the field and the sector, as well as external stakeholder feedback. In light of these external evaluations conducted at the end of each academic term or activity year, curriculum structures, the content of vocational practice courses, international mobility plans, and social contribution-oriented management practices are reshaped.","uygulama_alanlari":"Mezunlar, Sektör Paydaşları, Kamu Kurumları, STK''lar ve Uluslararası Ortaklar","ilk_planlama_tarihi":"2025-07-27","izleme_mekanizmalari":"Dış paydaş danışma kurulu toplantıları, odak grup görüşmeleri, mezun izleme çalışmaları, dış paydaş memnuniyet anketleri, protokol ve çalıştaylar","uluslararasi_paydaslar":"Erasmus+ ve Mevlana Değişim Programları, Uluslararası Üniversiteler ve İlahiyat Fakülteleri, Uluslararası Öğrenci ve Akademisyenler, Uluslararası Dil Kursları, Uluslararası İslam Araştırmaları Enstitüleri, Uluslararası Öğrenci Değişim Programları","performans_gostergeleri":"Dış paydaş toplantı ve görüşme raporları, anket analizleri, paydaş iş birliği protokol sayıları ve mezun istihdam verileri","degerlendirme_iyilestirme_tarihi":"2026-07-27"}'::jsonb) ON CONFLICT (id) DO UPDATE SET olcut_adi = EXCLUDED.olcut_adi, kalite_el_kitabi = EXCLUDED.kalite_el_kitabi;
INSERT INTO public.alt_olcutler (id, kod, olcut_adi, olcut_adi_en, olcut_adi_ar, ana_baslik_id, kalite_el_kitabi) VALUES (14, 'A.4.1', 'Uluslararasılaşma Politikası', 'Internationalization Policy', 'سياسة التدويل', 1, '{"bgs_yeri":"Üniversite Bilgi Yönetim Sistemi (EBYS EnVision)","ic_paydaslar":"Fakülte Akademik ve İdari Personeli, Kalite ve Akreditasyon Komisyonu, Akademik Kurul, Fakülte Erasmus Koordinatörlüğü, Öğrenci Temsilciliği","dis_paydaslar":"Eskişehir İl Müftülüğü ve İlgili Birimleri, Milli Eğitim Müdürlüğü Din Öğretimi Şubesi, Gençlik ve Spor İl Müdürlüğü, Aile ve Sosyal Hizmetler İl Müdürlüğü, Anadolu Üniversitesi Açık Öğretim Fakültesi İlahiyat Ön lisans Temsilcisi, İslam İlimler Vakfı, Mezunlar Derneği (ESİLDER), TUBİTAK ","sorumlu_birim":"Planlama: Kalite ve Akreditasyon Komisyonu Uygulama: Dekanlık, Erasmus+ Fakülte Koordinatörlüğü Kontrol Etme: Kalite Alt Komisyonu Önlem alma: Dekanlık Onay: Fakülte Yönetim Kurulu","aciklama_metni":"A.4.1. Uluslararasılaşma Politikası\nPlanlama Aşaması: Eskişehir Osmangazi Üniversitesi İlahiyat Fakültesi, uluslararasılaşmayı yükseköğretim alanındaki rekabet gücünün artırılması, kültürel çeşitliliğin desteklenmesi ve akademik etkileşimin güçlendirilmesi bakımından stratejik bir öncelik olarak görmektedir. Fakülte, bu doğrultuda üniversitenin belirlediği stratejik amaç ve hedefler çerçevesinde uluslararasılaşma faaliyetlerini planlamakta, yapılandırmakta ve geliştirmektedir. Fakülte, eğitim-öğretim, araştırma-geliştirme, toplumsal katkı ve yönetim alanlarında uluslararası standartlara uyumlu politikalar geliştirerek, Erasmus+ ve Mevlana gibi öğrenci ve öğretim elemanı değişim programlarından aktif şekilde faydalanarak uluslararası tanınırlığını arttırır. Ayrıca, uluslararası tanınırlığa sahip bilim insanlarının katılımıyla gerçekleştirilen sempozyum, çalıştay ve konferanslar düzenleyerek akademik düzeyde küresel bir ağın parçası olmayı hedeflemektedir.  \nUygulama Aşaması: Eskişehir Osmangazi Üniversitesi İlahiyat Fakültesi, uluslararası düzeyde ikili iş birliği protokollerinin artırılmasını ve mevcut anlaşmaların etkinliğinin yükseltilmesini öncelemektedir. Bu kapsamda, yabancı üniversitelerle sürdürülen akademik iş birliklerine yönelik ziyaretler gerçekleştirilmekte; ortak projeler, yayınlar ve öğretim faaliyetleri teşvik edilmektedir. Fakültedeki uluslararasılaşma süreci, Dekan, ilgili Dekan Yardımcısı, Fakülte Kalite Komisyonu ve fakültenin Uluslararasılaşma Kalite Alt Komisyonu tarafından; Erasmus Koordinatörlüğü, Uluslararası İlişkiler Birimi ve ilgili diğer paydaşlarla eş güdüm içerisinde yürütülmektedir. Yürütülen çalışmalar, Eskişehir Osmangazi Üniversitesi Uluslararası İlişkiler Birimi ile sürekli iletişim ve iş birliği halinde ilerletilmekte; yurtdışı eğitim, staj ve araştırma fırsatları öğrencilere duyurulmakta ve danışmanlık hizmetleri sağlanmaktadır. Fakülte paydaşlarının görüşleri alınarak süreçlere katılım teşvik edilmekte ve kalite güvencesi kapsamında sürekli iyileştirmeler hedeflenmektedir.\nKontrol Etme (İzleme-Değerlendirme) Aşaması: Eskişehir Osmangazi Üniversitesi İlahiyat Fakültesi, uluslararasılaşma politikasını üniversitenin misyonu, vizyonu ve stratejik planında yer alan hedeflerle uyumlu bir biçimde yapılandırır. Bu politika, fakülte içi akademik ve idari paydaşların katkıları, danışma kurulu önerileri ve Kalite Komisyonu’nun değerlendirmeleriyle şekillendirilir. Fakülte, Erasmus+ ve Mevlana değişim programlarının yanı sıra ikili protokoller yoluyla öğrenci ve akademik personel hareketliliğini desteklemeyi; öğretim dili kısmen yabancı dil olan programlar geliştirmeyi ve uluslararası öğrenci sayısını artırmayı hedeflemektedir. Uluslararasılaşma politikası kapsamında yapılan faaliyetler periyodik olarak gözden geçirilir, değerlendirme raporları Kalite Komisyonu tarafından hazırlanır ve Dekanlığa sunulur.\nÖnlem Alma Aşaması: İyileştirme çalışmaları, Temmuz ve Aralık aylarında yapılan değerlendirme toplantıları sonucunda tespit edilen hususlar doğrultusunda gerçekleştirilir. Fakülte yönetimi, bu süreçte hem akademik hem de idari personelin görüşlerini dikkate alarak katılımcı bir yaklaşımı benimser. Uluslararasılaşma politikası, iç kalite güvence sistemiyle bütünlük içinde sürdürülür ve sürekli gelişim anlayışı çerçevesinde güncellenir.  \n","aciklama_metni_en":"A.4.1. Internationalization Policy\nPlanning Phase: The Faculty of Theology at Eskişehir Osmangazi University regards internationalization as a strategic priority for enhancing competitiveness in higher education, promoting cultural diversity, and strengthening academic engagement. In line with the strategic goals and objectives established by the University, the Faculty systematically plans, structures, and develops its internationalization activities. By formulating policies that are aligned with international standards in the areas of education and training, research and development, community engagement, and governance, the Faculty seeks to enhance its international visibility and recognition through active participation in mobility programs such as Erasmus+ and Mevlana. Furthermore, the Faculty aims to become an integral part of the global academic community by organizing symposiums, workshops, and conferences with the participation of internationally recognized scholars, thereby fostering international academic networks and collaborations.\n\nImplementation Phase: The Faculty of Theology prioritizes increasing the number of bilateral cooperation agreements at the international level and improving the effectiveness of existing partnerships. Within this framework, academic visits are conducted to strengthen collaborations with foreign universities, while joint research projects, scholarly publications, and teaching activities are actively encouraged. The internationalization process within the Faculty is coordinated by the Dean, the relevant Vice Dean, the Faculty Quality Commission, and the Internationalization Quality Sub-Commission, in close collaboration with the Erasmus Coordination Office, the International Relations Unit, and other relevant stakeholders. All internationalization activities are carried out through continuous communication and cooperation with the International Relations Unit of Eskişehir Osmangazi University. In addition, opportunities for international education, internships, and research are regularly communicated to students, and guidance and advisory services are provided throughout the process. Stakeholder participation is encouraged through the systematic collection of feedback, and continuous improvement is pursued within the framework of quality assurance principles.\nMonitoring and Evaluation Phase: The Faculty of Theology structures its internationalization policy in alignment with the mission, vision, and strategic objectives outlined in the University''s Strategic Plan. The policy is shaped through contributions from academic and administrative stakeholders, recommendations from the Advisory Board, and evaluations conducted by the Faculty Quality Commission. The Faculty aims to support student and academic staff mobility through Erasmus+, Mevlana Exchange Programs, and bilateral agreements; to develop academic programs partially delivered in foreign languages; and to increase the number of international students. Activities conducted under the internationalization policy are periodically reviewed and evaluated, and assessment reports prepared by the Faculty Quality Commission are submitted to the Dean’s Office for further consideration and action.\nImprovement Phase: Improvement initiatives are implemented based on the findings and recommendations emerging from evaluation meetings held in July and December. Throughout this process, the Faculty administration adopts a participatory approach by taking into account the views and suggestions of both academic and administrative staff. The internationalization policy is maintained in harmony with the internal quality assurance system and is continuously reviewed and updated in accordance with the principles of continuous improvement and institutional development.\n","uygulama_alanlari":"Erasmus+ ve Mevlana değişim programları, Uluslararası ortak araştırma projeleri, Uluslararası öğrenci ve öğretim elemanı hareketliliği, Uluslararası sempozyum, çalıştay, konferans vb. akademik etkinlikler, Ortak diploma programları geliştirme çalışmaları","ilk_planlama_tarihi":"2025-07-01","izleme_mekanizmalari":"İç ve dış paydaş memnuniyet anketleri, Odak grup görüşmeleri, Etkinlik değerlendirme formları, Yıllık faaliyet raporları","uluslararasi_paydaslar":"Erasmus/Mevlana kapsamında anlaşmalı yurtdışı üniversiteler, Diyanet İşleri Başkanlığı Dış İlişkiler Birimi, Yurtdışı Türkler ve Akraba Toplulukları Başkanlığı (YTB), İslam dünyasındaki İlahiyat Fakülteleri","performans_gostergeleri":"Gelen ve giden öğrenci sayısı (Erasmus/Mevlana), Gelen ve giden öğretim elemanı sayısı, Düzenlenen uluslararası akademik etkinlik sayısı, İmzalanan uluslararası iş birliği protokol sayısı, Uluslararası öğrencilerin toplam sayısı","degerlendirme_iyilestirme_tarihi":"2026-07-15"}'::jsonb) ON CONFLICT (id) DO UPDATE SET olcut_adi = EXCLUDED.olcut_adi, kalite_el_kitabi = EXCLUDED.kalite_el_kitabi;
INSERT INTO public.alt_olcutler (id, kod, olcut_adi, olcut_adi_en, olcut_adi_ar, ana_baslik_id, kalite_el_kitabi) VALUES (15, 'A.4.2', 'Uluslararasılaşma Süreçlerinin Yönetimi ve Organizasyonel Yapısı', 'Management and Organizational Structure of Internationalization Processes', 'الإدارة والهيكل التنظيمي لعمليات التدويل', 1, '{"bgs_yeri":"Üniversite Bilgi Yönetim Sistemi (EBYS EnVision)","ic_paydaslar":"Rektörlük, Akademik ve İdari Personel, Öğrenciler, Arapça Hazırlık Koordinatörlüğü, Kalite ve Akreditasyon Komisyonu, Akademik Kurul, Fakülte Erasmus Koordinatörlüğü, Öğrenci Temsilciliği","dis_paydaslar":"Eskişehir İl Müftülüğü ve İlgili Birimleri, Milli Eğitim Müdürlüğü Din Öğretimi Şubesi, Gençlik ve Spor İl Müdürlüğü, Aile ve Sosyal Hizmetler İl Müdürlüğü, Anadolu Üniversitesi Açık Öğretim Fakültesi İlahiyat Ön lisans Temsilcisi, İslam İlimler Vakfı, Mezunlar Derneği (ESİLDER), TUBİTAK ","sorumlu_birim":"Planlama: Dekan, ilgili Dekan Yardımcısı, Erasmus+ Fakülte Koordinatörü, Uluslararasılaşma Kalite Alt Komisyonu ile Lisans ve Lisansüstü Değişim Programları Temsilcileri Uygulama: Dekanlık, Erasmus+ Fakülte Koordinatörlüğü Kontrol Etme: Kalite Güvence Sistemi Alt Komisyonu Önlem alma: Dekanlık Onay: Fakülte Yönetim Kurulu  ","aciklama_metni":"A.4.2. Uluslararasılaşma süreçlerinin yönetimi ve organizasyonel yapısı\nPlanlama Aşaması: Eskişehir Osmangazi Üniversitesi İlahiyat Fakültesi’nde uluslararasılaşma süreçlerinin planlaması; Dekan, ilgili Dekan Yardımcısı, Erasmus+ Fakülte Koordinatörü, Uluslararasılaşma Kalite Alt Komisyonu ile Lisans ve Lisansüstü Değişim Programları Temsilcilerinden oluşan bir yapı tarafından yürütülmektedir. Planlama aşamasında; Fakültenin uluslararasılaşma hedefleri, Üniversitemizin Uluslararasılaşma Strateji Belgesi doğrultusunda belirlenmekte, mevcut durum analizi yapılmakta ve kısa-orta-uzun vadeli amaçlar ortaya konmaktadır. Akademik yıl öncesinde yapılan koordinasyon toplantılarıyla ihtiyaç analizi ve süreç tasarımı gerçekleştirilir.\nUygulama Aşaması: Uluslararasılaşma uygulamaları; Erasmus+, Mevlâna, Farabi gibi öğrenci ve personel değişim programları, uluslararası öğrencilerle yürütülen akademik-danışmanlık faaliyetleri, uluslararası iş birlikleri ve ortak projeler aracılığıyla hayata geçirilmektedir. Sürecin yürütülmesi Fakülte Erasmus Koordinatörlüğü ile Uluslararası İlişkiler Birimi’nin iş birliğinde sağlanmakta; başvuru, yerleştirme, bilgilendirme, belgelerin takibi gibi işlemler belirlenmiş iş akışları doğrultusunda uygulanmaktadır. Aynı zamanda fakülte bünyesinde görev yapan temsilciler ve ilgili komisyonlar, sürecin paydaşlarla şeffaf ve etkili bir biçimde yürütülmesini sağlar.\nKontrol Etme (İzleme-Değerlendirme) Aşaması: Uygulanan faaliyetlerin etkililiği; dönem başı ve dönem sonu toplantılarında yapılan değerlendirmeler, akademik-idari personel ve öğrencilerle yapılan memnuniyet anketleri ve süreç geri bildirimleriyle izlenmektedir. Uluslararasılaşma süreciyle ilgili veriler Fakülte Kalite Güvence Sistemi Alt Komisyonu tarafından toplanır, analiz edilir ve yıllık olarak Kalite Komisyonuna rapor edilir. Kalite Komisyonu bu raporları Temmuz ve Aralık aylarında değerlendirerek Dekanlığa sunar.\nÖnlem Alma Aşaması: Fakülte Kalite Komisyonu tarafından yapılan değerlendirmeler sonucunda belirlenen aksaklıklar ve gelişim alanları doğrultusunda, Dekanlık koordinasyonunda gerekli iyileştirme çalışmaları başlatılır. Geri bildirimlere dayalı olarak süreçlerde güncellemeler yapılır, prosedürlerde revizyonlar gerçekleştirilir. Ayrıca, paydaşlardan alınan öneri ve görüşler dikkate alınarak uluslararasılaşma hedefleri yeniden şekillendirilir ve sürdürülebilir kalite iyileştirme sağlanır.\n","aciklama_metni_en":"A.4.2. Management and Organizational Structure of Internationalization Processes\nPlanning Phase: At the Faculty of Theology of Eskişehir Osmangazi University, the planning of internationalization processes is carried out through a coordinated structure consisting of the Dean, the relevant Vice Dean, the Faculty Erasmus+ Coordinator, the Internationalization Quality Sub-Commission, and representatives responsible for undergraduate and graduate exchange programs. During the planning phase, the Faculty’s internationalization objectives are determined in accordance with the University''s Internationalization Strategy Document. A comprehensive situational analysis is conducted, and short-, medium-, and long-term goals are established. Coordination meetings held prior to each academic year facilitate needs assessment, process design, and the strategic planning of internationalization activities.\nImplementation Phase: Internationalization activities are implemented through student and staff mobility programs such as Erasmus+, Mevlana, and Farabi, as well as through academic advising services provided to international students, international collaborations, and joint projects. The operational management of these processes is conducted through close cooperation between the Faculty Erasmus Coordination Office and the University''s International Relations Unit. Procedures including application management, placement processes, information dissemination, and document tracking are carried out in accordance with established workflows and institutional guidelines. Furthermore, faculty representatives and relevant commissions ensure that all internationalization processes are conducted transparently, effectively, and in collaboration with internal and external stakeholders.\nMonitoring and Evaluation Phase: The effectiveness of internationalization activities is monitored through evaluations conducted at the beginning and end of each academic term, satisfaction surveys administered to academic and administrative staff as well as students, and feedback collected throughout the implementation process. Data related to internationalization activities are collected and analyzed by the Faculty Quality Assurance System Sub-Commission and subsequently reported annually to the Faculty Quality Commission. The Quality Commission reviews these reports during its meetings held in July and December and submits its evaluations and recommendations to the Dean’s Office.\nImprovement Phase: Based on the findings and recommendations arising from evaluations conducted by the Faculty Quality Commission, necessary improvement initiatives are launched under the coordination of the Dean’s Office. Internationalization processes are updated and revised in response to stakeholder feedback, and procedural improvements are implemented where necessary. Furthermore, internationalization goals and strategies are continuously refined by taking into consideration the suggestions and opinions of stakeholders, thereby ensuring sustainable quality enhancement and the continuous development of internationalization practices.\n","uygulama_alanlari":"İç ve dış paydaş memnuniyet anketleri, Odak grup görüşmeleri, Etkinlik değerlendirme formları, Yıllık faaliyet raporları ","ilk_planlama_tarihi":"2025-07-01","izleme_mekanizmalari":"İç ve dış paydaş memnuniyet anketleri, Odak grup görüşmeleri, Etkinlik değerlendirme formları, Yıllık faaliyet raporları ","uluslararasi_paydaslar":"Erasmus+ ve Mevlana değişim programları, Öğrenci ve Personel Değişimi Yapılan Üniversiteler, Diğer Uluslararası Paydaşlar, Diyanet İşleri Başkanlığı Dış İlişkiler Birimi, Yurtdışı Türkler ve Akraba Toplulukları Başkanlığı, Uluslararası ortak araştırma projeleri, Uluslararası öğrenci ve öğretim elemanı hareketliliği, Uluslararası sempozyum, çalıştay, konferans vb. akademik etkinlikler, Ortak diploma programları geliştirme çalışmaları","performans_gostergeleri":"Gelen ve giden öğrenci sayısı (Erasmus/Mevlana), Gelen ve giden öğretim elemanı sayısı, Düzenlenen uluslararası akademik etkinlik sayısı, İmzalanan uluslararası iş birliği protokol sayısı, Uluslararası öğrencilerin toplam sayısı","degerlendirme_iyilestirme_tarihi":"2026-07-15"}'::jsonb) ON CONFLICT (id) DO UPDATE SET olcut_adi = EXCLUDED.olcut_adi, kalite_el_kitabi = EXCLUDED.kalite_el_kitabi;
INSERT INTO public.alt_olcutler (id, kod, olcut_adi, olcut_adi_en, olcut_adi_ar, ana_baslik_id, kalite_el_kitabi) VALUES (16, 'A.4.3', 'Uluslararasılaşma Kaynakları', 'Internationalization Resources', 'موارد التدويل', 1, NULL) ON CONFLICT (id) DO UPDATE SET olcut_adi = EXCLUDED.olcut_adi, kalite_el_kitabi = EXCLUDED.kalite_el_kitabi;
INSERT INTO public.alt_olcutler (id, kod, olcut_adi, olcut_adi_en, olcut_adi_ar, ana_baslik_id, kalite_el_kitabi) VALUES (17, 'A.4.4', 'Uluslararasılaşma Performansının İzlenmesi ve İyileştirilmesi', 'Monitoring and Improving Internationalization Performance', 'مراقبة وتحسين أداء التدويل', 1, NULL) ON CONFLICT (id) DO UPDATE SET olcut_adi = EXCLUDED.olcut_adi, kalite_el_kitabi = EXCLUDED.kalite_el_kitabi;
INSERT INTO public.alt_olcutler (id, kod, olcut_adi, olcut_adi_en, olcut_adi_ar, ana_baslik_id, kalite_el_kitabi) VALUES (18, 'B.1.1', 'Program Tasarım ve Onayı', 'Program Design and Approval', 'تصميم البرنامج والموافقة عليه', 2, '{"bgs_yeri":"Üniversite web sitesi ders bilgi paketi sayfası (https://ects.ogu.edu.tr/Lisans/Program/258)","ic_paydaslar":"Öğretim Elemanları ve Öğrenciler","dis_paydaslar":"Diyanet İşleri Başkanlığı’nın ildeki temsilci kurumu olan Eskişehir İl Müftülüğü,\nMillî Eğitim Bakanlığı’nın ildeki temsilci kurumu olan İl Milli Eğitim Müdürlüğü,\nEskişehir İslami İlimler Vakfı,\nEskişehir Osmangazi Üniversitesi İlahiyat Fakültesi Mezun ve Mensupları Derneği","sorumlu_birim":"Eğitim Koordinatörlüğü / Dekanlık Birim Kalite Koordinatörlüğü (İzleme, Değerlendirme)","aciklama_metni":"ESOGÜ İlahiyat Fakültesinde yeni bir lisans programı açılmak istendiğinde, süreç Dekanlığın görevlendirdiği Program Geliştirme Çalışma Birimi (PGÇB) tarafından yürütülür. Bu birim, ihtiyaç analizini yaparak gerekçe raporunu hazırlar, programın öğretim amaçlarını ve program çıktılarını belirler. Öğretim amaçları, mezunların beş ila on yıl içinde ulaşması beklenen mesleki ve kişisel gelişim düzeylerini tanımlarken, program çıktıları bu amaçlardan türetilerek mezunların sahip olması beklenen bilgi, beceri ve yetkinlikleri açıkça ifade eder. Bu çalışmalar boyunca PGÇB, hem fakülte içindeki öğretim elemanı, öğrenci ve mezun temsilcilerinin hem de Diyanet İşleri Başkanlığı, Millî Eğitim Bakanlığı gibi dış paydaşların Eskişehir’deki temsilci kurumlarından görüşlerini anket, çalıştay veya görüşme yöntemleriyle toplar. Paydaş görüşlerinin program tasarım sürecine yansıtılmasına özen gösterilir.\nÖğrenci katılımı da sürecin ayrılmaz bir parçasıdır: öğrencilere yönelik anketler uygulanır, seçmeli ders önerileri toplanıp ilgili anabilim dallarının görüşüne sunulur ve isteyen öğrenciler tasarım çalıştaylarına gözlemci olarak katılabilir. Tüm bu girdiler doğrultusunda, zorunlu-seçmeli ders dengesi kurulur, ders kazanımları program çıktılarıyla eşleştirilir ve öğrenci iş yüküne göre AKTS kredileri hesaplanarak müfredat iskeleti oluşturulur.\nTamamlanan müfredat taslağı, PGÇB Başkanı tarafından Dekana sunulur ve Dekan taslağı önce Fakülte Kurulunun görüşüne açar. Fakülte Kurulu değerlendirmesini on beş iş günü içinde PGÇB''ye bildirir; PGÇB de gelen görüşler doğrultusunda raporu güncelleyerek yeniden Fakülte Kuruluna sunar. Fakülte Kurulu, programın akademik gerekçesini, müfredat tasarımını, paydaş süreçlerini ve kaynak yeterliliğini değerlendirerek kararını verir; varsa koşul ve önerilerini yazılı olarak PGÇB''ye iletir.\nFakülte Kurulundan onay alan müfredat taslağı, Üniversite Senatosunun onayı için Rektörlüğe gönderilir. Senato onayının ardından program, Öğrenci İşleri Daire Başkanlığı tarafından bilgi sistemine işlenerek resmen uygulamaya hazır hâle gelir.\nProgramın sürdürülebilir bir işleyişi yakalaması için her eğitim-öğretim yılı sonrasında öğretim elemanları ve öğrencilerden anket yoluyla görüş istenir. Varsa gelen öneri ve istekler Eğitim Koordinatörlüğü tarafından değerlendirilerek gerekirse Fakülte Kurulu’na rapor edilir. Böylece PUKÖ eksenli bir süreç işletilmiş olur.","aciklama_metni_en":"**Translation to English:**\n\nWhen a new undergraduate program is to be opened at ESOGU Faculty of Theology, the process is carried out by the Program Development Working Unit (PGÇB) appointed by the Dean''s Office. This unit conducts the needs analysis and prepares the justification report, and determines the program''s educational objectives and program outcomes. While educational objectives define the professional and personal development levels that graduates are expected to reach within five to ten years, program outcomes are derived from these objectives and clearly express the knowledge, skills, and competencies that graduates are expected to possess. Throughout these efforts, the PGÇB collects opinions through surveys, workshops, or interviews from both faculty member, student, and graduate representatives within the faculty, as well as from external stakeholders such as the Presidency of Religious Affairs and the Ministry of National Education through their representative institutions in Eskişehir. Care is taken to ensure that stakeholder opinions are reflected in the program design process.\n\nStudent participation is also an integral part of the process: surveys are administered to students, elective course suggestions are collected and submitted to the relevant departments for their opinion, and students who wish to do so may participate in design workshops as observers. In line with all these inputs, the balance between compulsory and elective courses is established, course learning outcomes are matched with program outcomes, and ECTS credits are calculated according to student workload to form the curriculum framework.\n\nThe completed curriculum draft is presented to the Dean by the Chair of the PGÇB, and the Dean first submits the draft for the opinion of the Faculty Board. The Faculty Board communicates its evaluation to the PGÇB within fifteen working days; the PGÇB then updates the report in line with the feedback received and resubmits it to the Faculty Board. The Faculty Board makes its decision by evaluating the program''s academic justification, curriculum design, stakeholder processes, and resource adequacy, and communicates any conditions or recommendations to the PGÇB in writing.\n\nThe curriculum draft approved by the Faculty Board is sent to the Rectorate for the approval of the University Senate. Following Senate approval, the program is entered into the information system by the Department of Student Affairs and becomes officially ready for implementation.\nIn order for the program to achieve sustainable operation, opinions are requested via survey from faculty members and students after each academic year. Any suggestions and requests received are evaluated by the Education Coordination Office and, if necessary, reported to the Faculty Board. In this way, a PDCA (Plan-Do-Check-Act)–based process is implemented.","uygulama_alanlari":"Bütün fakülte","ilk_planlama_tarihi":"2025-10-31","izleme_mekanizmalari":"Yıl sonu anketleri temel izleme mekanizması olup anket sonuçları göre gerekli iyileştirme planları sonraki yıl için yapılır.","uluslararasi_paydaslar":"","performans_gostergeleri":"Yıl sonu anketi, odak grup görüşmesi","degerlendirme_iyilestirme_tarihi":"2026-06-29"}'::jsonb) ON CONFLICT (id) DO UPDATE SET olcut_adi = EXCLUDED.olcut_adi, kalite_el_kitabi = EXCLUDED.kalite_el_kitabi;
INSERT INTO public.alt_olcutler (id, kod, olcut_adi, olcut_adi_en, olcut_adi_ar, ana_baslik_id, kalite_el_kitabi) VALUES (19, 'B.1.2', 'Program Amaçları, Çıktıları ve İAA Ölçütleri ile Uyumu', 'Program Objectives, Outputs and Compatibility with IAA Criteria', 'أهداف البرنامج ومخرجاته وتوافقه مع معايير IAA', 2, '{"bgs_yeri":"https://abys-ivory.vercel.app/tr/izlenceler","ic_paydaslar":"Öğretim Elemanları ve Öğrenciler","dis_paydaslar":"Diyanet İşleri Başkanlığı’nın ildeki temsilci kurumu olan Eskişehir İl Müftülüğü,\nMillî Eğitim Bakanlığı’nın ildeki temsilci kurumu olan İl Milli Eğitim Müdürlüğü,\nEskişehir İslami İlimler Vakfı,\nEskişehir Osmangazi Üniversitesi İlahiyat Fakültesi Mezun ve Mensupları Derneği","sorumlu_birim":"Eğitim Koordinatörlüğü, Program Geliştirme Çalışma Birimi","aciklama_metni":"Programın amaç ve çıktılarının belirlenmesinden Program Geliştirme Çalışma Birimi (PGÇB) sorumludur. Program amaçları önceki ölçütte kısmen ifade edildiği üzere program mezunlarının beş ila on yıl içinde ulaşması beklenen mesleki ve kişisel gelişim düzeylerini tanımlamaktadır. Çıktılar ise bu amaçlardan hareketle mezunların sahip olması beklenen bilgi, beceri ve yetkinlikleri ifade etmektedir.\nBu aşamanın en önemli adımlarından biri, program amaç ve çıktılarının İAA ölçütleri ile uyumuna dikkat edilmesidir. PGÇB söz konusu amaç ve çıktıları İAA ölçütlerine uyum içinde hazırlar. Ayrıca bu uyumun ders bazında da gerçekleştirilebilmesi için İAA ölçütlerinin yer aldığı matbu izlence formu hazırlanır. Dekanlık dönem başında tüm ders yürütücülerinden derslerini izlence formuna göre planlamaları ve işlemelerini ister. Ders izlencelerinin eksiksiz doldurulması için her bölümün takibiyle bir öğretim elemanı görevlendirilir. Dönem sonunda uygulanan anket ile katılımcıların bu konudaki görüşleri toplanarak gerekli görülen iyileştirme adımları sonraki eğitim öğretim yılı için planlanır.","aciklama_metni_en":"The Program Development Working Unit (PGÇB) is responsible for determining the program''s objectives and outcomes. As partially expressed in the previous criterion, program objectives define the professional and personal development levels that program graduates are expected to reach within five to ten years. Outcomes, on the other hand, express the knowledge, skills, and competencies that graduates are expected to possess, derived from these objectives.\n\nOne of the most important steps in this stage is ensuring that the program''s objectives and outcomes are aligned with İAA (İlahiyat Akreditasyon Ajansı/Theology Accreditation Agency) criteria. The PGÇB prepares these objectives and outcomes in alignment with İAA criteria. In addition, in order for this alignment to also be achieved at the course level, a standard syllabus form incorporating the İAA criteria is prepared. At the beginning of each semester, the Dean''s Office requests that all course instructors plan and conduct their courses according to this syllabus form. An academic staff member is assigned in each department to follow up and ensure that course syllabi are filled out completely. Through the survey administered at the end of the semester, participants'' opinions on this matter are collected, and the improvement steps deemed necessary are planned for the following academic year.","uygulama_alanlari":"Bütün fakülte","ilk_planlama_tarihi":"2025-10-31","izleme_mekanizmalari":"Yıl sonu anketleri temel izleme mekanizması olup anket sonuçları göre gerekli iyileştirme planları sonraki yıl için yapılır.","uluslararasi_paydaslar":"","performans_gostergeleri":"Yıl sonu anketleri","degerlendirme_iyilestirme_tarihi":"2026-06-29"}'::jsonb) ON CONFLICT (id) DO UPDATE SET olcut_adi = EXCLUDED.olcut_adi, kalite_el_kitabi = EXCLUDED.kalite_el_kitabi;
INSERT INTO public.alt_olcutler (id, kod, olcut_adi, olcut_adi_en, olcut_adi_ar, ana_baslik_id, kalite_el_kitabi) VALUES (20, 'B.1.3', 'Ders Kazanımlarının Program Çıktıları ve Disipline Özgü Çıktılar ile Eşleştirilmesi', 'Matching Course Outcomes with Program Outcomes and Discipline-Specific Outcomes', 'مطابقة نتائج الدورة مع نتائج البرنامج والنتائج الخاصة بالانضباط', 2, '{"bgs_yeri":"OGUBS / Fakülte İnternet Sitesi / Google Drive / WhatsApp Grupları","ic_paydaslar":"Akademik ve İdari Personel\nÖğrenciler\n","dis_paydaslar":"-","sorumlu_birim":"Eğitim Koordinatörlüğü Dekanlık Birim Kalite Koordinatörlüğü (İzleme, Değerlendirme)","aciklama_metni":"Fakülte, program amaçlarını, program çıktılarını, programa özgü ölçütler ve ders kazanımlarının belirlenmesi ve güncellenmesi ile ilgili süreçleri yukarıda zikredilen mevzuat çerçevesinde yürütür. Dersin amacı, on dört haftalık ders içerikleri, öğrenme çıktıları, öğretim yöntemleri, konuları, kaynakları, program çıktılarına katkı düzeyleri, değerlendirme sistemi ve AKTS-İş Yükü etkinliği öğretim elemanları tarafından belirlenerek OGUBS otomasyon sistemine işlenir. Öğrenciler bu bilgilere OGUBS kişisel şifreleri ile ulaşır. Eğitim Koordinatörlüğü derslerin ilgili öğretim elemanlarına ataması yapıldıktan sonra öğretim elemanlarının izlenceleri belirlenen esaslara göre doldurmalarını sağlar. Koordinatörlük süreç ile ilgili Dekanlığa bilgi verir. Dekanlık süreci değerlendirerek iyileştirmeye yönelik gerekli adımları atar. Ders kazanımlarının program çıktıları, disipline özgü çıktılar ile eşleştirme süreçleri Eğitim Koordinatörlüğü tarafından yürütülür.\nBirim Kalite Koordinatörlüğü Haziran ve Kasım aylarında toplanarak süreci kalite bakımından izler, tespit ve önerilerini rapor hâlinde Dekanlığa sunar. Dekanlık paydaşlarla görüşerek gerekli iyileştirmeleri yapar.\n","aciklama_metni_en":"The faculty carries out the processes related to determining and updating program objectives, program outcomes, program-specific criteria, and course learning outcomes within the framework of the aforementioned regulations. The course objective, 14-week course content, learning outcomes, teaching methods, topics, resources, contribution levels to program outcomes, assessment system, and ECTS workload are determined by faculty members and entered into the OGUBS automation system. Students access this information using their personal OGUBS passwords. After the Education Coordination Office assigns courses to the relevant faculty members, it ensures that the faculty members complete their syllabi in accordance with the established guidelines. The Coordination Office informs the Dean’s Office about the process. The Dean’s Office evaluates the process and takes the necessary steps for improvement. The processes of aligning course learning outcomes with program outcomes and discipline-specific outcomes are carried out by the Education Coordination Office.\nThe Unit Quality Coordination Office meets in June and November to monitor the process from a quality perspective and submits its findings and recommendations to the Dean’s Office in the form of a report. The Dean’s Office consults with stakeholders and implements the necessary improvements.","uygulama_alanlari":"Tüm Bölümler","ilk_planlama_tarihi":"2025-01-15","izleme_mekanizmalari":"Anketler\nOdak grup görüşmeleri\n","uluslararasi_paydaslar":"-","performans_gostergeleri":"Kazanımların Program Çıktıları ve Disipline Özgü Çıktılar ile Eşleştirilen Ders Sayısı\nDers Kazanımları Başarı Düzeyi Grafikleri \n","degerlendirme_iyilestirme_tarihi":"2025-12-30"}'::jsonb) ON CONFLICT (id) DO UPDATE SET olcut_adi = EXCLUDED.olcut_adi, kalite_el_kitabi = EXCLUDED.kalite_el_kitabi;
INSERT INTO public.alt_olcutler (id, kod, olcut_adi, olcut_adi_en, olcut_adi_ar, ana_baslik_id, kalite_el_kitabi) VALUES (21, 'B.1.4', 'Programın Yapısı ve Ders Dağılım Dengesi', 'Structure of the Program and Course Distribution Balance', 'هيكل البرنامج وتوازن توزيع الدورة', 2, '{"bgs_yeri":"OGUBS\nFakülte İnternet Sitesi\nGoogle Drive\nWhatsApp Grupları\n","ic_paydaslar":"Akademik ve İdari Personel\nÖğrenciler\n","dis_paydaslar":"İl Milli Eğitim Müdürlüğü\nİl Müftülüğü\n","sorumlu_birim":"Eğitim Koordinatörlüğü Dekanlık Birim Kalite Koordinatörlüğü (İzleme, Değerlendirme)","aciklama_metni":"Kurum, programlarında yer alan derslerin öğrenci iş yüküne dayalı kredi değerlerinin hesaplandığı bir sisteme (AKTS) sahiptir. Bu süreçte öğrenme çıktılarının 14 haftalık periyotta öğrencilere kazandırılması amaçlanır. Ders planları ders içi ve dışı tüm etkinlikler dikkate alınarak AKTS’ye uygun biçimde belirlenir.\nAKTS iş yükü, dersin kategorisi, sınav ve doküman işlemleri dersin ait olduğu Anabilim Dalı Başkanlığı tarafından dersi verecek bütün öğretim elemanlarının görüşü alınarak belirlenir. Fakülte Kurulunda görüşülen iş yükleri üniversite senatosuna sunulmak üzere Dekanlık tarafından Rektörlüğe gönderilir. Senatoda kabulünün gerçekleşmesi hâlinde tüm paydaşlarla paylaşılır. İhtiyaç hâlinde derslere ait iş yükleri eğitim-öğretim yılı başlamadan güncellenebilir. Öğrenci iş yüküne dayalı tasarımla ilgili süreç, Eğitim Koordinatörlüğü tarafından yürütülür. Birim Kalite Koordinatörlüğü de süreci kalite bakımından izler, tespit ve önerilerini Haziran ve Kasım aylarında rapor hâlinde Kalite Komisyonunda görüşülmek üzere Dekanlığa sunar. Komisyon, Temmuz ve Aralık aylarında toplanıp koordinatörlüklerden gelen raporları inceleyerek değerlendirmelerini Dekanlığa bildirir. Dekanlık, komisyonun değerlendirmeleri doğrultusunda paydaşların da görüşlerini alarak gerekli iyileştirmeleri yapar. \n","aciklama_metni_en":"The institution has a system (ECTS) in which the credit values of courses included in its programs are calculated based on the student workload. This process aims to ensure that learning outcomes are achieved by students over a 14-week period. Course syllabi are determined in accordance with ECTS, taking into account all in-class and out-of-class activities.\nThe ECTS workload, course category, and examination and documentation procedures are determined by the Department Chair to which the course belongs, after consulting with all faculty members who will teach the course. Workloads reviewed by the Faculty Council are submitted by the Dean’s Office to the Rector’s Office for presentation to the University Senate. Upon approval by the Senate, they are shared with all stakeholders. If necessary, course workloads may be updated before the start of the academic year. The process related to workload-based course design is managed by the Education Coordination Office. The Unit Quality Coordination Office also monitors the process from a quality perspective and submits its findings and recommendations to the Dean’s Office in June and November in the form of reports for discussion by the Quality Commission. The Commission meets in July and December to review the reports submitted by the coordinators’ offices and communicates its evaluations to the Dean’s Office. The Dean’s Office implements the necessary improvements in line with the Commission’s evaluations, taking into account the views of stakeholders as well. ","uygulama_alanlari":"Tüm Dersler\nTüm Bölümler\n","ilk_planlama_tarihi":"2025-09-15","izleme_mekanizmalari":"Öğrenci iş yüküne dair anket uygulanması\nWhatssApp grupları aracılığıyla bilgilendirme/haberleşme\nÖğrenci toplantıları\nBilgi sistemi\nÖğretim elemanı geri bildirimleri (Anket, odak grup görüşmesi)\n","uluslararasi_paydaslar":"-","performans_gostergeleri":"Var olan derslerin kaçında AKTS işlemlerinin öğretim elemanı ve öğrenciye sorarak tamamlandığına dair veriler\nAKTS konusundaki öğrenci memnuniyet verileri\nAKTS konusundaki öğretim elemanı memnuniyeti\n","degerlendirme_iyilestirme_tarihi":"2026-07-15"}'::jsonb) ON CONFLICT (id) DO UPDATE SET olcut_adi = EXCLUDED.olcut_adi, kalite_el_kitabi = EXCLUDED.kalite_el_kitabi;
INSERT INTO public.alt_olcutler (id, kod, olcut_adi, olcut_adi_en, olcut_adi_ar, ana_baslik_id, kalite_el_kitabi) VALUES (22, 'B.1.5', 'Öğrenci İş Yüküne Dayalı Tasarım', 'Design Based on Student Workload', 'التصميم على أساس عبء العمل الطالب', 2, '{"bgs_yeri":"OGUBS\nFakülte İnternet Sitesi\nWhatsApp Grupları\n","ic_paydaslar":"Akademik ve İdari Personel\nÖğrenciler\nFakülte Bünyesindeki Birimler\nÜniversite İdari Birimleri\n","dis_paydaslar":"İl Milli Eğitim Müdürlüğü\nİl Müftülüğü\n","sorumlu_birim":"Eğitim Koordinatörlüğü / Dekanlık / Kalite Koordinatörlüğü","aciklama_metni":"Fakültemizde sunulan derslerin AKTS kapsamında belirlenen kredi değerleri, öğrenci iş yükü temel alınarak hesaplanmaktadır. Bu süreçte, derslerin öğrenme hedeflerine ulaşması için on dört haftalık akademik takvim esas alınmaktadır. Öğrencilerin ders içi ve ders dışı tüm etkinlikleri göz önünde bulundurularak ders planları oluşturulmaktadır. Böylece, öğrencilerin bilgi ve beceri kazanımları sistematik bir yaklaşımla desteklenirken, ders planları AKTS’ye uygun şekilde belirlenmektedir.\nDers koordinatörü, tüm öğretim elemanlarının katılımıyla dersin değerlendirme gruplarını, AKTS iş yükünü, kategorisini, sınav süreçlerini ve dokümanlarını oluşturur. Ölçme ve değerlendirme süreçleri Eskişehir Osmangazi Üniversitesi Ölçme ve Değerlendirme Yönergesi''ne uygun olarak oluşturulmaktadır. İhtiyaç duyulması halinde Senato''nun belirlediği takvime göre ders verileri güncellenmektedir.\nÖğrencilerin ders seçim ve kayıt işlemleri Eskişehir Osmangazi Üniversitesi Önlisans ve Lisans Eğitim Öğretim ve Sınav Yönetmeliği’ne göre yapılmaktadır.\n\n","uygulama_alanlari":"Tüm Dersler\nTüm Bölümler\n","ilk_planlama_tarihi":"2025-09-15","izleme_mekanizmalari":"Öğrenci iş yüküne dair anket uygulanması\nWhatssApp grupları aracılığıyla bilgilendirme/haberleşme\nÖğrenci toplantıları\nBilgi sistemi\nÖğretim elemanı geri bildirimleri (Anket, odak grup görüşmesi)\n","uluslararasi_paydaslar":"-","performans_gostergeleri":"Öğrencilerin Memnuniyet verileri\nÖğretim Elemanlarının Memnuniyet verileri\n","degerlendirme_iyilestirme_tarihi":"2026-06-20"}'::jsonb) ON CONFLICT (id) DO UPDATE SET olcut_adi = EXCLUDED.olcut_adi, kalite_el_kitabi = EXCLUDED.kalite_el_kitabi;
INSERT INTO public.alt_olcutler (id, kod, olcut_adi, olcut_adi_en, olcut_adi_ar, ana_baslik_id, kalite_el_kitabi) VALUES (23, 'B.1.6', 'Ölçme ve Değerlendirme', 'Measurement and Evaluation', 'القياس والتقييم', 2, '{"bgs_yeri":"OGUBS\nFakülte İnternet Sitesi\nWhatsApp Grupları\n","ic_paydaslar":"Akademik ve İdari Personel\nÖğrenciler\nFakülte Bünyesindeki Birimler\n","dis_paydaslar":"Rektörlük","sorumlu_birim":"Eğitim Koordinatörlüğü / Dekanlık/ Kalite Koordinatörlüğü ","aciklama_metni":"Kurum, ölçme ve değerlendirmede Eskişehir Osmangazi Üniversitesi Önlisans, Lisans Öğretim ve Sınav Yönetmeliği’ni esas alır ve uygular. \nHer ders için uygulanacak ölçme ve değerlendirme yöntemleri, ders bilgi paketlerinde belirtilir ve kuruma ait web sitesinde yayınlanır. Kurumdaki mevcut dersler kapsamında dönem içi değerlendirme süreçleri; ara sınav, kısa test, ödev, sözlü değerlendirme, uygulama temelli görevler (atölye çalışmaları, seminerler) ve projeler aracılığıyla gerçekleştirilir. Bu süreçlerde, öğrencilerin bilgi, beceri ve yeterliliklerini ölçmeye yönelik yöntemler kullanılır. \nKurumumuzda yürütülen öğrenci odaklı ölçme ve değerlendirme süreci, dönem sonunda Dekanlık tarafından uygulanan ders memnuniyet anketleri ile takip edilir. Anket sonuçlarına göre geliştirilmesi veya düzeltilmesi gereken noktalar ders koordinatörüne iletilir. Yapılan iyileştirmelerin etkisi ise bir sonraki dönem gerçekleştirilen ders anketleriyle değerlendirilir.\n","uygulama_alanlari":"Tüm Bölümler, Tüm Dersler, Tüm Öğrenciler","ilk_planlama_tarihi":"2025-09-15","izleme_mekanizmalari":"Ders kazanımları üzerinde ders kazanımının ne ile ölçülüp değerlendirildiğini (soru, ödev, proje vs.) gösteren doküman, görüntü kaydı vs.","uluslararasi_paydaslar":"-","performans_gostergeleri":"Derslerin kaçta kaçında yeterlilik temelli ölçme değerlendirme yapıldığına dair gösterge","degerlendirme_iyilestirme_tarihi":"2026-06-22"}'::jsonb) ON CONFLICT (id) DO UPDATE SET olcut_adi = EXCLUDED.olcut_adi, kalite_el_kitabi = EXCLUDED.kalite_el_kitabi;
INSERT INTO public.alt_olcutler (id, kod, olcut_adi, olcut_adi_en, olcut_adi_ar, ana_baslik_id, kalite_el_kitabi) VALUES (24, 'B.2.1', 'Öğrenci Kabulü ve Önceki Öğrenmelerin Tanınması ve Kredilendirilmesi', 'Student Admission and Recognition and Crediting of Prior Learning', 'قبول الطلاب والاعتراف واعتماد التعلم السابق', 2, '{"bgs_yeri":"Fakültemize öğrenci kabulü, ÖSYM tarafından düzenlenen merkezi sınav sonuçlarına göre Yükseköğretim Kurulu (YÖK) mevzuatı çerçevesinde gerçekleştirilmektedir. Fakültemizde zorunlu olarak uygulanan Arapça Hazırlık Sınıfı için muafiyet şartları ve seviye tespit süreçleri ''Eskişehir Osmangazi Üniversitesi Yabancı Dil Eğitim-Öğretim ve Sınav Yönetmeliği'' hükümlerine uygun olarak yürütülmektedir. Eğitim-Öğretim yılı başında yapılan Arapça Muafiyet Sınavı ile öğrencilerin dil yeterlilikleri objektif kriterlerle ölçülmekte ve başarılı olanların doğrudan 1. sınıfa geçişleri sağlanmaktadır.\n\nDikey Geçiş Sınavı (DGS), Yatay Geçiş (Kurum içi/Kurumlar arası ve Merkezi Yerleştirme Puanı ile) yoluyla fakültemize kayıt yaptıran veya daha önce başka bir yükseköğretim programında öğrenim görmüş öğrencilerin ''Önceki Öğrenmelerinin Tanınması'' ve muafiyet işlemleri, İlahiyat Fakültesi İntibak ve Muafiyet Komisyonumuz tarafından titizlikle incelenmektedir. Öğrencilerin geldikleri kurumlardan aldıkları onaylı ders içerikleri ve transkriptler, TYYÇ ve İlahiyat program çıktılarımıza olan uyumu (içerik ve AKTS/Kredi dengesi) açısından değerlendirilerek Fakülte Yönetim Kurulu kararıyla kredilendirilmekte ve BYS''ye işlenmektedir.\"","ic_paydaslar":"Fakülte Sekreterliği / Web Birimi, İntibak Komisyonu ","dis_paydaslar":"Rektörlük, ESOGÜ Öğrenci İşleri Daire Başkanlığı, ÖSYM ","sorumlu_birim":"Fakülte Kurulu ve Rektörlük ","aciklama_metni":"Eskişehir Osmangazi Üniversitesi İlahiyat Fakültesi, öğrenci kabulünde Ölçme Seçme ve Yerleştirme Merkezi (ÖSYM) tarafından düzenlenen merkezi sınav sonuçlarına göre kayıt yapmaktadır. Öğrenci kontenjanları, Fakülte Kurulu’nun önerisi ile belirlenir ve Rektörlük onayı ile kesinleşir.  Fakültemize kayıt yaptıran öğrencilerin önceki formel veya enformel öğrenmelerine dair kazanımlarının tanınması, Üniversitemiz, “Ön Lisans, Lisans Programları Ders Eşdeğerlilik ve İntibak Esasları” doğrultusunda yürütülmektedir. Öğrenciler, ilgili belgeleriyle başvurarak öğrenim geçmişlerinin tanınmasını talep edebilirler. İlgili birimler tarafından en az üç kişiden oluşturulan İntibak Komisyonu, yapılan başvuruları 1 (bir) hafta içerisinde değerlendirir. Birim İntibak Komisyonu tarafından değerlendirilen formlar ilgili Fakülte Kurulu tarafından onaylanır ve imza karşılığı öğrenciye verilir. Öğrencinin ders eşdeğerliği / muafiyet talebi; daha önceki eğitimleri sırasında alıp başarmış oldukları eşdeğer kabul edilen derslere muafiyet verilerek programdan alınması gereken dersler belirlenir. Eşdeğer sayılan toplam AKTS kredisine göre intibak yapılır, intibakı yapılan derslere ilişkin daha önce alınan notlar transkripte işlenir ve not ortalamasına katılır. Hazırlık sınıfı okuyan öğrencilerin intibakı okuyacakları programa başladıklarında yapılır.  Uluslararası öğrenciler ise YÖS sınavı ile kabul edilmektedir. Tanınan öğrenmeler, öğrenim süresine ve alınacak ders yüküne etki ettiği için Fakülte Akademik Danışmanları bu süreçte öğrencilere rehberlik etmektedir.  ","uygulama_alanlari":"Tüm Dersler ve Tüm Öğrenciler ","ilk_planlama_tarihi":"2025-09-01","izleme_mekanizmalari":"Öğrenci memnuniyet anketleri, performans göstergeleri (YÖS, DGS, DBS gibi) ile sistemli izleme ve değerlendirme yapılmaktadır. ","uluslararasi_paydaslar":"Bulunmamaktadır","performans_gostergeleri":"Yıllar itibarıyla YÖS ve DGS kapsamında kayıt yaptıran öğrenci sayıları; İntibak Komisyonuna başvuran ve başvurusu 1 hafta içerisinde neticelendirilen öğrencilerin toplam başvuruya oranı (%); Muafiyet tanınarak intibakı yapılan derslerin ve aktarılan toplam AKTS kredilerinin yıllık sayısal dağılımı; Önceki öğrenmenin tanınması süreçlerine dair uygulanan paydaş memnuniyet anketi sonuçları.","degerlendirme_iyilestirme_tarihi":"2026-06-08"}'::jsonb) ON CONFLICT (id) DO UPDATE SET olcut_adi = EXCLUDED.olcut_adi, kalite_el_kitabi = EXCLUDED.kalite_el_kitabi;
INSERT INTO public.alt_olcutler (id, kod, olcut_adi, olcut_adi_en, olcut_adi_ar, ana_baslik_id, kalite_el_kitabi) VALUES (25, 'B.2.2', 'Diploma, Derece ve Diğer Yeterliliklerin Tanınması ve Sertifikalandırılması', 'Recognition and Certification of Diplomas, Degrees and Other Qualifications', 'الاعتراف وإصدار الشهادات للدبلومات والدرجات العلمية والمؤهلات الأخرى', 2, '{"bgs_yeri":"B.2.2. alt ölçütü, üniversitemiz BYS altyapısında Kalite Yönetim Sistemi / Kurumsal Özdeğerlendirme modülü altında bağımsız bir veri giriş alanı olarak konumlandırılmıştır. Bu alan; Öğrenci İşleri Bilgi Sistemi, Bologna Bilgi Paketi ve Mezuniyet Onay Ekranları ile entegre çalışmakta olup, süreçlerin dijital takibi, doğrulanması ve kanıtlandırılması bu hiyerarşik yapı üzerinden gerçekleştirilmektedir.","ic_paydaslar":"Öğrenci İşleri, Dekanlık","dis_paydaslar":"Rektörlük","sorumlu_birim":" Eğitim ve Öğretim Komisyonu ","aciklama_metni":"Eskişehir Osmangazi Üniversitesi İlahiyat Fakültesi bünyesinde mezuniyet koşullarını sağlayan öğrencilerin diploma, derece ve diğer yeterliliklerinin tanınması ile sertifikalandırılması süreçleri titizlikle ve tanımlı kurumsal prosedürlere bağlı olarak yürütülmektedir. Fakültemiz lisans programından mezun olabilmek için öğrencilerin genel not ortalamasının (GANO) en az 2.00 olması, eğitim planında yer alan tüm zorunlu ve seçmeli derslerden en az DD veya YT notu alarak başarılı olmaları ve toplamda lisansta 240 AKTS kredisini eksiksiz tamamlamaları şartı aranmaktadır. Bu mezuniyet koşullarını başarıyla yerine getiren tüm öğrencilere lisans diploması tahsis edilmektedir.  Temel lisans eğitiminin yanı sıra, kurumumuz bünyesinde yürütülen çift anadal ve yandal programlarına kabul edilen ve bu programların resmî süreçlerini başarıyla nihayete erdiren öğrencilerimiz de ek diploma ya da uzmanlık sertifikası almaya hak kazanırlar. Öğrencilerimizin muafiyet, intibak, ders eşdeğerlilik ve derece/yeterlilik tescil işlemleri, üniversitemizin yürürlükte olan “Ön Lisans ve Lisans Programları Ders Eşdeğerlilik ve İntibak Esasları” mevzuat hükümleri doğrultusunda adil, şeffaf ve denetlenebilir bir mekanizmayla gerçekleştirilmektedir.  Sürecin planlanması, takibi ve sertifikalandırma adımlarının yürütülmesi Eğitim ve Öğretim Komisyonu ile Fakülte Kurulu sorumluluğundadır. Ayrıca, disiplin cezası almamış ve yüksek akademik ortalamaya sahip başarılı öğrencilerin şeref ve yüksek şeref listelerinin belirlenerek fakülte resmî web sayfasında ilan edilmesi de bu alt ölçütün izleme ve sertifikalandırma faaliyetleri kapsamında kurumsal bir kültür olarak işletilmektedir. Tüm bu süreçler; Öğrenci İşleri Bilgi Sistemi (OGUBS), Bologna Bilgi Paketi ve Mezuniyet Onay Ekranları ile entegre bir biçimde dijital olarak izlenmekte, doğrulanmakta ve kalite güvence sistemi dahilinde sürekli iyileştirme döngüsüne tabi tutulmaktadır.  ","uygulama_alanlari":"Başarı Tescili ve Şeref Listeleri\n","ilk_planlama_tarihi":"2026-05-31","izleme_mekanizmalari":"Disiplin cezası almamış, yüksek ortalamalı öğrencilerin şeref ve yüksek şeref listelerinin Fakülte Sitesinde ilanı.","uluslararasi_paydaslar":"Uluslararası paydaş bulunmamaktadır","performans_gostergeleri":"Yıllar itibarıyla 240 AKTS kredisini ve minimum 2.00 GANO şartını tamamlayarak mezun olan öğrenci sayıları; Çift Anadal (ÇAP) ve Yandal programlarını başarıyla tamamlayarak ek diploma veya uzmanlık sertifikası almaya hak kazanan öğrenci sayıları; Mezuniyet komisyonu değerlendirme ve diploma basım/teslim sürelerindeki ortalama gün verileri; Mezuniyet, diploma ve sertifikalandırma süreçlerine yönelik yapılan öğrenci memnuniyet anketlerinin olumluluk oranı (%).","degerlendirme_iyilestirme_tarihi":"2027-06-15"}'::jsonb) ON CONFLICT (id) DO UPDATE SET olcut_adi = EXCLUDED.olcut_adi, kalite_el_kitabi = EXCLUDED.kalite_el_kitabi;
INSERT INTO public.alt_olcutler (id, kod, olcut_adi, olcut_adi_en, olcut_adi_ar, ana_baslik_id, kalite_el_kitabi) VALUES (26, 'B.3.1', 'Öğretim Yöntem ve Teknikleri', 'Teaching Methods and Techniques', 'طرق وتقنيات التدريس', 2, '{"bgs_yeri":"Öğrenci Bilgi Sistemi, Fakülte Web Sayfası, Kalite Güvence Sistemi Veri Havuzu","ic_paydaslar":"Öğretim Üyeleri, Öğrenciler, Fakülte Eğitim Koordinatörlüğü, Fakülte Kalite Komisyonu, ESOGÜ Mükemmeliyet Birimi","dis_paydaslar":"Milli Eğitim Müdürlüğü, İl Müftülüğü, Mezunlar, İAA","sorumlu_birim":"Eğitim Koordinatörlüğü, Birim Kalite Koordinatörlüğü, Fakülte Kalite Komisyonu, Dekanlık","aciklama_metni":"Fakültemiz, öğrenmenin öğrencinin aktif katılımıyla gerçekleşen bir süreç olduğu anlayışını benimser. Bu doğrultuda eğitim-öğretim faaliyetleri; öğrencilerin bilgiye erişen, bilgiyi sorgulayan, yorumlayan, farklı bakış açılarıyla ilişkilendiren ve kendi öğrenme süreçlerinde sorumluluk üstlenen bireyler olarak yetişmelerini destekleyecek şekilde yapılandırılır.\n\nÖğrenci merkezli eğitim yaklaşımı, yalnızca öğretim yöntem ve tekniklerinin çeşitlendirilmesini değil; derslerin planlanmasından öğrenme ortamlarının düzenlenmesine, öğrenci katılımının desteklenmesinden geri bildirim süreçlerine kadar tüm eğitim faaliyetlerinin öğrenen odaklı bir anlayışla yürütülmesini ifade eder. Fakültemiz bu doğrultuda öğrencilerin aktif katılımını, iş birliğini, araştırma ve sorgulamayı, eleştirel düşünmeyi ve yaşam boyu öğrenme becerilerini destekleyen öğrenme deneyimleri sunmayı hedefler.\n\nFakültemiz, öğrenci merkezli eğitim anlayışının eğitim-öğretim süreçlerine sistematik biçimde yansıtılmasını esas alır. Bu kapsamda çalışmalar Eğitim Koordinatörlüğü ve Birim Kalite Koordinatörlüğü iş birliğiyle yürütülür ve aşağıdaki alanlarda yapılandırılır:\n\n• Program ve ders tasarımı süreçlerinde öğrenme çıktıları, öğrencilerin bilgi, beceri ve yetkinlik gelişimlerini destekleyecek şekilde planlanır.\n\n• Ders izlenceleri, öğrenme çıktıları, öğretim yöntem ve teknikleri ile öğrenci iş yükü arasında uyum sağlayacak biçimde hazırlanır ve düzenli olarak güncellenir.\n\n• Derslerde öğrencilerin aktif katılımını destekleyen tartışma, grup çalışması, proje, vaka incelemesi, uygulama, sunum, araştırma ve benzeri öğrenme etkinliklerine yer verilmesi teşvik edilir.\n\n• Öğretim elemanlarının öğrenci merkezli öğrenme, öğretim yöntem ve teknikleri ile öğrenme teknolojileri konularındaki mesleki gelişimleri desteklenir.\n\n• Öğrencilerin öğrenme süreçlerine ilişkin beklenti ve deneyimlerini paylaşabilecekleri geri bildirim mekanizmaları işletilir; elde edilen bulgular eğitim-öğretim süreçlerinin geliştirilmesinde kullanılır.\n\n• Fiziksel ve dijital öğrenme ortamları, öğrenci katılımını ve etkileşimi destekleyecek şekilde geliştirilir.\n\nÖğrenci merkezli eğitim uygulamalarının etkililiği; öğrenci memnuniyet anketleri, öğretim elemanı süreç değerlendirme formları, ders başarı analizleri ve ders izlencesi incelemeleri aracılığıyla düzenli olarak izlenir. Elde edilen veriler Eğitim Koordinatörlüğü ve Fakülte Kalite Komisyonu tarafından değerlendirilerek güçlü yönler ve gelişime açık alanlar belirlenir. Değerlendirme sonuçları doğrultusunda öğretim yöntem ve teknikleri, ders tasarımları, öğrenme ortamları ve destekleyici uygulamalara ilişkin iyileştirme çalışmaları planlanır ve izlenir.\n","aciklama_metni_en":"The Faculty adopts the view that learning is a process realized through the active participation of students. Accordingly, educational activities are designed to support students in becoming individuals who can access, question, interpret, and relate knowledge to different perspectives while taking responsibility for their own learning processes.\n\nThe student-centered learning approach involves not only diversifying teaching methods and techniques but also conducting all educational activities from course planning and the organization of learning environments to the promotion of student participation and feedback processes through a learner-oriented perspective. In line with this approach, the Faculty aims to provide learning experiences that foster active participation, collaboration, inquiry, critical thinking, and lifelong learning skills.\n\nThe Faculty is committed to systematically integrating the principles of student-centered learning into all educational processes. Within this framework, activities are coordinated through the collaboration of the Educational Coordination Unit and the Unit Quality Coordination Office and are structured around the following areas:\n\n• Learning outcomes are designed to support the development of students’ knowledge, skills, and competencies within curriculum and course design processes.\n\n• Course syllabi are prepared and regularly updated to ensure alignment among learning outcomes, teaching and learning methods, and student workload.\n\n• The use of learning activities that promote active student engagement, such as discussions, group work, projects, case studies, practical applications, presentations, research activities, and similar approaches, is encouraged.\n\n• Faculty members are supported in their professional development regarding student-centered learning, teaching methods and techniques, and educational technologies.\n\n• Feedback mechanisms are maintained to enable students to share their expectations and experiences regarding the learning process, and the resulting findings are used to improve educational practices.\n\n• Physical and digital learning environments are continuously enhanced to support student participation and interaction.\n\nThe effectiveness of student-centered learning practices is regularly monitored through student satisfaction surveys, faculty process evaluation forms, course achievement analyses, and syllabus reviews. The data obtained are evaluated by the Educational Coordination Unit and the Faculty Quality Commission to identify strengths and areas for improvement. Based on the evaluation results, improvement actions related to teaching methods and techniques, course design, learning environments, and support mechanisms are planned, implemented, and monitored.\n","uygulama_alanlari":"Tüm lisans dersleri","ilk_planlama_tarihi":"2025-10-20","izleme_mekanizmalari":"Öğrenci Memnuniyet Anketi, Öğretim Üyesi Süreç Değerlendirme Formu","uluslararasi_paydaslar":"","performans_gostergeleri":"Aktif öğrenme etkinliği içeren ders oranı, öğrenci memnuniyet düzeyi","degerlendirme_iyilestirme_tarihi":"2026-07-20"}'::jsonb) ON CONFLICT (id) DO UPDATE SET olcut_adi = EXCLUDED.olcut_adi, kalite_el_kitabi = EXCLUDED.kalite_el_kitabi;
INSERT INTO public.alt_olcutler (id, kod, olcut_adi, olcut_adi_en, olcut_adi_ar, ana_baslik_id, kalite_el_kitabi) VALUES (27, 'B.3.2', 'Ölçme ve Değerlendirme', 'Measurement and Evaluation', 'القياس والتقييم', 2, '{"bgs_yeri":"Öğrenci Bilgi Sistemi, Fakülte Web sayfası, Kalite Güvence Sistemi Veri Havuzu","ic_paydaslar":"Dekanlık, Eğitim Koordinatörlüğü, Kalite Komisyonu, Öğretim Üyeleri, Öğrenciler","dis_paydaslar":"Milli Eğitim Müdürlüğü, İl Müftülüğü, Mezunlar, İAA","sorumlu_birim":"Eğitim Koordinatörlüğü, Fakülte Kalite Komisyonu, Dekanlık","aciklama_metni":"Fakültemiz, ölçme ve değerlendirme süreçlerini öğrenci merkezli öğrenme anlayışının ayrılmaz bir parçası olarak kabul eder. Ölçme ve değerlendirme yalnızca öğrenci başarısını belirlemeye yönelik bir süreç değil; öğrenmeyi destekleyen, öğretim süreçlerinin etkililiğine ilişkin veri sağlayan ve program çıktılarının gerçekleşme düzeyini ortaya koyan temel bir kalite güvencesi mekanizması olarak değerlendirilir.\n\nBu doğrultuda fakültemiz, öğrenme çıktılarıyla uyumlu, şeffaf, güvenilir, adil ve geliştirici ölçme-değerlendirme uygulamalarını yaygınlaştırmayı; öğrencilerin bilgi, beceri ve yetkinlik gelişimlerini çok boyutlu biçimde izlemeyi ve değerlendirme süreçlerini sürekli iyileştirmeyi hedefler.\n\nFakültemiz, ölçme ve değerlendirme süreçlerinin eğitim programlarının amaçları ve öğrenme çıktılarıyla uyumlu biçimde yürütülmesini esas alır. Bu kapsamda çalışmalar Eğitim Koordinatörlüğü ve Birim Kalite Koordinatörlüğü iş birliğiyle aşağıdaki alanlarda yapılandırılır:\n\n• Ölçme ve değerlendirme uygulamaları, ders öğrenme çıktıları ve program çıktılarıyla uyumlu şekilde planlanır.\n\n• Öğrencilerin bilgi, beceri ve yetkinlik gelişimlerini ortaya koyabilecek farklı ölçme ve değerlendirme araçlarının kullanılması teşvik edilir.\n\n• Değerlendirme süreçlerinde öğrencilere zamanında ve geliştirici geri bildirim sunulması desteklenir.\n\n• Ölçme ve değerlendirme uygulamalarının öğrenci iş yükü ile uyumu gözetilir.\n\n• Öğretim elemanlarının ölçme ve değerlendirme alanındaki mesleki gelişimleri desteklenir ve iyi uygulama örneklerinin paylaşılması teşvik edilir.\n\n• Öğrenci geri bildirimleri ölçme ve değerlendirme süreçlerinin geliştirilmesinde kullanılır.\n\nÖlçme ve değerlendirme süreçlerinin etkililiği; öğrenci memnuniyet anketleri, öğretim elemanı süreç değerlendirme formları, ders başarı analizleri ve ders izlencesi incelemeleri aracılığıyla düzenli olarak izlenir. Elde edilen bulgular Eğitim Koordinatörlüğü ve Fakülte Kalite Komisyonu tarafından değerlendirilerek güçlü yönler ve gelişime açık alanlar belirlenir. Değerlendirme sonuçları doğrultusunda ölçme ve değerlendirme uygulamalarına, öğrenci iş yükü planlamalarına ve öğretim elemanlarına yönelik destekleyici faaliyetlere ilişkin iyileştirme çalışmaları planlanır ve izlenir.\n","aciklama_metni_en":"The Faculty regards assessment and evaluation processes as an integral component of the student-centered learning approach. Assessment and evaluation are considered not merely as mechanisms for determining student achievement, but also as essential quality assurance tools that support learning, provide evidence regarding the effectiveness of teaching processes, and demonstrate the extent to which program learning outcomes are achieved.\n\nIn this context, the Faculty aims to promote assessment and evaluation practices that are aligned with learning outcomes and are transparent, reliable, fair, and developmental in nature. It also seeks to monitor students’ knowledge, skills, and competencies through multidimensional approaches and to continuously improve assessment and evaluation processes.\n\nThe Faculty is committed to ensuring that assessment and evaluation processes are conducted in alignment with the objectives of educational programs and intended learning outcomes. To this end, activities are coordinated through the collaboration of the Educational Coordination Unit and the Unit Quality Coordination Office and are structured around the following areas:\n\n• Assessment and evaluation practices are planned in alignment with course learning outcomes and program learning outcomes.\n\n• The use of diverse assessment and evaluation methods that can effectively demonstrate students’ knowledge, skills, and competencies is encouraged.\n\n• The provision of timely and constructive feedback to students is supported throughout the assessment process.\n\n• The alignment between assessment and evaluation practices and student workload is taken into consideration.\n\n• Faculty members are supported in their professional development related to assessment and evaluation, and the sharing of good practices is encouraged.\n\n• Student feedback is utilized in the continuous improvement of assessment and evaluation processes.\n\nThe effectiveness of assessment and evaluation processes is regularly monitored through student satisfaction surveys, faculty process evaluation forms, course achievement analyses, and syllabus reviews. The findings obtained are evaluated by the Educational Coordination Unit and the Faculty Quality Commission to identify strengths and areas for improvement. Based on these evaluations, improvement actions related to assessment and evaluation practices, student workload planning, and support activities for faculty members are planned, implemented, and monitored.","uygulama_alanlari":"Tüm lisans dersleri","ilk_planlama_tarihi":"2025-10-20","izleme_mekanizmalari":"Öğrenci Memnuniyet Anketi, Öğretim Üyesi Süreç Değerlendirme Formu","uluslararasi_paydaslar":"","performans_gostergeleri":"Birden fazla ölçme-değerlendirme aracı kullanan ders oranı (%); Ölçme ve değerlendirme süreçlerine ilişkin öğrenci memnuniyet düzeyi (%)","degerlendirme_iyilestirme_tarihi":"2026-07-20"}'::jsonb) ON CONFLICT (id) DO UPDATE SET olcut_adi = EXCLUDED.olcut_adi, kalite_el_kitabi = EXCLUDED.kalite_el_kitabi;
INSERT INTO public.alt_olcutler (id, kod, olcut_adi, olcut_adi_en, olcut_adi_ar, ana_baslik_id, kalite_el_kitabi) VALUES (28, 'B.3.3', 'Öğrenci Geri Bildirimleri', 'Student Feedback', 'ردود فعل الطلاب', 2, '{"bgs_yeri":"OGUBS","ic_paydaslar":"Eğitim Öğretim Komisyonu, Fakülte Öğrenci İşleri Birimi, Öğrenci Temsilciliği","dis_paydaslar":"Öğrenci İşleri Daire Başkanlığı","sorumlu_birim":"Eğitim Komisyonu","aciklama_metni":"B.3.3. Öğrenci Geri Bildirimleri (Ders-öğretim üyesi-program-genel memnuniyet anketleri, talep ve öneri sistemleri)\n\nÖğrenciler, istek, öneri, şikâyet ve düşüncelerini çeşitli kanallar aracılığıyla kurum yetkililerine iletebilmektedir. Bu talepler, farklı yollarla iletilmiş olsa da yetkili personel tarafından dijital ortamda arşivlenmektedir. Sisteme kaydedilen talepler, yetkili görevlilerce incelendikten sonra, fakülte ya da üniversite bünyesindeki ilgili birim ya da sorumlu kişilere yönlendirilmektedir. Öğrencilerin talep, istek ve şikayetlerini iletebilecekleri yollar aşağıda sıralanmaktadır:\n1.\tİletişim Formu: Öğrenciler fakültenin internet sayfasında yer alan ‘İletişim Formu’ ile dilek, istek ve şikayetlerini fakülte yönetimine iletebilirler. Dilek, istek ve şikayet formuna gelen mesajlar öğrenci işlerinden sorumlu dekan yardımcısının gözetiminde işleme alınır. (Web sayfasında iletişim formu oluşturulması gerekmektedir.)\n2.\tMail Adresleri: Kurumun kurumsal mail adresi ve öğrenci işleri mail adresi öğrencilerin dilek, istek ve şikayetlerini iletebilecekleri kanallar arasındadır. Bu adreslere gelen iletiler adreslerden sorumlu görevliler ve öğrenci işlerinden sorumlu dekan yardımcısının işbirliği ile işleme alınır. \n3.\tDilek, İstek ve Şikâyet Kutusu: Öğrencilerin dilek, istek ve şikayetlerini yazılı olarak iletebilecekleri dilek, istek ve şikâyet kutusu öğrenci kantininin olduğu katta yer almaktadır. Kutu her ayın ilk günü öğrenci işlerinden sorumlu dekan yardımcısı gözetiminde açılır ve Kalite Yönetimi birimi tarafından dijital ortama aktarılarak işleme alınır. (Eğer yoksa bir dilek, istek ve şikayet kutusu gereklidir)\n4.\tÖğrenci Temsilciliği: Fakülte öğrenci temsilcisi ile öğrenci işlerinden sorumlu dekan yardımcısı ve Eğitim Komisyonu güz ve bahar dönemlerinde bir toplantı yaparak öğrenci dilek, istek ve şikayetlerini görüşürler. Görüşmeler tutanak halinde kayıt altına alınır ve kayda alınan konuların takibi öğrenci işlerinden sorumlu dekan yardımcısının gözetiminde işleme alınır. \n5.\tAkademik Danışmanlık: Öğrenciler dilek, istek ve şikayetlerini akademik danışmanlarına yüzyüze ya da online olarak iletebilirler. Akademik danışmanlar kendilerine iletilen konuları öğrenci işlerinden sorumlu dekan yardımcısıyla paylaşarak sürecin takibini yaparlar. \n6.\tYüz Yüze Görüşmeler: Öğrenciler istek, dilek ve şikayetlerini; fakülte dekanı, dekan yardımcıları, fakülte sekreteri, bölüm başkanları ya da öğretim üye ve görevlileri ile yüz yüze veya online olarak yaptıkları görüşmeler aracılığıyla iletebilirler. Bu kanallarla iletilen durumlar öğrenci işlerinden sorumlu dekan yardımcısının gözetiminde değerlendirmeye alınır. \n7.\tDers ve Öğretim Üyesi Değerlendirme Anketleri: Öğrenciler her dönemin sonunda her bir ders ile ilgili ‘Ders ve Öğretim Üyesi Değerlendirme Anketi’ doldururlar. Anket verileri Öğrenci Bilgi Sistemi’ne entegre edilerek toplanır. Verilerin değerlendirmesi Eğitim Öğretim Komisyonu tarafından yapılarak rapor haline getirilir. \n8.\tGenel Memnuniyet Anketi: Fakülte için genel memnuniyet anketi her eğitim öğretim yılının son ayında fakülte web sayfası aracılığıyla toplanır ve Eğitim Öğretim Komisyonu tarafından raporlaştırılır. \n","aciklama_metni_en":"B.3.3. Student Feedback (Course–Instructor–Programme–Overall Satisfaction Surveys, Request and Suggestion Systems)\nStudents are able to communicate their requests, suggestions, complaints, and opinions to the faculty administration through various channels. Regardless of the communication method, all submissions are digitally archived by the authorized personnel. After being reviewed, each submission is forwarded to the relevant faculty or university unit or responsible staff member for further action. The available channels through which students may submit their requests, suggestions, and complaints are listed below:\nCommunication Form: Students may submit their requests, suggestions, and complaints to the faculty administration via the Communication Form available on the faculty website. Messages received through this form are processed under the supervision of the Vice Dean responsible for student affairs. (A communication form should be created on the faculty website if one is not already available.)\nInstitutional Email Addresses: Students may also communicate their requests, suggestions, and complaints through the faculty’s official email address and the Student Affairs Office email address. Messages received through these channels are processed collaboratively by the responsible administrative staff and the Vice Dean responsible for student affairs.\nRequest, Suggestion, and Complaint Box: A physical request, suggestion, and complaint box is located on the floor where the student cafeteria is situated, allowing students to submit written feedback. The box is opened on the first day of each month under the supervision of the Vice Dean responsible for student affairs. The submissions are then transferred to a digital system by the Quality Management Unit and processed accordingly. (If such a box does not already exist, one should be established.)\nStudent Representation: The Faculty Student Representative meets once during both the fall and spring semesters with the Vice Dean responsible for student affairs and the Education Commission to discuss students’ requests, suggestions, and complaints. Minutes of these meetings are prepared, and follow-up procedures are carried out under the supervision of the Vice Dean responsible for student affairs.\nAcademic Advising: Students may communicate their requests, suggestions, and complaints to their academic advisors either in person or online. Academic advisors forward these issues to the Vice Dean responsible for student affairs and monitor the follow-up process.\nFace-to-Face Meetings: Students may also communicate their requests, suggestions, and complaints through face-to-face or online meetings with the Dean, Vice Deans, Faculty Secretary, Heads of Departments, faculty members, or instructors. Issues raised through these channels are evaluated under the supervision of the Vice Dean responsible for student affairs.\nCourse and Instructor Evaluation Surveys: At the end of each semester, students complete a Course and Instructor Evaluation Survey for every course they have taken. Survey data are collected through integration with the Student Information System. The Education Commission analyzes the data and prepares an evaluation report.\nOverall Satisfaction Survey: An overall faculty satisfaction survey is conducted during the final month of each academic year via the faculty website. The collected data are analyzed and reported by the Education Commission.","uygulama_alanlari":"Fakülte öğrencileri","ilk_planlama_tarihi":"2025-10-01","izleme_mekanizmalari":"","uluslararasi_paydaslar":"","performans_gostergeleri":"Öğrencilerden; şikayet kutusu, yüz yüze görüşmeler, online kanallar aracılığıyla gelen dilek, istek ve şikayetlere cevap oranı. \nDers ve öğretim üyesi değerlendirme anketi\nGenel değerlendirme anketi\nÖğrenci temsilciliğiyle yapılan toplantılar\n","degerlendirme_iyilestirme_tarihi":"2026-07-30"}'::jsonb) ON CONFLICT (id) DO UPDATE SET olcut_adi = EXCLUDED.olcut_adi, kalite_el_kitabi = EXCLUDED.kalite_el_kitabi;
INSERT INTO public.alt_olcutler (id, kod, olcut_adi, olcut_adi_en, olcut_adi_ar, ana_baslik_id, kalite_el_kitabi) VALUES (29, 'B.3.4', 'Akademik Danışmanlık', 'Academic Advising', 'الإرشاد الأكاديمي', 2, '{"bgs_yeri":"ESOGUBS","ic_paydaslar":"Bölüm kurulları, öğrenci temsilciliği","dis_paydaslar":"Öğrenci İşleri Daire Başkanlığı\nUluslararası İlişkiler Ofisi\n","sorumlu_birim":"Eğitim Koordinatörlüğü","aciklama_metni":"Öğrencilere dönük danışmanlık hizmetleri ‘Ders Kayıt Danışmanlığı’ ve ‘Akademik Danışmanlık’ olmak üzere ikiye ayrılır. Ders Kayıt Danışmanlığı ile ilgili işlemler Eskişehir Osmangazi Üniversitesi Ön Lisans-Lisans Ders Kayıt, Kayıt Yenileme ve Öğrenci Danışmanlığı Yönergesi’ne uygun olarak gerçekleştirilir. \nAkademik Danışmanlık hizmetinin amacı öğrencinin eğitim öğretim hedeflerinin belirlenmesi, üniversite yaşamına uyum, üniversite kaynaklarına erişim ve kariyer hedeflerinin belirlenmesi konularında destek sağlamaktır. Bunların yanında öğrencilerin akademik, sosyal veya kişisel sorunlarının takip ederek gerekli yönlendirmelerin yapılması akademik danışmanlık hizmetlerinin kapsamında yer alır. \nÖğrenci fakülteye kayıt yaptırdığında Eğitim Komisyonu tarafından kedisine bir danışman atanır. Komisyon danışman atamalarını öğretim üyesi/görevlisi-öğrenci sayısal dengesini gözeterek gerçekleştirir. \nÖğretim üye/görevlileri danışmanlık hizmetlerini sağlıklı bir şekilde yürütmek için haftada en az bir saat olmak üzere ‘Haftalık Görüşme Saati’ belirler ve bu saatleri hem Eğitim Komisyonu’da hem de danışmanlık yaptıkları öğrencilere ilan eder. \nÖğretim üye/görevlileri danışmanlıklarında bulunan öğrencilerle öncelikli olarak mail grupları aracılığıyla iletişim kurarlar. Danışman her yarıyılın ikinci-üçüncü haftalarında öğrencileriyle akademik gelişim ve kariyer gelişimi ile ilgili toplantı düzenler. Toplantılar ‘Akademik Danışman-Öğrenci Toplantı Tutanağı ile kayıt altına alınarak Eğitim Komisyonuna iletilir. Bunun dışında öğrenciler danışmanlarından haftalık görüşme saatlerinde görüşmek üzere mail ya da yüz yüze görüşme yoluyla randevu alabilirler. (Akademik Danışman-Öğrenci Toplantı Tutanağı düzenlenmeli)\nDanışmanlık hizmetleri eğitim öğretim yılı sonunda öğrencilere dönük uygulanacak olan ‘Genel Memnuniyet Anketi’ içinde yer alan akademik danışmanlık ile ilgili maddeler aracılığıyla değerlendirilir. Her yıl Eylül ayında anket sonuçları merkeze alınarak gerekli iyileştirmeler yapılması için Eğitim Koordinatörlüğü ve fakülte yönetimi toplantı düzenler. Değişiklikler/iyileştirmeler öğretim üye/görevlilerine duyurulur. İyileştirmeler sonucu Akademik Danışmanlık Yönergesi güncellenmişse öğrencilere duyuru yapılır. \nDanışmanlar eğitim öğretim yılı sonunda Haziran ayında; ‘akademik danışman-öğrenci toplantı tutanağı’nı ve ilgili yıl boyunca danışmanlık kapsamında yürüttükleri faaliyetleri içeren ‘Akademik Danışmanlık Faaliyet Raporu’nu Eğitim Komisyonuna sunar. Tutanak ve raporlar Eylül ayında yapılan toplantıda değerlendirilerek iyileşme sürecinde kullanılır. \nFakülteye çift anadal ya da yandal programlarıyla gelen öğrenciler için dekanlık danışman ataması yapar. Değişim programları ile gelen öğrencilerin danışmanlığını değişim programları koordinatörü yürütür. \n","aciklama_metni_en":"Student-facing advisory services are divided into two categories: **Course Registration Advising** and **Academic Advising**. Course Registration Advising is conducted in accordance with the Eskişehir Osmangazi University Associate and Undergraduate Degree Course Registration, Enrollment Renewal, and Student Advising Directive.\n\nThe purpose of Academic Advising is to support students in defining their educational goals, adapting to university life, accessing university resources, and identifying career objectives. In addition, monitoring students'' academic, social, or personal difficulties and providing appropriate guidance falls within the scope of academic advising.\n\nWhen a student enrolls in the faculty, the Education Committee assigns them an advisor. The Committee makes advisor assignments with attention to the numerical balance between faculty members/instructors and students.\n\nFaculty members/instructors designate a **Weekly Office Hour** of at least one hour per week to conduct advising effectively, and announce these hours both to the Education Committee and to the students they advise.\n\nFaculty members/instructors communicate with their advisees primarily through email groups. Each semester, during the second or third week, the advisor holds a meeting with their students on academic and career development. Meetings are recorded in an **Academic Advisor–Student Meeting Report** and submitted to the Education Committee. Beyond these meetings, students may arrange appointments with their advisors during weekly office hours by email or in person. (An Academic Advisor–Student Meeting Report must be prepared for these as well.)\n\nAdvising services are evaluated at the end of the academic year through items related to academic advising included in the **General Satisfaction Survey** administered to students. Each September, the Education Coordination Office and faculty administration hold a meeting using survey results as the basis for identifying necessary improvements. Changes/improvements are communicated to faculty members/instructors. If the improvements result in an updated Academic Advising Directive, an announcement is made to students.\n\nAt the end of the academic year, in June, advisors submit to the Education Committee the **Academic Advisor–Student Meeting Report** along with an **Academic Advising Activity Report** documenting all advising activities carried out during that year. The reports and records are reviewed at the September meeting and used in the improvement process.\n\nFor students who join the faculty through double major or minor programs, the deanship assigns an advisor. Students arriving through exchange programs are advised by the exchange programs coordinator.","uygulama_alanlari":"Fakülte öğrencileri","ilk_planlama_tarihi":"2025-10-01","izleme_mekanizmalari":"Genel Memnuniyet Anketinde yer alan Akademik Danışmanlık ile ilgili maddelere verilen yanıtlar","uluslararasi_paydaslar":"","performans_gostergeleri":"Danışman raporları\nÖğrenci memnuniyet düzeyleri\n","degerlendirme_iyilestirme_tarihi":"2026-07-31"}'::jsonb) ON CONFLICT (id) DO UPDATE SET olcut_adi = EXCLUDED.olcut_adi, kalite_el_kitabi = EXCLUDED.kalite_el_kitabi;
INSERT INTO public.alt_olcutler (id, kod, olcut_adi, olcut_adi_en, olcut_adi_ar, ana_baslik_id, kalite_el_kitabi) VALUES (30, 'B.4.1', 'Atama, Yükseltme ve Görevlendirme Kriterleri', 'Appointment, Promotion and Assignment Criteria', 'معايير التعيين والترقية والتعيين', 2, NULL) ON CONFLICT (id) DO UPDATE SET olcut_adi = EXCLUDED.olcut_adi, kalite_el_kitabi = EXCLUDED.kalite_el_kitabi;
INSERT INTO public.alt_olcutler (id, kod, olcut_adi, olcut_adi_en, olcut_adi_ar, ana_baslik_id, kalite_el_kitabi) VALUES (31, 'B.4.2', 'Öğretim Yetkinliği', 'Teaching Competence', 'الكفاءة التدريسية', 2, NULL) ON CONFLICT (id) DO UPDATE SET olcut_adi = EXCLUDED.olcut_adi, kalite_el_kitabi = EXCLUDED.kalite_el_kitabi;
INSERT INTO public.alt_olcutler (id, kod, olcut_adi, olcut_adi_en, olcut_adi_ar, ana_baslik_id, kalite_el_kitabi) VALUES (32, 'B.4.3', 'Eğitim Faaliyetlerine Yönelik Teşvik ve Ödüllendirme', 'Incentive and Reward for Educational Activities', 'حوافز ومكافآت للأنشطة التعليمية', 2, '{"bgs_yeri":"OGUBS / Fakülte İnternet Sitesi / WhatsApp Grupları, ","ic_paydaslar":"Akademik Faaliyet Birimi KoordinatörlüğüBilimsel Araştırma Projeleri Koordinatörlüğü\nAkademik Kurul\n","dis_paydaslar":"YÖK","sorumlu_birim":"Teşvik ve Ödüllendirme Koordinatörlüğü Kalite Koordinatörlüğü Eğitim Komisyonu (izleme ve değerlendirme)","aciklama_metni":"Fakültede eğitim faaliyetlerine yönelik teşvik ve ödüllendirme hizmetlerini yürütmek üzere Teşvik ve Ödüllendirme Koordinatörlüğü kurulmuştur. Koordinatörlük bu alandaki çalışmalarını Akademik Faaliyet Birimi Koordinatörlüğü ve Bilimsel Araştırma Projeleri Koordinatörlüğü ile işbirliği halinde yürütür. Fakülte bu koordinatörlükler kanalıyla akademik ve idari personelini, eğitim-öğretim alanında örnek teşkil edecek faaliyetler yapmaya, yeni teknikler geliştirmeye ve toplumsal katkıya yönelik çalışmalar ortaya koymaya teşvik eder. Bu alanda başarı elde eden öğretim elemanını ile öğrenciyi ödüllendirir. “Yılın Bilim İnsanı”, “Yılın Sanatçısı”, “Genç Bilim İnsanı”, “En İyi Araştırmacı” gibi üniversite bünyesinde veya kamu alanında ödül kazanan personelini de ödüllendirir. Ödüllendirmeler maddi bir karşılık vermek şeklinde olabileceği gibi tebrik etmek, takdir belgesi vermek, üstün başarı belgesi vermek şeklinde de olabilir. Ödüller Akademik Genel Kurul toplantısında verilebileceği gibi özel bir program düzenlenerek de verilebilir.\nÖğretim elemanlarının fakültenin teşvik ve ödüllendirme sistemi ile alakalı istek, öneri ve şikâyetleri sistem üzerinden alınır. Kaydedilen istek, öneri ve şikâyetler Teşvik ve Ödüllendirme Koordinatörlüğü tarafından paydaşlarla birlikte değerlendirilir. Birim Kalite Koordinatörlüğü eğitim faaliyetlerine yönelik teşvik ve ödüllendirme hizmetlerini kalite bakımından izler. Tespit ve tekliflerini Haziran ve Kasım aylarında teklif komisyonunda görüşülmek üzere Dekanlığa sunar. Komisyon Aralık-Ocak aylarında toplanıp koordinatörlüklerden gelen raporları inceleyerek değerlendirmelerini Dekanlığa bildirir. Dekanlık komisyonun değerlendirmeleri doğrultusunda paydaşların da görüşlerini alarak gerekli iyileştirmeleri yapar.    ","aciklama_metni_en":"Incentive and Reward Coordinatorship was established to carry out incentive and reward services for educational activities in the Faculty. The Coordinatorship carries out its studies in this field in cooperation with the Academic Activity Unit Coordinatorship and the Scientific Research Projects Coordinatorship. Through these coordinations, the Faculty encourages its academic and administrative staff to carry out exemplary activities in the field of education, develop new techniques and provide studies for social contribution. It rewards the student with the faculty member who achieves success in this field. It also rewards award-winning personnel such as \"Scientist of the Year\", \"Artist of the Year\", \"Young Scientist\", \"Best Researcher\" within the university or in the public field. Awards can be in the form of giving a financial response, congratulating, giving a certificate of appreciation, or giving a certificate of outstanding achievement. Awards can be given at the Academic General Assembly meeting or by organizing a special program.\n\nThe requests, suggestions and complaints of the faculty members regarding the incentive and reward system of the faculty are received through the system. Recorded requests, suggestions and complaints are evaluated by the Incentive and Reward Coordination Office together with the stakeholders. Unit Quality Coordinatorship monitors incentive and reward services for educational activities in terms of quality. He submits his determinations and proposals to the Dean''s Office to be discussed in the proposal commission in June and November. The Commission meets in December-January and examines the reports from the coordinators and reports to the Dean''s Office. The dean''s office makes the necessary improvements by taking the opinions of the stakeholders in line with the evaluations of the commission.","uygulama_alanlari":"Tüm Bölümler ve Akademik Personel","ilk_planlama_tarihi":"2025-10-30","izleme_mekanizmalari":"Öğretim Elemanı Memnuniyet Anketleri\nÖğrenci Memnuniyet Anketleri\nAkademik Teşvik Komisyonu\n","uluslararasi_paydaslar":"","performans_gostergeleri":"Ödül alan akademik personel sayısı\nAkademik teşvik alan akademik personel sayısı\nÖğretim elemanı memnuniyet anket sonuçları\nÖğrenci memnuniyet anket sonuçları\n","degerlendirme_iyilestirme_tarihi":"2026-12-30"}'::jsonb) ON CONFLICT (id) DO UPDATE SET olcut_adi = EXCLUDED.olcut_adi, kalite_el_kitabi = EXCLUDED.kalite_el_kitabi;
INSERT INTO public.alt_olcutler (id, kod, olcut_adi, olcut_adi_en, olcut_adi_ar, ana_baslik_id, kalite_el_kitabi) VALUES (33, 'B.5.1', 'Öğrenme Kaynakları', 'Learning Resources', 'مصادر التعلم', 2, '{"bgs_yeri":"OGUBS / Fakülte İnternet Sitesi / WhatsApp Grupları, ","ic_paydaslar":"Akademik ve İdari Personel, Öğrenciler","dis_paydaslar":"ESOGÜ İlahiyat Fakültesi Mezunları ve Mensupları Derneği (ESİLDER)","sorumlu_birim":"Dekanlık/ Eğitim Koordinatörlüğü  Birim Kalite Koordinatörlüğü","aciklama_metni":"Fakültenin öğrenme kaynakları arasında derslikler, konferans salonları, amfiler, toplantı salonları, kütüphane ve çalışma salonu yer alır. Fakülte bünyesinde 30 kişilik 10, 35 kişilik 2, 80 kişilik 2, 72 kişilik 4 adet olmak üzere toplam 16 derslik ve 72 kişilik 2 adet amfi bulunur. Ayrıca 20 kişilik toplantı salonu ile birlikte 1 adet çalışma salonu ve 150 kişi kapasiteli konferans salonu yer alır. \nDersliklerin tamamı internet bağlantısı ve projeksiyon cihazları ile donatılmış olup öğrenci ve öğretim elemanları sunum ve gösterimler yapabilir. Konferans salonu, toplantı salonu ve amfilerde de projeksiyon cihazı yer alıp bu cihazlar, konferans, seminer, sempozyum, ortak dersler ve tüm etkinliklerde kullanılmak üzere öğrenciler, öğretim elemanları ve idari personelin istifadesine sunulur. 50 kişilik çalışma salonunda bazı temel ve yardımcı kaynaklar ile birlikte masaüstü bilgisayar ve internet imkânı bulunur. Fakülte, çeşitli etkinliklerde kullanmak üzere öğrencilerine fotoğraf makinesi ve kamera hizmeti sunar.\nFakültede yer alan kütüphane üniversite bünyesindeki Merkez Kütüphaneye taşınmış olup Merkez Kütüphane, 7200 metrekare kapalı alan üzerinde 838 kişilik oturma kapasitesi ile birlikte 10 adet grup çalışma odası, 7 adet akademik personel çalışma odasına sahiptir.\nMerkez Kütüphanenin görsel-işitsel bölümünde ödev ve araştırma amaçlı internet erişimli bilgisayarlar, kütüphane kataloğunu tarama bilgisayarları ve otomatik kitap ödünç-iade verme istasyonu bulunur. Merkez Kütüphane ayrıca kullanıcılarına (ILL) Kütüphaneler arası ödünç verme-kitap sağlama hizmeti sunar.\nMerkez Kütüphane, dijital ortamda kaynak taramasında 40 veri tabanına sahip olup hâlihazırda bazı veri tabanlarını da deneme amaçlı öğrenci ve araştırmacıların kullanımına açmıştır. EDS Ekual Keşif Arama Kutusu ile kullanıcılarına tüm veri tabanlarında aynı anda kaynak tarama hizmeti sunar. Merkez kütüphane, personel ve öğrencileri için erişim tabanlarına üniversite dışından erişim imkânı da sağlar.\nMerkez Kütüphane TUBESS sistemi ile de akademik, idari ve doktora öğrencileri için belge sağlama hizmeti verir. Merkez Kütüphane bünyesindeki Engelli Öğrenci Birimi, rektörlüğe bağlı olup engelli öğrencilerin öğrenme kaynaklarına ulaşım ve istifadeleri konusunda da gerekli yükümlülükleri yerine getirir.\nKaynak temini ve veri tabanının erişime açılmasına dair tüm işlemler, akademik birimlerden gelen talepler doğrultusunda ESOGÜ Kütüphane ve Dokümantasyon Daire Başkanlığı tarafından ilgili tanımlı süreçler çerçevesinde yürütülmektedir.\nKurumdaki derslikler tanımlı bir sürece göre kullanılır. Sınıfların haftalık ders programları dönem başlamadan bir ay önce ilgili Dekan yardımcısı tarafından hazırlanır. İlahiyat lisans programında yer alan tüm dersler ilgili dönem ve sınıfa göre gruplandırılarak bir excel dosyası oluşturulur. Dosya bölümlere gönderilerek iki haftalık süre içerisinde hangi derslerin kaç şube açılacağı ve hangi öğretim elemanının gireceğine dair bilgilendirme yapılması talep edilir. Bölümlerden alınan bilgiler doğrultusunda dersler şube ve öğretim elemanlarına göre OGUBS sisteminde aktifler. Taslağın tamamlanmasından sonra sisteme aktarılan ders programı, her bir öğretim elemanı için ayrı olacak şekilde excel dosyasına aktarılarak öğrencilere ilan edilir.\nDersliklerin sınav için hazırlanmasında da benzer bir süreç izlenir. Öncelikle Sınav Koordinatörü tarafından taslak takvim hazırlanarak fakülte web sayfası ve WhatsApp gruplarında öğretim üyesi/elemanları ve öğrencilerle paylaşılır. Geri bildirimler doğrultusunda taslak takvimde gerekli düzenlemeler yapılarak sınav takviminin son hali, aynı iletişim kanallarıyla ilan edilir.\nFakültedeki tüm bu öğrenme kaynaklarının kullanımı ile ilgili süreçler Eğitim Koordinatörlüğünün sorumluluğundadır. Birim Kalite Koordinatörlüğü süreci kalite bakımından izler; tespit ve tekliflerini iç paydaşlardan gelen talep ve önerileri de dikkate alarak Haziran - Temmuz aylarında Kalite Komisyonunda görüşülmek üzere Dekanlığa sunar. Komisyon Temmuz - Ağustos aylarında toplanıp koordinatörlükten gelen raporları inceleyerek değerlendirmelerini Dekanlığa bildirir. Dekanlık, komisyonun değerlendirmeleri doğrultusunda paydaşların da görüşlerini alarak gerekli iyileştirmeleri yapar.\n","uygulama_alanlari":"Tüm fakülte","ilk_planlama_tarihi":"2025-10-15","izleme_mekanizmalari":"Öğrenci memnuniyet anketleri\nÖğrenci odak grup görüşmeleri\nKütüphane memnuniyet anketi\n\n","uluslararasi_paydaslar":"","performans_gostergeleri":"Talep edilen kaynaklarının sayısal ifadesi\nTemin edilen kaynaklarının sayısal ifadesi \nKaynak yeterliliğine dair anket uygulama raporlarının sonuçları \nPersonel ve öğrenci memnuniyet oranları\n","degerlendirme_iyilestirme_tarihi":"2026-06-24"}'::jsonb) ON CONFLICT (id) DO UPDATE SET olcut_adi = EXCLUDED.olcut_adi, kalite_el_kitabi = EXCLUDED.kalite_el_kitabi;
INSERT INTO public.alt_olcutler (id, kod, olcut_adi, olcut_adi_en, olcut_adi_ar, ana_baslik_id, kalite_el_kitabi) VALUES (34, 'B.5.2', 'Sosyal, Kültürel, Sportif Faaliyetler', 'Social, Cultural, Sportive Activities', 'الأنشطة الاجتماعية والثقافية والرياضية', 2, '{"bgs_yeri":"OGUBS / Fakülte İnternet Sitesi / WhatsApp Grupları","ic_paydaslar":"Akademik ve İdari Personel\nÖğrenciler \n","dis_paydaslar":"ESİLDER / Eskişehir İslami İlimler Vakfı","sorumlu_birim":"Dekanlık/Eğitim Koordinatörlüğü/Sosyal, Kültürel ve Sanatsal Faaliyetler Koordinatörlüğü  Kalite Koordinatörlüğü (İzleme, Değerlendirme)","aciklama_metni":"Fakülte bünyesindeki Sosyal, Kültürel ve Sportif Faaliyetler Koordinatörlüğü görevleri ve politikaları çerçevesinde fakülteyle ilişkili tüm sosyal, kültürel ve sportif faaliyetlerin planlamasını, hazırlık, tanıtım ve duyurularını yapar. Yürütülen tüm faaliyetlerde fakültenin toplumsal katkı politikası, hedefleri ve stratejisine uygunluk gözetilir. Öğrencilere yönelik akademik faaliyetlerin yanı sıra sosyal ve kültürel etkinliklerin de planlandığı organizasyonlara ESOGÜ İlahiyat Fakültesi Mezun ve Mensupları Derneği maddi ve manevi olarak destek sağlar. \nFakülte bünyesinde mesleki, sosyal ve kültürel faaliyetlerin icra edilmesinde kullanılan 150 kişi kapasiteli bir konferans salonu ve ……….kişi kapasiteli ESOGÜ İlahiyat Fakültesi Camii salonu ve Camii bahçesi/avlusu bulunur. 2.880.830 metrekare ESOGÜ yerleşkesi, 50.000 metrekare sosyal tesis ve kütüphaneye sahiptir. Üniversitenin farklı birimleri içerisinde 5 ayrı konferans salonu olup ayrıca Kongre ve Kültür Merkezi mevcuttur. Toplamda 1057 kapasiteli olan 5 ayrı salona sahip olan Kongre ve Kültür Merkezi’ndeki salonlar, farklı etkinlikleri gerçekleştirmeye uygun donanımlara sahiptir.\n\nESOGÜ yerleşkesi bünyesinde 1100 kişilik seyirci kapasitesine sahip uluslararası karşılaşmaların yapılabildiği kapalı spor salonu, 800 kişiye hizmet verebilen bedensel uyum merkezi, çok amaçlı salon, 5 açık ve 2 kapalı olmak üzere 7 adet tenis kortu, 1 kapalı ve 2 açık olmak üzere 3 adet halı saha, 6 potadan oluşan 500 metrekare alanda açık basketbol sahası, dağcılık tırmanma kulesi bulunmaktadır.\nÖğrenciler, Rektörlük ve Dekanlık tarafından düzenlenen sportif etkinliklere birey veya grup hâlinde katılabilirler. Bütün bu imkânlardan öğretim elemanları, öğrenciler ve idari personel ile öğretim elemanı ve personelin birinci derece yakınları hizmet alabilir. \nÖğrenciler bilimsel, mesleki, sosyal, kültürel ve sportif etkinliklerde bulunabilmek amacıyla kendi aralarında bir araya gelerek öğrenci kulüpleri kurabilir. Bu kulüplerin işleyişi ve tüm faaliyetleri, Dekanlık Sosyal, Kültürel ve Sanatsal Faaliyetler Koordinatörlüğü ve Rektörlük Sağlık, Kültür ve Spor Daire Başkanlığı tarafından takip edilmekte ve desteklenmektedir. Kulüp, bir öğretim üyesinin danışmanlığı altında etkinlik yapar. Bunun için kulüp başkanı, danışman öğretim üyesinin imzalı muvafakatini alarak etkinliğin muhtevasını belirten dilekçesiyle Dekanlıktan izin alır. Dekanlıkça belirlenen mekânda ve verilen izin çerçevesinde faaliyet icra edilir. Bu çerçevede fakülte bünyesinde 12 öğrenci kulübü olup birçoğu aktif olarak faaliyet ve etkinlikler düzenlemektedir.\nFakülte maddi yönden sıkıntı çeken öğrencilere yardımcı olmaya çalışır. Bunu, iş birliği protokolü imzaladığı ESOGÜ İlahiyat Fakültesi Mezun ve Mensupları Derneği ve Eskişehir İslami İlimler Vakfı üzerinden yapar. Öğrencilere, Sosyal Yardım ve Destek Koordinatörlüğü üzerinden gereken desteği sağlayabilir. Koordinatörlük, öğrenci kayıt formlarındaki bilgileri incelemenin yanı sıra Dekanlıkça uygun görülmesi hâlinde öğrencilerle planlı görüşmeler gerçekleştirerek tespitlerde bulunur. Ayrıca, öğretim üyeleri ve sınıf temsilcilerinin bu yöndeki bildirimlerini dikkate alır. Desteğe ihtiyacı bulunanları belirler ve gönüllülük esasına göre bağışçıların katkı sunmasına aracılık eder. Ayrıca, şartları taşıyan öğrenciler Rektörlüğün Kısmi Zamanlı Öğrenci Çalıştırma Yönergesi çerçevesinde Fakülteye tahsis ettiği yarı zamanlı çalışma bursu imkânından yararlanır. \nFakültede gerçekleşen etkinlikler haber yapılır ve fakülte internet sayfası ile fakülteye ait diğer sosyal medya mecralarında yayımlanır. Ayrıca Youtube kanalı ve diğer sosyal mecra kanalları canlı ve aktif tutulur. Bu mecralarda fakülteye ilişkin haberler paylaşıldığı gibi etkinliklerin canlı veya banttan yayını yapılır. \nTüm bu süreçlerin yürütülmesinden Eğitim Koordinatörlüğü sorumludur. Birim Kalite Koordinatörlüğü süreci kalite bakımından izler; tespit ve tekliflerini Haziran - Temmuz aylarında Kalite Komisyonunda görüşülmek üzere Dekanlığa sunar. Komisyon, Temmuz - Ağustos aylarında toplanıp koordinatörlüklerden gelen raporları inceleyerek değerlendirmelerini Dekanlığa bildirir. Dekanlık, komisyonun değerlendirmeleri doğrultusunda paydaşların da görüşlerini alarak gerekli iyileştirmeleri yapar.\n","uygulama_alanlari":"Tüm fakülte","ilk_planlama_tarihi":"2025-10-15","izleme_mekanizmalari":"Öğrencilerin sosyal, kültürel ve sportif faaliyetlerine yönelik memnuniyet anketleri\nÖğrenci odak grup görüşmeleri\n","uluslararasi_paydaslar":"","performans_gostergeleri":"Öğrenci kulübü sayısı\nÖğrenci kulüplerinde görev alan öğrenci sayısı \nSosyal, kültürel ve sportif faaliyetlere yönelik anket sonuçları\n","degerlendirme_iyilestirme_tarihi":"2026-06-24"}'::jsonb) ON CONFLICT (id) DO UPDATE SET olcut_adi = EXCLUDED.olcut_adi, kalite_el_kitabi = EXCLUDED.kalite_el_kitabi;
INSERT INTO public.alt_olcutler (id, kod, olcut_adi, olcut_adi_en, olcut_adi_ar, ana_baslik_id, kalite_el_kitabi) VALUES (35, 'B.5.3', 'Tesis ve Altyapılar', 'Facilities and Infrastructures', 'المرافق والبنية التحتية', 2, '{"bgs_yeri":"OGUBYS\nhttps://ilahiyat.ogu.edu.tr/","ic_paydaslar":"Akademik ve İdari Personel\nÖğrenciler","dis_paydaslar":"ESİLDER \nEskişehir İslami İlimler Vakfı\nESOGÜ Sağlık, Kültür ve Spor Daire Başkanlığı\nEskişehir Müftülüğü\n","sorumlu_birim":"B.5.3. Tesis ve Altyapı","aciklama_metni":"Eskişehir Osmangazi Üniversitesi Meşelik Merkez yerleşkesinde yer alan fakültemiz, çağdaş ve donanımlı binasında eğitim-öğretim faaliyetlerine etkin biçimde devam etmektedir. Öğrencilerimizin hem akademik gelişimlerini destekleyecek hem de sosyal ihtiyaçlarını karşılayacak çeşitli olanaklar üniversitemiz bünyesinde sağlanmaktadır. Fakülte, yerleşkesindeki imkânların yanı sıra üniversitenin yemekhane, internet, salon ve spor merkezi gibi altyapı imkânlarından istifade etmektedir. Fakülte bünyesinde kantin, kütüphane mekânların iyileştirilmesi ve kapasitesinin artırılması yönünde adımlar atılmaktadır. Ayrıca TDV Diyanet Gençlik Ofisi’nde bireysel ve toplu ders çalışma alanları, dinlenme alanı, manevî danışmanlık hizmeti, kitap alım hizmetleri gibi tesis ve altyapıya yönelik erişim hafta içi 09:00-19:00 saatleri ve hafta sonu cumartesi günü hizmet sunmaktadır.\nÜniversitenin merkez yemekhanesinde, kalori hesaplamaları bilimsel ölçütlere göre yapılan ve çeşitlilik arz eden yemekler birinci ve ikinci öğretim öğrencileri için günde iki defa sunulmaktadır. Bu imkândan akademik ve idari personel de yararlanmaktadır. Personel ve öğrenciler aynı yemekleri yemektedir. Yine fakülte içerisinde bulunan kantin hafta içi her gün 08:00-19:00 saatleri arasında öğrencilere hizmet sunmaktadır. Haftalık yemek listeleri Üniversite web sayfasında yayınlanmaktadır. Öğrenciler, kendilerine sağlanan öğrenci kartı sayesinde yemekhane hizmetlerinden kolaylıkla ve hızlıca faydalanabilmektedir.\nFakülte öğrencilerimiz, belli şartlar altında Üniversitenin Sürekli Eğitim Merkezi’nin (ESOGÜSEM) hizmetlerinden yararlanabilirler. ESOGÜSEM Üniversite öğrencilerine hizmet verdiği gibi akademik ve idari personel ile dışarıdan katılmak isteyenlere de toplumsal katkıya yönelik hizmet sunmaktadır.\nEskişehir Osmangazi Üniversitesi Meşelik kampüsünde, altyapısı ULAKBİM tarafından sağlanan internet hizmetleri öğrencilere hem sabit hem de kablosuz bağlantı seçenekleriyle hizmet sunulmaktadır. \nFakülte öğrencilerimizin sportif etkinliklerde bulunmalarına imkân tanımak amacıyla, üniversitemiz bünyesinde Eskişehir Osmangazi Üniversitesi Stadyumu, kapalı spor salonu ile çeşitli alanlarda faaliyet gösteren açık ve kapalı tenis kortları, açık basketbol sahası, açık futbol halı sahası, kapalı yüzeme havuzu, dağcılık kulesi gibi spor tesisleri bulunmaktadır. Bu imkanlardan akademik ve idari personel de yararlanmaktadır. Ayrıca üniversite bünyesindeki Mediko’dan aile hekimliği ve psikolojik destek hizmetinden faydalanılmaktadır.\nFakülte öğrencilerimizin barınma ihtiyaçlarının karşılanması için Meşelik Kampüsü civarı Yüksek Öğrenim Kredi ve Yurtlar Kurumuna ait yurtlar bulunmaktadır. Ayrıca Eskişehir Merkez’de çok sayıda özel öğrenci yurt ve apartları öğrencilerimize hizmet vermektedir. \nÖğrencilerin Üniversitenin sağladığı imkânlardan yararlanabilmesi sürecini Eğitim Koordinatörlüğü yürütür.  Kalite Koordinatörlüğü süreci izler; tespit ve tekliflerini Haziran - Temmuz aylarında Komisyonda görüşülmek üzere Dekanlığa sunar. Komisyon, toplanıp koordinatörlüklerden gelen raporları inceleyerek değerlendirmelerini Dekanlığa bildirir. Dekanlık, komisyonun değerlendirmeleri doğrultusunda paydaşların da görüşlerini alarak gerekli iyileştirmeleri yapar.\n","aciklama_metni_en":"Located on the Meşelik Main Campus of Eskişehir Osmangazi University, the Faculty carries out its educational and academic activities in a contemporary and well-equipped building. The University provides a wide range of facilities and infrastructure services designed to support students’ academic development, social engagement, and overall well-being. In addition to its own facilities, the Faculty benefits from the University''s dining, internet, sports, and social infrastructure. Continuous improvement efforts are undertaken to enhance the quality, accessibility, and capacity of Faculty facilities, particularly the canteen and library.\n\nStudents also have access to the facilities and services offered by the Turkish Religious Foundation (TDV) Diyanet Youth Office, which include individual and group study spaces, recreational areas, spiritual counseling services, and book support services. These services are available on weekdays between 09:00 and 19:00 and on Saturdays.\n\nThe University’s central dining hall provides nutritionally balanced meals prepared in accordance with scientific dietary standards. Meal services are offered twice daily for students enrolled in daytime and evening education programs. Academic and administrative staff benefit from the same dining services under equal conditions. Weekly meal menus are regularly announced through the University website, and students can access dining services efficiently through their student identification cards. In addition, the Faculty canteen serves students on weekdays between 08:00 and 19:00.\n\nStudents may also benefit from the educational and professional development opportunities offered by the Eskişehir Osmangazi University Continuing Education Center (ESOGÜSEM), subject to the relevant participation requirements. ESOGÜSEM serves not only university students but also academic and administrative staff and external participants, thereby contributing to lifelong learning and social responsibility initiatives.\n\nInternet access across the Meşelik Campus is provided through infrastructure supported by ULAKBİM and is available through both wired and wireless networks, ensuring uninterrupted access to digital learning resources and communication technologies.\n\nThe University offers extensive sports and recreational facilities to support students’ physical development and healthy lifestyles. These facilities include the Eskişehir Osmangazi University Stadium, an indoor sports hall, indoor and outdoor tennis courts, an outdoor basketball court, an outdoor artificial turf football field, an indoor swimming pool, and a climbing tower. These facilities are available to students as well as academic and administrative staff. Furthermore, healthcare and psychological counseling services are provided through the University Health Center (Mediko).\n\nAccommodation opportunities for students are supported through public dormitories operated by the Credit and Dormitories Institution (KYK) located near the Meşelik Campus. In addition, numerous private dormitories and student residences in the city center of Eskişehir provide alternative accommodation options.\n\nThe process of facilitating students’ access to the facilities and services offered by the University is coordinated by the Education Coordination Office. The effectiveness and adequacy of these facilities and services are systematically monitored by the Quality Coordination Office. Findings, evaluations, and improvement proposals are submitted to the Dean’s Office for discussion by the relevant Commission during the June–July evaluation period. The Commission reviews the reports received from the coordination offices, assesses their findings, and communicates its recommendations to the Dean’s Office. Taking into account stakeholder feedback and the Commission’s evaluations, the Dean’s Office implements the necessary improvement actions within the framework of the Faculty’s continuous quality improvement policy.","uygulama_alanlari":"Tüm Fakülte","ilk_planlama_tarihi":"2025-10-10","izleme_mekanizmalari":"Anketler\nDekanlığa İletilen Öneri ve Görüşler","uluslararasi_paydaslar":"-","performans_gostergeleri":"Yapılan Anket Görüşleri ve Memnuniyet Oranları\n","degerlendirme_iyilestirme_tarihi":"2026-05-20"}'::jsonb) ON CONFLICT (id) DO UPDATE SET olcut_adi = EXCLUDED.olcut_adi, kalite_el_kitabi = EXCLUDED.kalite_el_kitabi;
INSERT INTO public.alt_olcutler (id, kod, olcut_adi, olcut_adi_en, olcut_adi_ar, ana_baslik_id, kalite_el_kitabi) VALUES (36, 'B.5.4', 'Engelsiz Fakülte', 'Barrier-Free Faculty', 'كلية خالية من العوائق', 2, '{"bgs_yeri":"OGUBYS\nWhatsApp Grupları\nFakülte İnternet Sitesi","ic_paydaslar":"ESOGÜ Engelli Öğrenci Birimi\nESOGÜ Rektörlük Öğrenci İşleri\nAkademik ve İdari Personel Birimi\nÖğrenciler\n","dis_paydaslar":"Öğrenci Yakınları","sorumlu_birim":"B.5.4. Engelsiz Fakülte","aciklama_metni":"Fakültemiz, özel gereksinimli öğrencilerin akademik ve sosyal hayata tam katılımlarını sağlamak amacıyla, Eskişehir Osmangazi Üniversitesi Engelli Öğrenci Birimi ile iş birliği içinde hareket etmektedir. Bu doğrultuda, öğrencilerin bireysel ihtiyaçlarına yönelik çözümler üretilmekte ve gerekli destek mekanizmaları oluşturulmaktadır. Koordinatörlük, özel gereksinimli öğrencilerin karşılaştığı sorunların çözümüne yönelik girişimlerde bulunmakta; öğrencilerin eğitim süreçlerinde karşılaştıkları engelleri en aza indirmek için öğretim elemanlarıyla yakın iş birliği içinde çalışmaktadır. Buna yönelik fakültemizde özel gereksinimli öğrenci asansörü, sınav zamanı özel gereksinimli öğrencilere yönelik sınav evrakı hazırlama gibi iyileştirme hizmetleri sunulmaktadır.\nEngelsiz Fakülte konusundaki süreci Eğitim Koordinatörlüğü yürütür. Birim Koordinatörlüğü süreci izler; tespit ve tekliflerini Kalite Komisyonunda görüşülmek üzere Dekanlığa sunar. Komisyon, koordinatörlüklerden gelen raporları inceleyerek değerlendirmelerini Dekanlığa bildirir. Dekanlık, komisyonun değerlendirmeleri doğrultusunda paydaşların da görüşlerini alarak gerekli iyileştirmeleri yapar.\n","aciklama_metni_en":"Our faculty works in collaboration with the Office for Students with Disabilities at Eskişehir Osmangazi University to ensure the full participation of students with special needs in academic and social life. To this end, solutions tailored to students’ individual needs are developed, and the necessary support mechanisms are established. The Coordination Office takes initiatives to resolve the challenges faced by students with special needs and works in close collaboration with faculty members to minimize the barriers students encounter in their educational processes. To this end, our faculty offers accessibility services such as an elevator for students with special needs and the preparation of exam materials tailored to their needs during exam periods.\nThe Education Coordination Office oversees the “Accessible Faculty” process. The Unit Coordination Office monitors the process and submits its findings and recommendations to the Dean’s Office for review by the Quality Commission. The Commission reviews the reports submitted by the coordination offices and communicates its evaluations to the Dean’s Office. The Dean’s Office implements the necessary improvements in accordance with the Commission’s evaluations, taking into account the views of all stakeholders.\n\n\n","uygulama_alanlari":"Tüm fakülte","ilk_planlama_tarihi":"2025-10-20","izleme_mekanizmalari":"Odak grup görüşmesi","uluslararasi_paydaslar":"-","performans_gostergeleri":"Yapılan odak grup görüçmeleri\nEngelli öğrencilerin sayısı\n\n","degerlendirme_iyilestirme_tarihi":"2026-01-20"}'::jsonb) ON CONFLICT (id) DO UPDATE SET olcut_adi = EXCLUDED.olcut_adi, kalite_el_kitabi = EXCLUDED.kalite_el_kitabi;
INSERT INTO public.alt_olcutler (id, kod, olcut_adi, olcut_adi_en, olcut_adi_ar, ana_baslik_id, kalite_el_kitabi) VALUES (37, 'B.5.5', 'Rehberlik, Psikolojik Danışmanlık ve Kariyer Hizmetleri', 'Guidance, Psychological Counseling and Career Services', 'التوجيه والإرشاد النفسي والخدمات المهنية', 2, '{"bgs_yeri":"OGUBS / Fakülte İnternet Sitesi / WhatsApp Grupları","ic_paydaslar":"Akademik ve İdari Personel\nLisans Öğrencileri\nAkademik Danışmanlık Koordinatörlüğü\nPsikolojik Danışmanlık ve Rehberlik Birimi\nKariyer Geliştirme, Uygulama ve Araştırma Merkezi\n","dis_paydaslar":"ESOGÜ İlahiyat Fakültesi Mezunları ve Mensupları Derneği (ESİLDER)","sorumlu_birim":"Rehberlik ve Danışmanlık Koordinatörlüğü Kalite Koordinatörlüğü (izleme ve değerlendirme)","aciklama_metni":"Fakültede rehberlik, danışmanlık ve kariyer hizmetlerini yürütmek üzere Rehberlik ve Danışmanlık Koordinatörlüğü kurulmuştur. Koordinatörlük öğrencilerin eğitim-öğretim ve araştırma faaliyetlerini yürüttükleri sırada psiko-sosyal ve manevi iyi oluşları açısından istek ve ihtiyaçlarının karşılanabilmesi için öğrencilerle işbirliği halinde olur. Öğrencilerin fakülteye uyumunu sağlamak, aidiyetini güçlendirmek ve iyi oluş hallerini yükseltebilmek için çalışmalar yapar. İhtiyaç halinde öğrencileri üniversitenin Psikolojik Danışmanlık ve Rehberlik birimi ile Kariyer Geliştirme, Uygulama ve Araştırma Merkezi’ne yönlendirir.Birim Kalite Koordinatörlüğü Rehberlik ve Danışmanlık Koordinatörlüğünün yürüttüğü Rehberlik, Danışmanlık ve Kariyer Hizmetlerini kalite bakımından izler. Tespit ve tekliflerini Haziran - Temmuz aylarında kalite komisyonunda görüşülmek üzere Dekanlığa sunar. Komisyon Temmuz - Ağustos aylarında toplanıp koordinatörlüklerden gelen raporları inceleyerek değerlendirmelerini Dekanlığa bildirir. Dekanlık komisyonun değerlendirmeleri doğrultusunda paydaşların da görüşlerini alarak gerekli iyileştirmeleri yapar.","aciklama_metni_en":"Guidance and Counseling Coordinatorship was established to carry out guidance, consultancy and career services in the faculty. The coordination cooperates with the students in order to meet their wishes and needs in terms of psycho-social and spiritual well-being while they carry out education and research activities. It works to ensure the adaptation of students to the faculty, to strengthen their belonging and to improve their well-being. If necessary, it directs students to the University''s Psychological Counseling and Guidance unit and the Career Development, Application and Research Center. The Unit Quality Coordinatorship monitors the Guidance, Counseling and Career Services carried out by the Guidance and Counseling Coordinatorship in terms of quality. He submits his determinations and proposals to the Dean''s Office to be discussed in the quality commission between June and July. The Commission meets in July - August and examines the reports from the coordinators and reports to the Dean''s office of its evaluations. The dean''s office makes the necessary improvements by taking the opinions of the stakeholders in line with the evaluations of the commission.","uygulama_alanlari":"Tüm öğrencilerRehberlik, psikolojik danışmanlık ve kariyer hizmetleri","ilk_planlama_tarihi":"2025-10-30","izleme_mekanizmalari":"Öğrenci memnuniyet anketleri\nÖğrenci odak grup görüşmeleri\nİletişim formu\n","uluslararasi_paydaslar":"","performans_gostergeleri":"Memnuniyet anketlerinin sonuçları\nBu hizmetlerden faydalanan öğrencilerin tüm öğrencilere oranı\nİletişim formuna gelen talep, ihtiyaç ve önerilerin sayısal kategorizasyonu\n","degerlendirme_iyilestirme_tarihi":"2026-06-30"}'::jsonb) ON CONFLICT (id) DO UPDATE SET olcut_adi = EXCLUDED.olcut_adi, kalite_el_kitabi = EXCLUDED.kalite_el_kitabi;
INSERT INTO public.alt_olcutler (id, kod, olcut_adi, olcut_adi_en, olcut_adi_ar, ana_baslik_id, kalite_el_kitabi) VALUES (38, 'B.6.1', 'Program Çıktılarının İzlenmesi ve Güncellenmesi', 'Monitoring and Updating Program Outputs', 'مراقبة وتحديث مخرجات البرنامج', 2, NULL) ON CONFLICT (id) DO UPDATE SET olcut_adi = EXCLUDED.olcut_adi, kalite_el_kitabi = EXCLUDED.kalite_el_kitabi;
INSERT INTO public.alt_olcutler (id, kod, olcut_adi, olcut_adi_en, olcut_adi_ar, ana_baslik_id, kalite_el_kitabi) VALUES (39, 'B.6.2', 'Mezun İzleme Sistemi', 'Alumni Tracking System', 'نظام متابعة الخريجين', 2, NULL) ON CONFLICT (id) DO UPDATE SET olcut_adi = EXCLUDED.olcut_adi, kalite_el_kitabi = EXCLUDED.kalite_el_kitabi;
INSERT INTO public.alt_olcutler (id, kod, olcut_adi, olcut_adi_en, olcut_adi_ar, ana_baslik_id, kalite_el_kitabi) VALUES (40, 'C.1.1', 'Kurumun Araştırma Politikası, Hedefleri ve Stratejisi', 'Research Policy, Goals and Strategy of the Institution', 'سياسة البحث وأهدافه وإستراتيجيته', 3, '{"bgs_yeri":"https://abys-ivory.vercel.app/tr/olcutler/40/kalite-el-kitabi","ic_paydaslar":"Akademik ve İdari personel, Öğrenciler","dis_paydaslar":"İl ve İlçe Meb Müdürlükleri, İl ve İlçe Müftülükleri.","sorumlu_birim":"Araştırma Geliştirme Koordinatörlüğü ","aciklama_metni":"C. 1. 1. Kurumun Araştırma Politikası, Hedefleri Ve Stratejisi \nKurum, yönetimi ve idari işleyişi ile birlikte görev, yetki ve sorumlulukları belirleme; kurum içi iş akış süreçlerinin tanımlanarak güvence altına alındığı bir yapı olma politikasını kendine hedef olarak belirlemiş, bu doğrultuda gerekli stratejileri oluşturmanın tedbirlerini iç mekanizma olarak almıştır.\nBu kapsamda kurum, personel liyakatinin esas alındığı etkin bir insan kaynakları yönetimi gerçekleştirir. Mali kaynaklarını verimli, hukuka uygun, açık ve hesap verilebilir bir şekilde yönetir. Mali yönetimin bilgisine ilişkin elindeki verileri zamanında, doğru, güvenilir bir şekilde kamuoyuyla paylaşır. Kurum, kalite süreçleriyle ilgili etkin bir bilgi yönetim sistemini kullanır. Yönetim hizmetlerinin verimliliğini nesnel ölçütlerle değerlendirerek sürekli ve gerekli iyileştirmeleri sağlar.\nKurum şeffaf, katılımcı ve sürdürülebilir bir yönetim politikası belirleyerek araştırma strateji ve hedeflerini bilimsel, imkân ölçüsünde teknolojik ve toplumsal katkıyı da gözeterek en üst düzeye çıkarmayı hedefler.\nKurum, araştırma ve geliştirme süreçlerini eğitim-öğretim faaliyetleriyle entegre bir biçimde araştırma kadrosunun da gelişimini destekleyecek biçimde kurumlararası iş birliğini güçlendirerek uluslararası araştırma alanlarıyla bağlantılar kurmayı hedefler. Bu süreçte strateji ve hedeflerini iç ve dış paydaşların da katılımıyla belli aralıklarla gözden geçirerek günceller.\nKurum, araştırma stratejilerinde yerel, ulusal ve uluslararası düzeyde bilimsel katkı sağlamayı ve benimsemiş olduğu stratejik öncelikleri doğrultusunda sürdürülebilir bir araştırma ekosistemi oluşturmayı hedefler. Yapmış olduğu faaliyetlerde araştırma sonuçlarının toplumla daha etkin bir şekilde paylaşılmasını amaçlar. Dahası kurum çevresel, sosyal ve kültürel sorumluluk bilinciyle yürütülen etki alanını genişletmeye ve toplumsal katma değer üreten projelere öncelik vermeye çalışan bir vizyon belirler.\n","uygulama_alanlari":"Fakülte ve alt birimler (Akademik personel, idari personel, tüm öğrenciler, yerel, bölgesel, ulusal ve uluslararası alanlar)","ilk_planlama_tarihi":"2025-01-01","izleme_mekanizmalari":"Araştırma-Geliştirme Komisyonu Toplantıları\nDış Paydaş Komisyonu Toplantıları\nAkademik personel memnuniyet anketleri\nÖğrenci memnuniyet anketleri\nMezunlarla yapılan anketler\nDers memnuniyet anketleri\nAkademik Kurul Toplantıları\nBölüm Kurulu Toplantıları\n","uluslararasi_paydaslar":"-","performans_gostergeleri":"Öğrencilerin memnuniyet oranları\nAkademik personelin memnuniyet oranları\nDış paydaşların memnuniyet oranları\nMezunların Memnuniyet Oranları\nAkademik Kurul Toplantıları\nYönetimin Gözden Geçirmesi Raporları\n","degerlendirme_iyilestirme_tarihi":"2026-09-01"}'::jsonb) ON CONFLICT (id) DO UPDATE SET olcut_adi = EXCLUDED.olcut_adi, kalite_el_kitabi = EXCLUDED.kalite_el_kitabi;
INSERT INTO public.alt_olcutler (id, kod, olcut_adi, olcut_adi_en, olcut_adi_ar, ana_baslik_id, kalite_el_kitabi) VALUES (41, 'C.1.2', 'Araştırma-Geliştirme Süreçlerinin Yönetimi ve Organizasyonel Yapısı', 'Management and Organizational Structure of Research and Development Processes', 'الإدارة والهيكل التنظيمي لعمليات البحث والتطوير', 3, '{"bgs_yeri":"https://abys-ivory.vercel.app/tr/olcutler/41/kalite-el-kitabi","ic_paydaslar":"Akademik ve İdari personel ve Öğrenciler","dis_paydaslar":"İl ve İlçe Meb Müdürlükleri ve İl ve İlçe Müftülükleri","sorumlu_birim":"Kalite ve Akreditasyon Komisyonu Kalite Takip Komisyonu Araştırma ve Geliştirme Komisyonu","aciklama_metni":"C. 1. 2. Araştırma-Geliştirme Süreçlerinin Yönetimi ve Organizasyonel Yapısı \nFakülte içindeki araştırma geliştirme süreçleri, bilimsel araştırmaların geliştirilmesi, akademik personel ve öğrencilerin bu konuda teşvik edilmesi, ilgili projelerin etkin bir biçimde yönetilip yürütülmesi amacını taşır. Araştırma Geliştirme Birimi, bu husustaki çalışmalarında, Kalite Takip Komisyonu tarafından denetlenir. Bu süreçte akademik personelin araştırma motivasyonunun arttırılmasında Araştırma Geliştirme Birimi, Fakülte Dekanlığı ile işbirliği içinde çalışır. Kalite Takip Komisyonu, Araştırma Geliştirme Birimi tarafından geliştirilen projelerin yürütülmesinde, Fakülteye özel hedefler doğrultusunda, Kalite ve Akreditasyon Komisyonu bünyesindeki alt komisyonlar tarafından yürütülür. Kalite Akreditasyon Komisyonu, projelerin ve akademik işbirliklerin koordinasyonunu sağlar. Araştırma Geliştirme Birimi yapılan eylem, etkinlik ve üretilen değer alalarında toplumsal katkı düzeyi ve üretilen değerin niteliği doğrultusunda eylem, etkinlik ve üretilen değerlerin izlemesini yaparak izlediği performans göstergeleri ve anket sonuçları gibi ölçmelerle değerlendirerek iyileştirme önerilerini geliştirir. Tespit edilen iyileştirme ve önerileri Kalite ve Akreditasyon Komisyonu’na sunar ve uygun görülenlerin uygulanmasını takip eder. Ayrıca Araştırma Geliştirme Birimi öğretim üyeleri, öğrenciler, dış paydaş ve kurumlar tarafından önerilen projeleri; Fakülte politikaları ve kurumsal öneriler çerçevesinde değerlendirerek uygun olanları projelendirir.\n","uygulama_alanlari":"Fakülte ve alt birimler (Akademik personel, idari personel, tüm öğrenciler, yerel, bölgesel, ulusal ve uluslararası alanlar)","ilk_planlama_tarihi":"2025-01-01","izleme_mekanizmalari":"Araştırma-Geliştirme Komisyonu Toplantıları\nDış Paydaş Komisyonu Toplantıları\nAkademik personel memnuniyet anketleri\nÖğrenci memnuniyet anketleri\nMezunlarla yapılan anketler\nDers memnuniyet anketleri\nAkademik Kurul Toplantıları\nBölüm Kurulu Toplantıları\n","uluslararasi_paydaslar":"-","performans_gostergeleri":"Öğrencilerin memnuniyet oranları\nAkademik personelin memnuniyet oranları\nDış paydaşların memnuniyet oranları\nMezunların Memnuniyet Oranları\nAkademik Kurul Toplantıları\nYönetimin Gözden Geçirmesi Raporları\n","degerlendirme_iyilestirme_tarihi":"2026-09-01"}'::jsonb) ON CONFLICT (id) DO UPDATE SET olcut_adi = EXCLUDED.olcut_adi, kalite_el_kitabi = EXCLUDED.kalite_el_kitabi;
INSERT INTO public.alt_olcutler (id, kod, olcut_adi, olcut_adi_en, olcut_adi_ar, ana_baslik_id, kalite_el_kitabi) VALUES (42, 'C.1.3', 'Araştırmaların Yerel/Bölgesel/Ulusal İhtiyaç ve Taleplerle İlişkisi', 'Relationship of Research to Local/Regional/National Needs and Demands', 'علاقة البحث بالاحتياجات والطلبات المحلية/الإقليمية/الوطنية', 3, '{"bgs_yeri":"https://abys-ivory.vercel.app/tr/olcutler/42/kalite-el-kitabi","ic_paydaslar":"Akademik ve İdari personel ve Öğrenciler","dis_paydaslar":"İl ve İlçe Meb Müdürlükleri ve İl ve İlçe Müftülükleri","sorumlu_birim":"Kalite ve Akreditasyon Komisyonu Kalite Takip Komisyonu Araştırma ve Geliştirme Komisyonu ","aciklama_metni":"•\tC. 1. 3. Araştırmaların Yerel/Bölgesel/Ulusal İhtiyaç ve Taleplerle İlişkisi \nFakülte araştırma geliştirme çalışmalarında yerel, ulusal ve uluslararası önceliklere odaklanmayı hedefler. Aynı zamanda yerel ve bölgesel kurum ve paydaşlarla işbirliği kurarak bilimsel araştırmaları toplumsal fayda merkezli yönlendirmeye çalışır. Böyle bir politika merkezli gerçekleştirilecek proje ve faaliyetlerde yerel, bölgesel ve ulusal ihtiyaç ve taleplere cevap vermeyi hedefler. Bu nitelikteki projeleri destekleyip yenilerinin geliştirilmesinin önünü açar. Bahsi geçen öncelikler çerçevesinde iç ve dış paydaşlarla düzenli istişare ve danışma toplantıları yaparak kendini günceller.\nAraştırma Geliştirme Birimi proje geliştirmelerinde diğer akademik kurumlarla ortak projeler, kamu kurumları ve toplum tabanlı araştırma merkezleriyle ortak projelerde toplumsal farkındalığın geliştirilmesi, sosyal sorumluluğun ve akademik bilgi birikiminin arttırılmasını hedefler.\nAraştırma geliştirme birimi, etkinlik ve projelerin uygulanmasını düzenli olarak izler. Kalite ve Akreditasyon Koordinatörlüğüne süreç hakkında bildirimlerde bulunur. İç ve dış paydaşlarla yaptığı toplantılarla sürecin sıhhatini gözlemleyip stratejiler geliştirir.\n","uygulama_alanlari":"Akademik personel, idari personel, tüm öğrenciler, yerel, bölgesel, ulusal ve uluslararası alanlar.","ilk_planlama_tarihi":"2025-01-01","izleme_mekanizmalari":"Araştırma-Geliştirme ve Uluslararasılaştırma Komisyonu Toplantıları\nYıllık Faaliyet Raporu\nDış paydaş anketleri\nÖğrenci memnuniyet anketleri\nMezunlarla yapılan anketler\nDers memnuniyet anketleri\nAkademik Kurul Toplantıları\nBölüm Kurulu Toplantıları\n","uluslararasi_paydaslar":"-","performans_gostergeleri":"Öğrencilerin memnuniyet oranları\nAkademik personelin memnuniyet oranları\nDış paydaşların memnuniyet oranları\nMezunların memnuniyet oranları\nYıllık faaliyetlerin analizi\nYıllık Faaliyet Raporu\nYerel/Bölgesel/Ulusal/uluslararası hedeflerin göstergesel verileri\n","degerlendirme_iyilestirme_tarihi":"2026-09-01"}'::jsonb) ON CONFLICT (id) DO UPDATE SET olcut_adi = EXCLUDED.olcut_adi, kalite_el_kitabi = EXCLUDED.kalite_el_kitabi;
INSERT INTO public.alt_olcutler (id, kod, olcut_adi, olcut_adi_en, olcut_adi_ar, ana_baslik_id, kalite_el_kitabi) VALUES (43, 'C.2.1', 'Araştırma Kaynakları: Fiziki, Teknik, Mali', 'Research Resources: Physical, Technical, Financial', 'مصادر البحث: المادية والفنية والمالية', 3, '{"bgs_yeri":"","ic_paydaslar":"Akademik Kurul, Lisans ve lisansüstü öğrenci temsilcileri, Ar-Ge Komisyonu, Kalite ve Akreditasyon Komisyonu, Dekanlık, Rektörlük ","dis_paydaslar":"TÜBİTAK,  Diyanet İşleri Başkanlığı, Milli Eğitim Bakanlığı, Kültür Bakanlığı, Adalet Bakanlığı, Eskişehir İl Müftülüğü, Eskişehir İl Milli Eğitim Müdürlüğü, Eskişehir Gençlik ve Spor İl Müdürlüğü, ESİLDER ve Eskişehir İslami İlimler Vakfı ","sorumlu_birim":"Planlama: Araştırma Geliştirme Koordinatörlüğü Uygulama: Ar-Ge Faaliyetleri Alt Komisyonları Değerlendirme: Araştırma Geliştirme Koordinatörlüğü, Kalite ve Akreditasyon Komisyonu İyileştirme: Araştırma Geliştirme Koordinatörlüğü, Kalite ve Akreditasyon Komisyonu Onay: Kalite ve Akreditasyon Komisyonu, Dekanlık","aciklama_metni":"Fakültemiz gerek akademik personel gerekse lisans, yüksek lisans ve doktora seviyesindeki öğrencilerimizin eğitim-öğretim ve araştırma faaliyetlerine destek olabilecek yeterli donanıma sahiptir. İdari personelimiz fakültemizin iç ve dış paydaşlarının her türlü desteği sayesinde bu faaliyetleri akademik eğitime kazandırma konusunda fakülte yönetimi ile tam bir iş birliği içerisinde çalışmaktadır. Akademik birimde yer alan her bir hocamızın ve idari personelin görevlerini yerine getirebilmeleri için gerekli olan ekipmanların yanı sıra ihtiyaç halindeki mali destek dekanlık tarafından sağlanmakta ve denetlenmektedir. Bunların başında akademik ve idari personelin görevlerini yerine getirmek için temel ihtiyaçları olan çalışma odası, ofis ekipmanları, kurum tarafından tahsis edilmiş bilgisayar ve yazıcı gelmektedir.\nKurumumuzun öncelikli hedefi akademik eğitim ve öğretimi geliştirmek olduğundan akademik personel ve öğrencilere yönelik pek çok ders dışı faaliyet ve araştırma kaynağı imkânı sunulmaktadır. Bu bağlamda dekanlık onayı ile fakültemiz tarafından bütün akademik personele ve öğrencilere açık şekilde gerçekleştirilen sempozyum ve çalıştaylar, kurum bünyesindeki öğrenci kulüplerinin hazırlamış oldukları panel, konferans ve söyleşilerin yanı sıra gönüllü hocalarımız tarafından gerçekleştirilen rutin dışında eğitim-öğretim faaliyetleri düzenlenmektedir. Fakültemiz, akademik personelimizin çalışmalarını geliştirmelerini ve mali açıdan kolaylaştırmalarını sağlamak amacıyla TÜBİTAK, BAP, Diyanet İşleri Başkanlığı, Milli Eğitim Bakanlığı, Kültür Bakanlığı, Adalet Bakanlığı, Gençlik ve Spor İl Müdürlüğü, Aile ve Sosyal Hizmetler İl Müdürlüğü gibi doğrudan devlet kurumlarının yanı sıra Anadolu Üniversitesi Açık Öğretim Fakültesi, İslami İlimler Vakfı ve STK’lar gibi özerk kuruluşlarla da işbirliği içerisinde olup bütün bu kurumlarla ortak çalışmaları desteklemektedir. Bu bağlamda akademik personelimiz içinde öğrencilerimizle ortak hazırlanmış pek çok proje hazırlanmıştır. Ayrıca kurumumuz, üniversitemiz bünyesindeki Uluslararası İlişkiler Birimi ile sıkı bir ilişki içerisinde olup başta BAP/ERASMUS olmak üzere birim bünyesindeki bütün uluslararası hareketlilik konusunda akademik personelimizi ve öğrencilerimizi teşvik etmektedir. ","aciklama_metni_en":"Our faculty is equipped with the necessary resources to support the teaching, learning, and research activities of both our academic staff and our undergraduate, master’s, and doctoral students. Thanks to the support of our faculty’s internal and external stakeholders, our administrative staff works in full collaboration with the faculty administration to integrate these activities into our academic programs. In addition to the equipment necessary for each faculty member and administrative staff member to perform their duties, the Dean’s Office provides and oversees the financial support required as needed. Among these are the basic necessities for academic and administrative staff to carry out their duties, such as workrooms, office equipment, and computers and printers allocated by the institution.\nSince our institution’s primary goal is to advance academic education and teaching, we offer a wide range of extracurricular activities and research resources for academic staff and students. In this context, symposia and workshops organized by our faculty—and open to all academic staff and students with the dean’s approval—are held alongside panels, conferences, and discussions prepared by student clubs within the institution, as well as educational activities conducted by our volunteer faculty members outside of regular teaching hours. To support our academic staff in advancing their work and to provide financial assistance, our faculty collaborates not only with direct government agencies such as TÜBİTAK, BAP, the Presidency of Religious Affairs, the Ministry of National Education, the Ministry of Culture, the Ministry of Justice, and the Provincial Directorate of Youth and Sports, and the Provincial Directorate of Family and Social Services, as well as autonomous organizations such as the Anadolu University Open Education Faculty, the Foundation for Islamic Sciences, and NGOs, to support the professional development of our academic staff and provide them with financial assistance. In this context, numerous projects have been developed jointly by our academic staff and students. Furthermore, our institution maintains close ties with the International Relations Unit within our university and encourages our academic staff and students to participate in all international mobility programs offered by the unit, particularly BAP/ERASMUS. \n","uygulama_alanlari":"Fakülte ve alt birimler (Akademik personel, idari personel, tüm öğrenciler, yerel, bölgesel, ulusal ve uluslararası alanlar)","ilk_planlama_tarihi":"2025-10-28","izleme_mekanizmalari":"Araştırma-Geliştirme Komisyonu Toplantıları\nDış Paydaş Komisyonu Toplantıları\nAkademik personel memnuniyet anketleri\nÖğrenci memnuniyet anketleri\nMezunlarla yapılan anketler\nDers memnuniyet anketleri\nAkademik Kurul Toplantıları\nBölüm Kurulu Toplantıları","uluslararasi_paydaslar":"","performans_gostergeleri":"Öğrencilerin memnuniyet oranları\nAkademik personelin memnuniyet oranları\nDış paydaşların memnuniyet oranları\nMezunların memnuniyet oranları\nAkademik kurul toplantıları\nYönetimin gözden geçirmesi raporları","degerlendirme_iyilestirme_tarihi":"2026-07-01"}'::jsonb) ON CONFLICT (id) DO UPDATE SET olcut_adi = EXCLUDED.olcut_adi, kalite_el_kitabi = EXCLUDED.kalite_el_kitabi;
INSERT INTO public.alt_olcutler (id, kod, olcut_adi, olcut_adi_en, olcut_adi_ar, ana_baslik_id, kalite_el_kitabi) VALUES (44, 'C.2.2', 'Üniversite İçi Kaynaklar', 'Internal University Resources', 'موارد الجامعة الداخلية', 3, '{"bgs_yeri":"","ic_paydaslar":"BAP Koordinasyon Birimi, Dekanlık, Kalite ve Akreditasyon Komisyonu, Ar-Ge Faaliyetleri Komisyonu, Lisans ve lisansüstü öğrenci temsilcileri","dis_paydaslar":"TÜBİTAK, Diyanet İşleri Başkanlığı, Milli Eğitim Bakanlığı, Kültür Bakanlığı, Adalet Bakanlığı, Eskişehir İl Müftülüğü, Eskişehir İl Milli Eğitim Müdürlüğü, Eskişehir Gençlik ve Spor İl Müdürlüğü, ESİLDER ve Eskişehir İslami İlimler Vakfı Proje kapsamındaki ulusal kuruluşlar","sorumlu_birim":"Planlama: BAP Koordinasyon Birimi, Dekanlık, Ar-Ge Koordinatörlüğü Uygulama: BAP Koordinasyon Birimi, Ar-Ge Faaliyetleri Alt Komisyonları Değerlendirme: BAP Koordinasyon Birimi, Araştırma Geliştirme Koordinatörlüğü İyileştirme: Araştırma Geliştirme Koordinatörlüğü Onay: Kalite ve Akreditasyon Komisyonu ","aciklama_metni":"Fakültemiz üniversite içi kaynak kullanımında en önemli desteği, üniversitemizin Bilimsel Araştırma Projeleri Koordinasyon Birimi’nden (BAP) almaktadır. BAP kapsamında akademik personelimiz ve onların projelerinde yer alan öğrencilerin çalışma şartlarını iyileştirme adına söz konusu birimden gerekli görülen ölçülerde mali destek sağlanmaktadır. Bu mali destek projenin türü, konusu ve ihtiyacı oranında değişiklik gösterir. Bu bağlamda araştırmaların geliştirilmesi ve birimden destek sağlanması amacıyla hem akademik personelin mail sistemine bildirimler iletilmekte hem de gerekli görüldüğünde duyurular ilan edilmektedir. Ayrıca BAP Birimi’nin resmi internet sayfasında desteklenen projelerin konusu ve türleri, mali hesaplaması ve genel prosedürüne dair bilgiler yer almaktadır. Akademik personelimizin BAP çerçevesinde yürüttüğü projeler Fakülte Yönetimi ile Kalite ve Akreditasyon Komisyonu tarafından izlenmekle birlikte Ar-Ge Komisyonu ve alt birimlerince denetlenmektedir. Bu sebeple gerek Akreditasyon gerekse Ar-Ge komisyonlarınca raporlar nitelik ve niceliğin artırılmasına yönelik bu konuda düzenlenen fakülte yönetimine iletilmektedir. ","aciklama_metni_en":"Our faculty receives its most significant support for the use of internal university resources from the university’s Scientific Research Projects Coordination Unit (BAP). Under the BAP framework, financial support is provided by this unit to the extent deemed necessary to improve the working conditions of our academic staff and the students participating in their projects. This financial support varies depending on the type, subject, and needs of the project. In this context, to facilitate the development of research and the provision of support from the unit, notifications are sent to the academic staff’s email system, and announcements are posted when deemed necessary. Additionally, the BAP Unit’s official website contains information on the subjects and types of supported projects, financial calculations, and general procedures. The projects carried out by our academic staff under the BAP framework are monitored by the Faculty Administration and the Quality and Accreditation Commission, and are also audited by the R&D Commission and its sub-units. For this reason, reports prepared by both the Accreditation and R&D commissions regarding efforts to improve quality and quantity in this area are submitted to the Faculty Administration. ","uygulama_alanlari":"Fakülte, akademik personel ve fakültenin lisans/lisansüstü eğitim programına kayıtlı öğrenciler, proje konusuna dayalı ulusal ve uluslararası kuruluşlar","ilk_planlama_tarihi":"2025-10-13","izleme_mekanizmalari":"BAP Koordinasyon Birimi Toplantıları\nAr-Ge Komisyonu Toplantıları\nAkademik personel memnuniyet anketleri\nAkademik Kurul Toplantıları\nBölüm Kurulu Toplantıları\nBAP konulu icra ve bilgilendirme seminerleri\nESOGÜ İlahiyat İnternet Sayfası (https://ilahiyat.ogu.edu.tr/Sayfa/Index/166/projeler)","uluslararasi_paydaslar":"","performans_gostergeleri":"BAP Koordinasyon Birimi’nden gelen raporlar\nAr-Ge Komisyonu İzleme-Geliştirme raporları\nAkademik Kurul Toplantıları\nYönetimin Gözden Geçirmesi Raporları\n","degerlendirme_iyilestirme_tarihi":"2026-06-15"}'::jsonb) ON CONFLICT (id) DO UPDATE SET olcut_adi = EXCLUDED.olcut_adi, kalite_el_kitabi = EXCLUDED.kalite_el_kitabi;
INSERT INTO public.alt_olcutler (id, kod, olcut_adi, olcut_adi_en, olcut_adi_ar, ana_baslik_id, kalite_el_kitabi) VALUES (45, 'C.2.3', 'Üniversite Dışı Kaynaklara Yönelik Yöntem ve Destekler', 'Methods and Support for Non-University Resources', 'طرق ودعم الموارد غير الجامعية', 3, '{"bgs_yeri":"","ic_paydaslar":"Akademik personel, öğrenciler, idari personel","dis_paydaslar":"BAP, ETTOM, TÜBİTAK, MEB, DİB ve STK’lar","sorumlu_birim":"Dekanlık Araştırma ve Geliştirme Komisyonu  Kalite Takip Komisyonu","aciklama_metni":"Fakültemiz, gerek kurumumuza bağlı çalışmalarda gerekse BAP’a dayalı projelerde ulusal ve uluslararası mali fonlara erişimle ilgili proje hazırlama, araştırma kaynaklarının kullanımı gibi konularda BAP ve üniversitemiz bünyesinde bulunan Eskişehir Teknoloji Transfer Ofisi Uygulama ve Araştırma Merkeziyle (ETTOM) iş birliği içerisindedir. Projeler kapsamında bu ve benzeri birimlerden destek alınır. Ar-Ge Faaliyet Komisyonu BAP ve ETTOM’la koordineli üniversite dışı kaynaklara ulaşım konusunda destek alır. Bu kapsamda fakülte personeline kurumsal e-maillerine gelen bilgilendirme ile proje tarihleri ve prosedürleri ile ilgili tanıtımlar yapılmaktadır. Fakültemiz bünyesindeki akademik personel bireysel olarak TÜBİTAK projelerine de başvurmakta, kurumumuz bu gibi projeleri bilhassa desteklemektedir. Bu bağlamda ilgili kurumlar gerekli görüldüğü durumlarda fakülte bünyesinde eğitim ve seminerler düzenleyebilir. İlgili kurumlarla gerçekleştirilen iş birliğine dair Ar-Ge Komisyonu’nun hazırladığı veri ve raporlar, faaliyetlerin niteliğinin geliştirilmesi ve artırılması amacıyla dekanlığa sunulur.","aciklama_metni_en":"Our faculty collaborates with the Research Projects Directorate (BAP) and the Eskişehir Technology Transfer Office Application and Research Center (ETTOM) within our university on matters such as project preparation and the use of research resources related to accessing national and international funding, both for initiatives under our institution and for BAP-funded projects. Support is obtained from these and similar units within the scope of these projects. The R&D Activities Commission receives support from BAP and ETTOM regarding access to external funding sources. In this context, faculty staff are informed via their institutional email accounts about project deadlines and procedures. Academic staff within our faculty also apply individually for TÜBİTAK projects, and our institution specifically supports such projects. In this context, relevant institutions may organize training sessions and seminars within the faculty when deemed necessary. Data and reports prepared by the R&D Commission regarding collaborations with these institutions are submitted to the Dean’s Office to enhance and expand the quality of these activities.","uygulama_alanlari":"Akademik personel, idari personel, tüm öğrenciler, yerel, bölgesel, ulusal ve uluslararası alanlar.","ilk_planlama_tarihi":"2025-10-01","izleme_mekanizmalari":"Araştırma-Geliştirme Komisyonu toplantıları\nYıllık Faaliyet Raporu\nAkademik Kurul Toplantıları\nBölüm Kurulu Toplantıları","uluslararasi_paydaslar":"","performans_gostergeleri":"Öğrencilerin memnuniyet oranları\nAkademik personelin memnuniyet oranları\nDış paydaşların memnuniyet oranları\nYönetimin gözden geçirmesi raporları\nYıllık faaliyetlerin analizi","degerlendirme_iyilestirme_tarihi":"2026-06-01"}'::jsonb) ON CONFLICT (id) DO UPDATE SET olcut_adi = EXCLUDED.olcut_adi, kalite_el_kitabi = EXCLUDED.kalite_el_kitabi;
INSERT INTO public.alt_olcutler (id, kod, olcut_adi, olcut_adi_en, olcut_adi_ar, ana_baslik_id, kalite_el_kitabi) VALUES (46, 'C.2.4', 'Kurumun Araştırma Politikası ve Uyumlu Lisansüstü Programlar', 'Institution''s Research Policy and Compatible Graduate Programs', 'السياسة البحثية للمؤسسة وبرامج الدراسات العليا المتوافقة', 3, '{"bgs_yeri":"","ic_paydaslar":"Bölüm Başkanlıkları, Anabilimdalı Başkanlıkları, Akademik personel, lisansüstü öğrenciler, gerekli durumlarda idari personel","dis_paydaslar":"ESOGÜ Sosyal Bilimler Enstitüsü ve Uluslararası İlişkiler Birimi, ESOGÜ Sosyal Bilimler Enstitüsü, Ar-Ge Komisyonu, BAP, STK ve üniversite dışı kurum ve kuruluşlar","sorumlu_birim":"Araştırma-Geliştirme Komisyonu","aciklama_metni":"İlahiyat Fakültesi, bünyesindeki üç temel bölüm ve bunlara bağlı alt anabilim dalları kapsamında görev yapan bütün öğretim üyelerinin aktif faaliyet gösterebilecekleri lisansüstü programları ve dersleri açılmasını teşvik eder. Bu kapsamda ilk olarak boş olan anabilim dallarında lisansüstü ders verebilecek akademik personelin fakülteye kazandırılması hedeflenir. Akademik kadro takibi ilgili bölüm başkanlığı ve dekanlık tarafından bizzat kontrol edilerek raporlanır. Lisansüstü öğrenciler ilgi alanlarına göre anabilim dallarına dağıtılır ve ulusal-uluslararası sahada tez konuları ve projeler konusunda bilgilendirilir. Öğrenciler ve doktorasını bitirmiş akademik personelin yurtdışında yüksek lisans, doktora ve post-doktora programlarına başvurmaları hususunda imkanlar sunulur.\nHerhangi bir anabilim dalında yeter sayıda öğretim üyesi bulunması halinde, ilgili akademik personelin lisansüstü faaliyeti desteklenir. Akademik personelin çalıştığı anabilim dalında gerekli gördüğü dersleri açması kolaylaştırılır. Bu konuda İlahiyat Fakültesi, üniversite bünyesindeki Sosyal Bilimler Enstitüsü ile ortak hareket eder. Bölümlerin problemleri, eksiklikleri ve yeni fikirlerin üretimiyle ilgili bölüm başkanlıkları güz ve bahar ders dönemlerinde bölüm toplantıları düzenler. Düzenlenen toplantılarda Ar-Ge Komisyonu’na destek sağlayacak temel görüşler, projeler ve fikirler görüşülür. Ar-Ge Komisyonu ile ortak hareket ederek ilgili öğretim üyesi ve lisansüstü öğrencilerin çeşitli proje ve faaliyetlerde ortak hareket etmeleri amaçlanır. Ar-Ge Komisyonu lisansüstü program faaliyetlerinde sadece ilgili alanın akademik programını değil, aynı zamanda fakülte ve üniversitenin misyon, vizyon ve stratejileriyle uyumlu, toplumsal katkıyı hedefleyen, sosyal bilim ölçütlerine uygun olan paydaş projeleri üretmeyi hedefler.","aciklama_metni_en":"The Faculty of Theology encourages the establishment of graduate programs and courses in which all faculty members working within its three main departments and their affiliated sub-departments can actively participate. In this context, the primary goal is to recruit academic staff capable of teaching graduate-level courses in sub-departments where there are currently vacancies. The academic staff is monitored and reported on directly by the relevant department chairs and the dean’s office. Graduate students are assigned to sub-disciplines based on their areas of interest and are informed about thesis topics and projects at the national and international levels. Opportunities are provided for students and faculty members who have completed their doctorates to apply for master’s, doctoral, and postdoctoral programs abroad.\nIf there are a sufficient number of faculty members in any department, the graduate studies of the relevant academic staff are supported. It is made easier for academic staff to offer courses they deem necessary in their respective departments. In this regard, the Faculty of Theology collaborates with the university’s Institute of Social Sciences. Department chairs organize department meetings during the fall and spring semesters to address departmental issues, shortcomings, and the generation of new ideas. At these meetings, key perspectives, projects, and ideas that will support the Research and Development (R&D) Commission are discussed. By working in collaboration with the R&D Commission, the aim is to facilitate joint participation by relevant faculty members and graduate students in various projects and activities. In its graduate program activities, the R&D Commission aims to develop stakeholder projects that are not only aligned with the academic program of the relevant field but also consistent with the faculty’s and university’s mission, vision, and strategies, aimed at social contribution, and in accordance with social science standards.","uygulama_alanlari":"Tüm fakülte ve akademik personel, lisansüstü öğrenciler, yerel, bölgesel, ulusal ve uluslararası kurum ve kuruluşlar.","ilk_planlama_tarihi":"2025-10-01","izleme_mekanizmalari":"Genel Kurul toplantıları \nESOGÜ Sosyal Bilimler Enstitüsü yönetim kurulu toplantıları\nAr-Ge ve uluslararasılaştırma Komisyonu Toplantıları\nAkademik kurul toplantıları\nBölüm kurulu toplantıları\nAkademik kadro anketleri\nAkademik kadro odak grup anketleri\nYıllık faaliyet raporu\nDış paydaş anketleri\nLisansüstü öğrenci memnuniyet anketleri\nUzmanlık dersleri ile lisansüstü öğrenci takibi","uluslararasi_paydaslar":"DİB Dış İlişkiler Genel Müdürlüğü, ESOGÜ Uluslararası İlişkiler Birimi","performans_gostergeleri":"Lisansüstü programlardaki araştırma politikalarıyla uyumlu çalışmaların sayısı\nLisansüstü programlardaki çalışmaların yerel, bölgesel ve ulusal dağılımlarının sayısı\nLisansüstü programlardaki çalışmaların yıllara göre sayısı\nKurumun lisansüstü programlarının sayısı, lisansüstü tercihlere ve bu tercihlerden memnuniyetlere yönelik anket verileri","degerlendirme_iyilestirme_tarihi":""}'::jsonb) ON CONFLICT (id) DO UPDATE SET olcut_adi = EXCLUDED.olcut_adi, kalite_el_kitabi = EXCLUDED.kalite_el_kitabi;
INSERT INTO public.alt_olcutler (id, kod, olcut_adi, olcut_adi_en, olcut_adi_ar, ana_baslik_id, kalite_el_kitabi) VALUES (47, 'C.3.1', 'Öğretim Elemanlarının Araştırma Yetkinliğinin Geliştirilmesi', 'Improving the Research Competency of Faculty Members', 'تحسين الكفاءة البحثية لأعضاء هيئة التدريس', 3, '{"bgs_yeri":"AVESİS, Fakülte İnternet Sitesi, Google Drive, Kalite Yönetim Sistemi e-posta adresi, WhatsApp grupları","ic_paydaslar":"İç Paydaşlar: Akademik Kurul, Tüm Öğretim Elemanları \n","dis_paydaslar":"Dış Paydaşlar: Danışma Kurulu, BAP Koordinatörlüğü, ETTOM Teknoloji Transfer Ofisi, Kütüphane Dokümantasyon Daire Başkanlığı, Rektörlük.","sorumlu_birim":"Akademik Yayın ve Destek Birimi  Akademik Faaliyetler Birimi  Kütüphane Koordinatörlüğü  Dekanlık Birim Kalite Koordinatörlüğü (İzleme ve Değerlendirme)  Ar-Ge Faaliyetleri Alt Komisyonu","aciklama_metni":"Kurumun öğretim elemanlarının araştırma yetkinliğinin geliştirilmesini kurumsal stratejik plan ile ilişkilendirilmiş tanımlı bir süreç üzerinden yürütülür. Bu süreç öğretim elemanlarının bireysel hedefleri ile üniversitenin bilimsel üretim ve toplumsal katkı hedeflerini birbirine örtüştürmeyi hedefler. Akademik personelin bireysel performansı AVESİS sistemi üzerinden izlenmektedir. Bireysel sayfalar aracılığıyla özgeçmiş, yayın, proje, etkinlik vb. veriler güncel tutulmaktadır.\nAkademik kadro atama ve yükseltme süreçlerinde araştırma yetkinliği, yayın kalitesi ve disiplinler arası işbirliği öncelikli kriterler arasında yer almakta; bu ölçütler düzenli olarak gözden geçirilerek geliştirilmektedir. Kurumun AR-GE politikaları, öğretim elemanlarının bireysel gelişim süreçleriyle entegre edilmiştir. Öğretim elemanlarının araştırma, yayın ve proje hazırlama becerilerini geliştirmek üzere seminerler, kurslar düzenlenmektedir. Bu faaliyetler, iç ve dış paydaşların katılımıyla, öğretim elemanlarının güncel bilimsel bilgi ve yöntemlere erişimini sağlamayı hedeflemektedir.\nKütüphane ve dökümantasyon daire başkanlığı, öğretim elemanlarının araştırma süreçlerinde ihtiyaç duydukları basılı ve dijital kaynaklara erişimi sağlamakta; eğitimlerle araştırma okuryazarlığı ve kaynak yönetimi becerilerinin artırılmasına katkı sunmaktadır.\nAR-GE koordinatörlüğü ve ilgili komisyonlar öncelikli araştırma alanlarının belirlenmesi, öğretim elemanlarının projelere katılımı, ulusal ve uluslararası fonlara erişimi için düzenli analiz ve yönlendirme çalışmaları yapmaktadır. Kurum, öğretim üyelerinin uluslararası araştırma projelerine katılımını teşvik edecek işbirliği protokoller imzalamakta, dış paydaşlarla etkileşimlerini güçlendirmektedir.\nAraştırma yetkinliği süreçleri, birim kalite koordinatörlükleri ve kalite komisyonu tarafından yılda iki kez gözden geçirilmektedir. Bu toplantıdan elde edilen bulgular, dekanlıklar aracılığıyla ilgili birimlere iletilip konuyla ilgili gerekli düzenlemeler yapılarak sürekli iyileştirilme döngüsü çalıştırılır.\n","aciklama_metni_en":"The development of the institution’s faculty members’ research competence is carried out through a defined process linked to the institutional strategic plan. This process aims to align the individual goals of faculty members with the university’s objectives for scientific output and societal contribution. The individual performance of academic staff is tracked through the AVESİS system. Data such as CVs, publications, projects, and events are kept up to date through individual profiles.\nIn academic staff appointment and promotion processes, research competence, publication quality, and interdisciplinary collaboration are among the primary criteria; these criteria are regularly reviewed and refined. The institution’s R&D policies are integrated with the individual development processes of faculty members. Seminars and courses are organized to enhance faculty members’ skills in research, publishing, and project development. These activities, conducted with the participation of internal and external stakeholders, aim to ensure that faculty members have access to current scientific knowledge and methods.\nThe Library and Documentation Directorate provides faculty members with access to the print and digital resources they need for their research processes; it also contributes to enhancing research literacy and resource management skills through training programs.\nThe R&D Coordination Office and relevant committees are responsible for identifying priority research areas, facilitating faculty participation in projects, and securing national and international funding\n\n","uygulama_alanlari":"Tüm öğretim elemanları","ilk_planlama_tarihi":"2025-10-01","izleme_mekanizmalari":"Akademik kadro anketi \nAkademik kadro odak grup görüşmesi \nDış paydaş anketi \nDış paydaş odak grup görüşmesi \nAVESİS bilgilendirme ve değerlendirme toplantıları, \nWhatsApp grupları, \nEğiticinin eğitimi seminerleri\n\n","uluslararasi_paydaslar":"Uluslararası Paydaşlar: Uluslararası Danışma Kurulu\n","performans_gostergeleri":"Öğretim elemanlarının araştırma yetkinliğinin geliştirilmesi için gerçekleştirilen etkinlik sayısı Öğretim elemanlarının araştırma yetkinliği performansı verileri  \nAVESİS’ten elde edilen veriler, düzenlenen seminer, kurs gibi faaliyetlerin sayısı\nAraştırma kadrosu doktora oranı, kümelenme vb. sayılar performans göstergeleri\n","degerlendirme_iyilestirme_tarihi":"0205-07-01"}'::jsonb) ON CONFLICT (id) DO UPDATE SET olcut_adi = EXCLUDED.olcut_adi, kalite_el_kitabi = EXCLUDED.kalite_el_kitabi;
INSERT INTO public.alt_olcutler (id, kod, olcut_adi, olcut_adi_en, olcut_adi_ar, ana_baslik_id, kalite_el_kitabi) VALUES (48, 'C.3.2', 'Ulusal ve Uluslararası Araştırma Birimleri ile Ortak Programlar', 'Joint Programs with National and International Research Units', 'برامج مشتركة مع وحدات البحوث الوطنية والدولية', 3, '{"bgs_yeri":"AVESİS, Fakülte İnternet Sitesi,Kalite Yönetim Sistemi e-posta adresi, WhatsApp grupları","ic_paydaslar":"Bölüm Kurulları, Akademik Kurul, Öğrenci Temsilcileri ","dis_paydaslar":"Danışma Kurulu, TÜBİTAK, Diyanet İşleri Başkanlığı, Milli Eğitim Bakanlığı, Kültür Bakanlığı, Adalet Bakanlığı, Eskişehir İl Müftülüğü, Eskişehir İl Milli Eğitim Müdürlüğü, Eskişehir Gençlik ve Spor İl Müdürlüğü, Proje kapsamındaki ulusal kuruluşlar\n \n\n","sorumlu_birim":"Dekanlık,  Anabilim Dalı Başkanlıkları  Akademik Faaliyetler Birimi  Birim Kalite Koordinatörlüğü (İzleme ve Değerlendirme)","aciklama_metni":"Ulusal ve Uluslararası Araştırma Birimleri ile Ortak Programlar\n\nKurum, araştırma-geliştirme faaliyetlerinde bölgesel, ulusal ve uluslararası ihtiyaçları dikkate alarak dış paydaşlarla iş birliğini güçlendirmeyi hedeflemektedir. Bu kapsamda, yeni protokoller imzalanmakta, mevcut iş birlikleri güncellenmekte ve ortak araştırma projelerine katkı sağlanmaktadır. Ulusal ve uluslararası ortak programların oluşturulması ve yürütülmesi dekanlık sorumluluğundadır. Lisansüstü düzeydeki ortak programlar Sosyal Bilimler Enstitüsü koordinasyonunda, ilgili anabilim dalları tarafından yürütülmektedir.\nİş birliklerine dair planlamalar Üniversite dış ilişkiler birimi tarafından hazırlanır ve rektörlük onayına sunulur. Yıl içerisinde dış paydaşlarla yapılan toplantılar ve her akademik yıl başında ve sonunda toplanan Uluslararası Danışma Kurulu aracılığıyla görüş alınır.\nBirim Kalite Koordinatörlüğü, süreçleri kalite açısından izler; Haziran ve Kasım aylarında hazırladığı raporları Kalite Komisyonuna sunar. Komisyon Temmuz ve Aralık aylarında toplanarak değerlendirme yapar. Kararlar dekanlık tarafından uygulanır.\n","aciklama_metni_en":"Joint Programs with National and International Research Units\n\nThe institution aims to strengthen collaboration with external stakeholders in its research and development activities, taking into account regional, national, and international needs. In this context, new protocols are being signed, existing collaborations are being updated, and contributions are being made to joint research projects. The Dean’s Office is responsible for establishing and implementing national and international joint programs. Joint programs at the graduate level are coordinated by the Institute of Social Sciences and carried out by the relevant departments.\nPlans regarding these collaborations are prepared by the University’s Office of External Relations and submitted to the Rector’s Office for approval. Input is gathered through meetings held with external stakeholders throughout the year and via the International Advisory Board, which convenes at the beginning and end of each academic year.\nThe Unit’s Quality Coordination Office monitors processes from a quality perspective; it submits reports prepared in June and November to the Quality Commission. The Commission meets in July and December to conduct evaluations. Decisions are implemented by the Dean’s Office.\n","uygulama_alanlari":"Tüm Öğretim Elemanları, Fakülte Lisans ve Lisansüstü Öğrencileri","ilk_planlama_tarihi":"2026-10-01","izleme_mekanizmalari":"Akademik personel memnuniyet anketi Akademik personel odak grup görüşmesi \nİç ve dış paydaşlar anketi\n İç ve dış paydaşlar odak grup görüşmesi Uluslararası paydaş anketi \nUluslararası paydaş odak grup görüşmesi Ulusal ve uluslararası araştırma birimleri ile yürütülen ortak programlara dair bilgi talebi, ilgili bilim dallarından toplantılarla izlenir, rapor olarak çıktılar istenir.\n","uluslararasi_paydaslar":" Uluslararası Danışma Kurulu","performans_gostergeleri":"İşbirliği protokol sayısı\nAraştırma ve uygulama merkezleri ortak işbirliği sayısı\nAR-GE faaliyetleri alt komisyonu toplantı sayısı \nAR-GE faaliyetleri alt komisyonu etkinlik sayısı \n","degerlendirme_iyilestirme_tarihi":"2026-07-10"}'::jsonb) ON CONFLICT (id) DO UPDATE SET olcut_adi = EXCLUDED.olcut_adi, kalite_el_kitabi = EXCLUDED.kalite_el_kitabi;
INSERT INTO public.alt_olcutler (id, kod, olcut_adi, olcut_adi_en, olcut_adi_ar, ana_baslik_id, kalite_el_kitabi) VALUES (49, 'C.4.1', 'Öğretim Elemanı Performans Değerlendirmesi', 'Instructor Performance Evaluation', 'تقييم أداء المعلم', 3, '{"bgs_yeri":"","ic_paydaslar":" Akademik Kurul, Bölüm Kurulları, Ar-Ge Faaliyetleri Alt Komisyonları","dis_paydaslar":"Fakülte Danışma Kurulu, Rektörlük","sorumlu_birim":"Araştırma Geliştirme Koordinatörlüğü, AR-GE Faaliyetleri Alt Komisyonları, Akademik Teşvik Komisyonu, Araştırma Geliştirme Koordinatörlüğü, Dekanlık,  Kalite ve Akreditasyon Komisyonu ","aciklama_metni":"Kurum, öğretim elemanlarının akademik yayınlara ilişkin performans değerlendirmesini AVESİS üzerinden takip eder. Öğretim elemanlarının performans değerlendirilmesi işlemi dekanlık tarafından yürütülür. Sisteme yüklenen kitap, makale, kitap bölümü v.b. yayın ve faaliyetler periyodik olarak izlenir. \nEskişehir Osmangazi Üniversitesi İlahiyat Fakültesi, öğretim elemanlarını akademik teşvikten yararlanmaya ve bu konuda çalışmalar yapmaya teşvik eder. Öğretim elemanlarından akademik teşvik puanı yüksek olanlara teşekkür belgesi verilir. Bu konudaki faaliyetlerden Akademik Teşvik Komisyonu sorumludur. Akademik Teşvik Komisyonu dekanlık ile koordineli olarak çalışır. Ayrıca Web of Science/ Scopus endeksli dergilerde yayın yapan ve çeşitli birimler kanalıyla proje üreten öğretim elemanlarına teşekkür belgesi verilir.\n","aciklama_metni_en":"The institution monitors the performance assessment of academic staff regarding academic publications via AVESİS. The performance assessment process for academic staff is carried out by the Dean’s Office. Publications and activities such as books, articles and book chapters uploaded to the system are monitored on a regular basis. \nThe Faculty of Theology at Eskişehir Osmangazi University encourages academic staff to benefit from academic incentives and to undertake work in this area. Certificates of appreciation are awarded to academic staff with high academic incentive scores. The Academic Incentives Commission is responsible for activities in this regard. The Academic Incentives Committee works in coordination with the Dean’s Office. Furthermore, certificates of appreciation are awarded to academic staff who publish in Web of Science/Scopus-indexed journals and undertake projects through various departments.\n","uygulama_alanlari":"Tüm akademik personel","ilk_planlama_tarihi":"2025-10-01","izleme_mekanizmalari":"Araştırma-Geliştirme Komisyonu Toplantıları\nAkademik Teşvik Komisyonu Toplantıları\nAkademik Kurul Toplantıları\nBölüm Kurulu Toplantıları\nAvesis\nYöksis\nVeri tabanları\n","uluslararasi_paydaslar":"-","performans_gostergeleri":"Öğretim Elemanlarının YÖKSİS Sayfasında yer alan araştırma performansları\nAVESİS verileri\nWeb of Science/Scopus’taki yayın performansı\nProje perfomans sayısı\nAkademik personelin yıllık araştırma performansı\n","degerlendirme_iyilestirme_tarihi":"2026-06-01"}'::jsonb) ON CONFLICT (id) DO UPDATE SET olcut_adi = EXCLUDED.olcut_adi, kalite_el_kitabi = EXCLUDED.kalite_el_kitabi;
INSERT INTO public.alt_olcutler (id, kod, olcut_adi, olcut_adi_en, olcut_adi_ar, ana_baslik_id, kalite_el_kitabi) VALUES (50, 'C.4.2', 'Araştırma Performansının Değerlendirilmesi ve İyileştirilmesi', 'Evaluation and Improvement of Research Performance', 'تقييم وتحسين أداء البحث', 3, '{"bgs_yeri":"","ic_paydaslar":"Akademik personel, öğrenciler, idari personel, mezunlar ","dis_paydaslar":"Fakülte Danışma Kurulu, Rektörlük","sorumlu_birim":"Kalite ve akreditasyon komisyonu, Kalite takip komisyonu, Akademik teşvik komisyonu, Fakülte kurulu, Dekanlık","aciklama_metni":"Fakültedeki öğretim elemanlarının akademik performanslarının belirlenmesi ve değerlendirilmesi, söz konusu araştırmaların nitelik ve nicelik bakımından arttırılması amacına yöneliktir. Bu anlamda fakülte, araştırma geliştirme politikasına uygun olarak, öğretim elemanlarına uluslararası, ulusal bölgesel ve yerel düzeyde bilimsel katkılar sağlayacak olan multidisipliner araştırmaları teşvik eder. \nAraştırma geliştirme alt komisyonu, YÖKSİS ile entegre çalışan AVESİS sistemi üzerinden gelen verilerle, atıf platformlarından gelen verileri değerlendirerek, araştırma faaliyetlerinin iyileştirilmesine yönelik teklif ve önerilerini fakülte dekanlığına sunar. Dekanlık paydaşların görüşlerini de dikkate alarak komisyonun değerlendirmeleri doğrultusunda gerekli iyileştirmeleri yapar.\n","aciklama_metni_en":"The assessment and evaluation of the academic performance of academic staff at the faculty are aimed at enhancing the quality and quantity of the research in question. In this regard, in line with its research and development policy, the faculty encourages multidisciplinary research that will enable academic staff to make scientific contributions at international, national, regional and local levels. \nThe Research and Development Sub-Committee evaluates data received via the AVESİS system—which is integrated with YÖKSİS—alongside data from citation platforms, and submits its proposals and recommendations for improving research activities to the Faculty Dean’s Office. The Dean’s Office implements the necessary improvements in line with the committee’s assessments, whilst also taking into account the views of stakeholders.","uygulama_alanlari":"Tüm akademik personel","ilk_planlama_tarihi":"2025-10-01","izleme_mekanizmalari":"AVESİS\nAkademik Teşvik Komisyonları\nVeri tabanları\n","uluslararasi_paydaslar":"-","performans_gostergeleri":"Öğretim Elemanlarının YÖKSİS Sayfasında yer alan araştırma performansları\nAVESİS verileri\nWeb of Science/Scopus’taki yayın performansı\nProje perfomans sayısı\nAkademik personelin yıllık araştırma performansı\n","degerlendirme_iyilestirme_tarihi":"2026-06-01"}'::jsonb) ON CONFLICT (id) DO UPDATE SET olcut_adi = EXCLUDED.olcut_adi, kalite_el_kitabi = EXCLUDED.kalite_el_kitabi;
INSERT INTO public.alt_olcutler (id, kod, olcut_adi, olcut_adi_en, olcut_adi_ar, ana_baslik_id, kalite_el_kitabi) VALUES (51, 'C.4.3', 'Araştırma Bütçe Performansı', 'Research Budget Performance', 'أداء ميزانية البحث', 3, '{"bgs_yeri":"","ic_paydaslar":"Akademik ve İdari Personel","dis_paydaslar":"Rektörlük\nEskişehir İslami İlimler Vakfı\nEskişehir Osmangazi Üniversitesi İlahiyat Fakültesi Mezun ve Mensupları Derneği (ESİLDER)\nEskişehir İl Müftülüğü\nEskişehir İl Milli Eğitim Müdürlüğü\n","sorumlu_birim":"Kalite Takip Komisyonu, Araştırma ve Geliştirme Komisyonu,  Dekanlık","aciklama_metni":"Fakülte, hizmet alımları, tüketim malları, malzeme alımları, yolluklar ile bakım ve onarım gibi bütçe planlamasında yer alan harcamalar için bütçe talebinde bulunur. İhtiyaç halinde ek bütçe teklif edilir. \nKurum merkezi bütçe dışında araştırmalarına kaynak sağlamak için Eskişehir İslami İlimler Vakfı, Eskişehir Osmangazi Üniversitesi İlahiyat Fakültesi Mezun ve Mensupları Derneği (ESİLDER), Eskişehir İl Müftülüğü ve Eskişehir İl Milli Eğitim Müdürlüğü ile işbirliği içindedir.\n","aciklama_metni_en":"The Faculty submits a budget request for expenditure included in the budget plan, such as the procurement of services, consumables, materials, travel expenses, and maintenance and repairs. Where necessary, a supplementary budget is proposed. \nIn addition to the central budget, the institution collaborates with the Eskişehir Foundation for Islamic Sciences, the Eskişehir Osmangazi University Faculty of Theology Alumni and Members’ Association (ESİLDER), the Eskişehir Provincial Directorate of Religious Affairs and the Eskişehir Provincial Directorate of National Education to secure funding for its research.\n","uygulama_alanlari":"Akademik personel, idari personel, tüm öğrenciler, yerel, bölgesel, ulusal ve uluslararası alanlar.","ilk_planlama_tarihi":"2025-10-01","izleme_mekanizmalari":"Yıllık Faaliyet Raporu\nAkademik personel memnuniyet anketi\nİdari personel memnuniyet anketi\n","uluslararasi_paydaslar":"-","performans_gostergeleri":"Akademik personelin memnuniyet oranları\nAraştırma faaliyetleri için tahsis edilen bütçe\n","degerlendirme_iyilestirme_tarihi":"2026-06-01"}'::jsonb) ON CONFLICT (id) DO UPDATE SET olcut_adi = EXCLUDED.olcut_adi, kalite_el_kitabi = EXCLUDED.kalite_el_kitabi;
INSERT INTO public.alt_olcutler (id, kod, olcut_adi, olcut_adi_en, olcut_adi_ar, ana_baslik_id, kalite_el_kitabi) VALUES (52, 'D.1.1', 'Toplumsal Katkı Politikası, Hedefleri ve Stratejisi', 'Social Contribution Policy, Goals and Strategy', 'سياسة المساهمة الاجتماعية والأهداف والاستراتيجية', 4, '{"bgs_yeri":"Fakülte İnternet Sitesi, Fakülte UBYS Sistemi, Akademik Kurul Toplantıları, ESOGÜ İlahiyat Fakültesi Bülteni, Fakülte İlan Panoları, WhatsApp grupları","ic_paydaslar":"Fakülte yönetimi, akademik ve idari personel, öğrenciler ve öğrenci toplulukları, ilgili fakülte komisyonları.","dis_paydaslar":"Eskişehir İl Müftülüğü Diyanet Gençlik Ofisi, Aile ve Sosyal Politikalar İl Müdürlüğü, Gençlik ve Spor İl Müdürlüğü gibi Kamu Kurumları; Anadolu Üniversitesi ve Eskişehir Teknik Üniversitesi’nin SKS Birimleri ve Öğrenci Toplulukları; Odunpazarı Belediyesi ve Tepebaşı Belediyesi gibi Yerel Yönetimler; Eskişehir Ticaret Odası, Eskişehir Sanayi Odası ve Esnaf Odaları Birliği gibi Özel Sektör Temsilcileri, Kaynak sağlanmasında destek ve katkı sunacak diğer kurum, kuruluş, ESİLDER, Türkiye Diyanet Vakfı gibi vakıf, dernek ve diğer STK’lar.","sorumlu_birim":"Toplumsal Katkı Koordinatörlüğü, Sosyal Sorumluluk ve Yardım Projeleri Birimi, Manevî Rehberlik ve Eğitim Faaliyetleri Birimi, Kültürel ve Akademik Etkinlikler Birimi","aciklama_metni":"D.1.1. Toplumsal katkı politikası, hedefleri ve stratejisi kapsamında Eskişehir Osmangazi Üniversitesi İlahiyat Fakültesi, toplumsal katkı faaliyetlerini üniversitenin 2025–2026 Stratejik Planı ve Yükseköğretim Kalite Kurulu’nun (YÖKAK) kalite güvence sistemi ilkeleri doğrultusunda planlamaktadır. Fakültemiz, bu kapsamda toplumun dinî, ahlaki ve manevî yönden desteklenmesini hedeflemekte; iç ve dış paydaşlarla iş birliği içerisinde çeşitli faaliyet alanları belirlemektedir.  \n\nBu alt ölçütün kurumsal yönetiminden ve yürütülmesinden Fakülte Kurulu gözetiminde Toplumsal Katkı Komisyonu / Koordinatörlüğü sorumludur. İç paydaşlarımız; akademik ve idari personel, öğrenciler ve öğrenci topluluklarıdır. Dış paydaşlarımız ise Eskişehir İl Müftülüğü, İl Millî Eğitim Müdürlüğü, belediyeler, sivil toplum kuruluşları, cezaevi ve hastane yönetimleri ile huzurevlerinden oluşmaktadır.","uygulama_alanlari":"Tüm Fakülte","ilk_planlama_tarihi":"2025-07-01","izleme_mekanizmalari":"Çevrimiçi etkinlik anketleri, -Mesaj kutusu, -Odak grup görüşmeleri, -Analiz raporları, -Komisyon değerlendirme raporları","uluslararasi_paydaslar":"Henüz doğrudan bir uluslararası paydaş işbirliği bulunmamaktadır.","performans_gostergeleri":"Tüm paydaşların toplumsal katkı organizasyonel yapısı ile ilgili memnuniyet oranlarını içeren çevrimiçi anket sonuçları, -Yıllara göre ilgili organizasyonel yapının toplantı ve etkinlik sayısı, -Toplumsal katkı hedeflerinin gerçekleşme oranları, -Organize edilen faaliyetlerin sayısı, karşılanan taleplerin sayısal verileri","degerlendirme_iyilestirme_tarihi":"2026-12-01"}'::jsonb) ON CONFLICT (id) DO UPDATE SET olcut_adi = EXCLUDED.olcut_adi, kalite_el_kitabi = EXCLUDED.kalite_el_kitabi;
INSERT INTO public.alt_olcutler (id, kod, olcut_adi, olcut_adi_en, olcut_adi_ar, ana_baslik_id, kalite_el_kitabi) VALUES (53, 'D.1.2', 'Toplumsal Katkı Süreçlerinin Yönetimi ve Teşkilat Yapısı', 'Management and Organizational Structure of Social Contribution Processes', 'الإدارة والهيكل التنظيمي لعمليات المساهمة الاجتماعية', 4, '{"bgs_yeri":"Fakülte İnternet Sitesi, Esogü İlahiyat Fakültesi Bülteni, WhatsApp grupları","ic_paydaslar":"Akademik ve idari personel, öğrenciler","dis_paydaslar":"Eskişehir İl Müftülüğü, Aile ve Sosyal Politikalar İl Müdürlüğü, Gençlik ve Spor İl Müdürlüğü, Diyanet Gençlik Ofisi, ESİLDER","sorumlu_birim":"Toplumsal Katkı Koordinatörlüğü","aciklama_metni":"Fakültede toplumsal katkı süreçleri Toplumsal Katkı Koordinatörlüğünün sorumluluğundadır.   Koordinatörlüğün alt birimleri olan Sosyal, Kültürel ve Sanatsal Faaliyetler, Mesleki Eğitim ve Uygulama ve Sosyal Yardım ve Destek Faaliyetleri Birimi organizasyonel yapının asli unsurlarıdır. Koordinatörlüğün temelde ilgilendiği iki ana başlık mevcuttur. Birincisi toplumsal katkıya yönelik seçmeli dersler, ikincisi, toplumsal katkıya yönelik faaliyetler. Bu temaları tartışmak, Fakültenin toplumsal politikası çerçevesine açılım sağlamak amacıyla koordinatörlüğün alt birimleri yılda en az iki defa (Kasım ve Haziran) toplantı yapar. Toplantı kararlarını ilgili iç (Eğitim Koordinatörlüğü gibi) ve dış paydaşlarla konuşur, gerekli yerlerde protokoller imzalar. Nihai olarak dönemsel toplumsal katkı kararları planlanır ve uygulanmaya başlar. Öğrencilerin, akademik personelin katılımıyla gerçekleşen toplumsal katkı faaliyetleri Fakülte internet sitesi ve sosyal medya hesapları ile kamuya açık hale getirilir. Uygulamalar bittikten sonra dönüt almak için iç ve dış paydaşlara izleme mekanizması olarak Etkinlik Anketleri uygulanır, gerekli durumlarda paydaşlarla odak grup görüşmeleri yapılarak gidişat kontrol edilir. Tüm süreci Toplumsal Katkı Koordinatörlüğü raporlar ve Birim Kalite Koordinatörlüğüne iletir. Birim Kalite Koordinatörlüğü süreci kalite bakımından izler, değerlendirir, tespit ve tekliflerini içeren raporunu Kalite Komisyonuna sunar. Kalite komisyonu değerlendirmelerini yaptıktan sonra Dekanlık bilgilendirilir. Dekanlık Birim Danışma Kurulu, STK’lar, MEB veya DİB gibi paydaşlarla istişarelerde bulunarak önlem alır veya gerekli iyileştirmeleri yapar. ","uygulama_alanlari":"Tüm fakülte","ilk_planlama_tarihi":"2025-07-30","izleme_mekanizmalari":"-Çevrimiçi etkinlik anketleri\n-Mesaj kutusu\n-Odak grup görüşmeleri\n","uluslararasi_paydaslar":"-","performans_gostergeleri":"-Tüm paydaşların toplumsal katkı organizasyonel yapısı ile ilgili memnuniyet oranlarını içeren çevrimiçi anket sonuçları\n-Yıllara göre ilgili organizasyonel yapının toplantı ve etkinlik sayısı\n-Toplumsal katkı hedeflerinin gerçekleşme oranları\n-Organize edilen faaliyetlerin sayısı, karşılanan taleplerin sayısal verileri\n","degerlendirme_iyilestirme_tarihi":"2025-11-30"}'::jsonb) ON CONFLICT (id) DO UPDATE SET olcut_adi = EXCLUDED.olcut_adi, kalite_el_kitabi = EXCLUDED.kalite_el_kitabi;
INSERT INTO public.alt_olcutler (id, kod, olcut_adi, olcut_adi_en, olcut_adi_ar, ana_baslik_id, kalite_el_kitabi) VALUES (54, 'D.2', 'Toplumsal Katkı Kaynakları', 'Social Contribution Sources', 'مصادر المساهمة الاجتماعية', 4, '{"bgs_yeri":"Fakülte İnternet Sitesi, Fakülte UBYS Sistemi, Akademik Kurul Toplantıları, ESOGÜ İlahiyat Fakültesi Bülteni, Fakülte İlan Panoları, WhatsApp grupları, ","ic_paydaslar":"Fakülte yönetimi, akademik ve idari personel, öğrenciler ve öğrenci toplulukları, ilgili fakülte komisyonları","dis_paydaslar":"Eskişehir İl Müftülüğü Diyanet Gençlik Ofisi, Aile ve Sosyal Politikalar İl Müdürlüğü, Gençlik ve Spor İl Müdürlüğü gibi Kamu Kurumları; Anadolu Üniversitesi ve Eskişehir Teknik Üniversitesi’nin SKS Birimleri ve Öğrenci Toplulukları; Odunpazarı Belediyesi ve Tepebaşı Belediyesi gibi Yerel Yönetimler; Eskişehir Ticaret Odası, Eskişehir Sanayi Odası ve Esnaf Odaları Birliği gibi Özel Sektör Temsilcileri, Kaynak sağlanmasında destek ve katkı sunacak diğer kurum, kuruluş, ESİLDER, Türkiye Diyanet Vakfı gibi vakıf, dernek ve diğer STK’lar.","sorumlu_birim":"Kaynakların etkili ve verimli kullanılmasından Dekanlık, Kalite ve Akreditasyon Komisyonu ve alt komisyonları sorumludur. Ayrıca ilgili etkinliğin paydaşları.","aciklama_metni":"Kurum, toplumsal katkı faaliyetlerini sürdürebilmek için uygun nitelik ve nicelikte fiziki, teknik ve mali kaynaklara sahip olmalı ve bu kaynakların etkin şekilde kullanımını sağlamalıdır.\nEskişehir Osmangazi Üniversitesi İlahiyat Fakültesi, bilgi ve birikimini toplum yararına sunmayı; toplumun kültürel, dini ve sosyal gelişimine katkıda bulunmayı ilke ve hedef edinmiştir. Bu kapsamda çeşitli faaliyetler yürüterek etkin, sürdürülebilir ve kalite odaklı toplumsal katkı çalışmaları gerçekleştirmeyi planlar. \nFakültemiz, toplumsal katkı faaliyetlerinin planlamasında, yürütülmesinde ve değerlendirilmesinde kullanacağı fiziki, dijital, bilişim, kütüphane, yayın, insan, işbirlikleri, ortaklıklar ve finansal kaynakları belirler, planlar, raporlar. Fakültemiz, kaynak yönetimi ve geliştirilmesini kalite güvence sistemi içerisinde sürekli izlemeyi ve iyileştirmeyi hedefler. Hedeflerin, amaçların, aksamadan uygulanabilir hale gelmesi ve sürdürülebilirlik ve iyileştirilme için, üniversitemizin ve fakültenin fiziksel imkanları dahilinde konferans, seminer ve toplantı salonları, fakülte resmi internet sitesi, uzaktan erişim sistemimiz (Esuzem) ve diğer online platformlar, merkez ve fakülte kütüphanemizde bulunan ilgili konularda basılı ve dijital kaynaklar, akademik ve idari personel, gönüllü öğrencilerimiz, sivil toplum kuruluşları, diğer yüksek öğretim kurumları ile yapılan işbirlikleri, protokoller, özel maddi kaynaklar, TÜBİTAK, BAP gibi projelerden sağlanan maddi destekler kaynak olarak kullanılmak üzere planlaması yapılır. Kaynakların etkin ve verimli kullanımından Dekanlık ve Kalite ve Akreditasyon Komisyonu sorumludur. \nEskişehir Osmangazi Üniversitesi İlahiyat Fakültesi, toplumla köklü ve güçlü bir iletişim ve etkileşim kurarak bilgi birikimini toplum yararına sunmaya devam etme sürecinde, toplumsal katkı alanındaki kaynak kullanımını planlı, ölçülebilir ve sürdürülebilir bir şekilde gerçekleştirmeyi amaç edinir. Böylece toplumsal katkı alanındaki etkinliğini ve görünürlüğünü hedeflediği çeşitli kaynaklar vasıtasıyla kalite güvencesi çerçevesinde artırmaya devam etmeyi istikrarlı bir şekilde sürdürür.\n","aciklama_metni_en":"In order to continue its social contribution activities, the institution must possess physical, technical and financial resources of an appropriate quality and quantity, and ensure the effective use of these resources.\nThe Faculty of Theology at Eskişehir Osmangazi University has adopted as its principle and objective the sharing of its knowledge and expertise for the benefit of society, and contributing to the cultural, religious and social development of society. Within this framework, it plans to carry out effective, sustainable and quality-focused social contribution initiatives through various activities. \nOur Faculty identifies, plans and reports on the physical, digital, IT, library, publishing, human, collaborative, partnership and financial resources it will utilise in the planning, implementation and evaluation of its social contribution activities. Our Faculty aims to continuously monitor and improve resource management and development within the quality assurance system. To ensure that objectives and aims are implemented without disruption and to foster sustainability and improvement, we utilise the physical facilities of our university and Faculty—including conference, seminar and meeting rooms, the Faculty’s official website, our remote access system (Esuzem) and other online platforms; printed and digital resources on relevant subjects available in our central and faculty libraries; academic and administrative staff; our student volunteers; civil society organisations; collaborations and protocols with other higher education institutions; special financial resources; and financial support provided by projects such as TÜBİTAK and BAP serve as resources.\n\n","uygulama_alanlari":"Fakülte içi seminerler, çalıştaylar, halk konferansları, yerel ve bölgesel düzeyde gerçekleştirilen sosyal sorumluluk projeleri, ulusal etkinlik ve projelerdeki katılımlar","ilk_planlama_tarihi":"2025-10-20","izleme_mekanizmalari":"-Çevrimiçi etkinlik anketleri\n-Mesaj kutusu\n-Odak grup görüşmeleri\n-Analiz raporları\n-Komisyon değerlendirme raporları\n","uluslararasi_paydaslar":"Henüz doğrudan bir uluslararası paydaş işbirliği bulunmamaktadır.","performans_gostergeleri":"Tanımlı kaynak türlerinin etkin kullanımı, gerçekleştirilen toplumsal katkı faaliyeti sayısı ve çeşitliliği, elde edilen katılımcı geri bildirimlerinin olumluluk oranı, kaynak yönetimine ilişkin düzenli toplantı ve raporlama verileri","degerlendirme_iyilestirme_tarihi":"2026-07-20"}'::jsonb) ON CONFLICT (id) DO UPDATE SET olcut_adi = EXCLUDED.olcut_adi, kalite_el_kitabi = EXCLUDED.kalite_el_kitabi;
INSERT INTO public.alt_olcutler (id, kod, olcut_adi, olcut_adi_en, olcut_adi_ar, ana_baslik_id, kalite_el_kitabi) VALUES (55, 'D.3', 'Toplumsal Katkı Performansı', 'Social Contribution Performance', 'أداء المساهمة الاجتماعية', 4, '{"bgs_yeri":"Fakülte İnternet Sitesi, Fakülte UBYS Sistemi, Akademik Kurul Toplantıları, ESOGÜ İlahiyat Fakültesi Bülteni, Fakülte İlan Panoları, WhatsApp grupları, ","ic_paydaslar":"Fakülte Yönetimi, akademik ve idari personel, öğrenciler ve öğrenci toplulukları, ilgili fakülte komisyonları.","dis_paydaslar":"Eskişehir İl Müftülüğü Diyanet Gençlik Ofisi, Aile ve Sosyal Politikalar İl Müdürlüğü, Gençlik ve Spor İl Müdürlüğü gibi Kamu Kurumları; Anadolu Üniversitesi ve Eskişehir Teknik Üniversitesi’nin SKS Birimleri ve Öğrenci Toplulukları; Odunpazarı Belediyesi ve Tepebaşı Belediyesi gibi Yerel Yönetimler; Eskişehir Ticaret Odası, Eskişehir Sanayi Odası ve Esnaf Odaları Birliği gibi Özel Sektör Temsilcileri, Kaynak sağlanmasında destek ve katkı sunacak diğer kurum, kuruluş, ESİLDER, Türkiye Diyanet Vakfı gibi vakıf, dernek ve diğer STK’lar.","sorumlu_birim":"Toplumsal Katkı Koordinatörlüğü","aciklama_metni":"     ESOGÜ İlahiyat Fakültesi Kalite El Kitabında yer alan vizyon ve misyona, toplumsal katkı komisyonunca belirlenen stratejiye uygun olan faaliyetler; bu faaliyetlerin izlenmesi adına hangi araçların kullanılacağı ve bunlara ait zaman çizelgesi akademik yılın başında yapılacak toplantıyla planlanır. Bu planlamada, anket, odak grup görüşmesi gibi yöntemlerden hangilerinin hangi etkinlik için geçerli olacağı; anket ve geri bildirim formlarının içerik ve uygulama şekli ve ayrıca odak gruplarla yapılacak görüşmelerin esasları belirlenir. \n     Toplumsal katkı koordinatörlüğü, etkinlik performanslarının izlenmesine yönelik kullanılan araçları uygulama sürecinden de sorumludur. Planlanan etkinlikler için belirlenen ölçme ve değerlendirme araçları koordinatörlük tarafından tespit edilen zaman ve şartlara göre uygulanır. Bu süreçte fakülte yönetimi, akademik kurul, il ve ilçe müftülükleri, KYK müdürlükleri ve STK’lar gibi paydaşlarla işbirliğine gidilir. Toplumsal katkı komisyonu anket sonuçlarını, geri bildirim formlarından elde edilen verileri ve yaptığı odak grup görüşmelerinin sonuçlarını fakülte yönetimi ve komisyon üyeleriyle periyodik olarak paylaşır. Bu araçların süreç içinde nasıl kullanıldığı, hedefine ulaşıp ulaşmadığı varsa hangi zorluklarla karşılaşıldığı tespit edilir. Uygulanan anketlerin verimliliği, geri bildirim formlarının kullanışlılığı, odak grup görüşmelerinin hangi seviyede sonuç verdiği izlenir.\n       Yıl boyunca gerçekleştirilen faaliyetlerin izlenmesine yönelik uygulanan performans ölçütlerine dair değerlendirmelere ve elde edilen verilere göre bu araçların (anket, odak grup görüşmesi vb.) aksayan tarafları ve uygulamadaki zorlukları belirlenir. Yapılan analizler sonrasında bir sonraki yıl için revizyona gidilir. Anketlerin şekil ve içeriklerinde, odak grup görüşmelerine ait esaslarda ve geri bildirim formlarının yapısında gerekli düzenleme ve iyileştirmeler yapılır.\n","aciklama_metni_en":"     Activities that align with the vision and mission outlined in the ESOGÜ Faculty of Theology Quality Manual and with the strategy determined by the Social Contribution Commission—as well as the tools to be used to monitor these activities and the corresponding timeline—are planned during a meeting held at the beginning of the academic year. As part of this planning, it is determined which methods—such as surveys and focus group discussions—will be applicable to which activities; the content and implementation methods of surveys and feedback forms; and the principles governing focus group discussions. \n     The Social Contribution Coordination Office is also responsible for the implementation process of the tools used to monitor activity performance. The measurement and evaluation tools identified for the planned activities are implemented according to the timeline and conditions established by the Coordination Office. During this process, collaboration takes place with stakeholders such as the faculty administration, the academic council, provincial and district muftis’ offices, KYK directorates, and NGOs. The Social Contribution Commission periodically shares survey results, data obtained from feedback forms, and the outcomes of its focus group discussions with the faculty administration and commission members. The commission assesses how these tools are used within the process, whether they achieve their objectives, and what challenges, if any, are encountered. It monitors the effectiveness of the surveys, the usefulness of the feedback forms, and the level of results achieved through the focus group discussions.\n  Based on evaluations of the performance indicators used to monitor activities carried out throughout the year and the data obtained, the shortcomings of these tools (surveys, focus group discussions, etc.) and the challenges in implementing them are identified. Following these analyses, revisions are made for the following year. Necessary adjustments and improvements are made to the format and content of surveys, the guidelines for focus group discussions, and the structure of feedback forms.\n\n\n","uygulama_alanlari":"Tüm Fakülte","ilk_planlama_tarihi":"2025-10-15","izleme_mekanizmalari":"-Çevrimiçi etkinlik anketleri\n-Mesaj kutusu\n-Odak grup görüşmeleri\n-Analiz raporları\n-Değerlendirme raporları\n","uluslararasi_paydaslar":"Henüz doğrudan bir uluslararası paydaş işbirliği bulunmamaktadır.","performans_gostergeleri":"-Tüm paydaşların toplumsal katkı organizasyonel yapısı ile ilgili memnuniyet oranlarını içeren çevrimiçi anket sonuçları\n-Yıllara göre ilgili organizasyonel yapının toplantı ve etkinlik sayısı\n-Toplumsal katkı hedeflerinin gerçekleşme oranları\n-Organize edilen faaliyetlerin sayısı, karşılanan taleplerin sayısal verileri\n","degerlendirme_iyilestirme_tarihi":"2026-07-15"}'::jsonb) ON CONFLICT (id) DO UPDATE SET olcut_adi = EXCLUDED.olcut_adi, kalite_el_kitabi = EXCLUDED.kalite_el_kitabi;
INSERT INTO public.alt_olcutler (id, kod, olcut_adi, olcut_adi_en, olcut_adi_ar, ana_baslik_id, kalite_el_kitabi) VALUES (56, 'E.1.1', 'Yönetim Modeli ve İdari Yapı', 'Management Model and Administrative Structure', 'نموذج الإدارة والهيكل الإداري', 5, '{"bgs_yeri":"OGUBS / Fakülte İnternet Sitesi / Elektronik Belge Yönetim Sistemi","ic_paydaslar":"Akademik ve İdari Personel ile Öğrenciler","dis_paydaslar":"Kamu ve Sivil Kurum ve Kuruluşları ","sorumlu_birim":"Dekanlık / Kalite ve Akreditasyon Sorumlu Birimi","aciklama_metni":"E. YÖNETİM SİSTEMİ\nE.1. Yönetim ve İdari Birimlerin Yapısı\nE.1.1. Yönetim modeli ve idari yapı\nKurumun yönetsel, temel ve destek süreçlerinin planlanması; misyonu, vizyonu, stratejik hedefleri ilgili yasa, mevzuat ve yönetmelikler doğrultusunda yapılandırılır. Kurum yönetim yapısı, akademik yapı ve idari yönetim yapısı olarak ikiye ayrılmaktadır. Akademik yönetim yapısı; Akademik Teşkilat Yönetmeliği, 2547 Sayılı Yükseköğretim Kanunu, 2809 sayılı Yükseköğretim Kurumları Teşkilat Kanunu ve diğer mevzuatlar ile belirlenmiştir. Fakültedeki yönetim yapısı dekan, iki dekan yardımcısı, fakülte sekreteri ve üç bölüm başkanından oluşmuştur. Fakülte idari yapısı, fakülte sekreteri ile sekreterlik bürosundan, öğrenci işleri, personel, kütüphane, mali işler, yayın ve destek hizmetleri biriminden oluşur. Kanuni düzenlemeler esas alınarak fakülte, Dekan tarafından temsil edilmekte ve dekan tarafından seçilen ve idari işlerin yürütülmesinde dekana yardımcı olan iki dekan yardımcısı bulunmaktadır. Kurumun idari yönetim yapısı, 124 Sayılı Kanun Hükmünde Kararname ve ilgili diğer mevzuatlar çerçevesinde belirlenmiştir. Fakültede, Dekan başkanlığında belirli aralıklarla ve kurumsal ihtiyaçlara binaen Fakülte Kurulu ve Fakülte Yönetim Kurulu toplantılar düzenlenmektedir. Bu kurulların dışında fakülte dekanının başkanlığında fakülte akademik personelinin tamamının katıldığı dönem içinde en az iki defa Akademik Kurul Toplantısı yapılır. Bu toplantılarda eğitim-öğretim süreci değerlendirilir ve sınavlar, öğrenci başarı durumları, müfredatın işleyişi ve ders devamsızlıkları gibi konularda öğretim elemanlarından bilgi alınıp fakülte kurulunda görüşülmek üzere tavsiye niteliğinde kararlar alınır. Fakültede yer alan Temel İslam Bilimleri, Felsefe ve Din Bilimleri ve İslam Tarihi ve Sanatları bölümleri ve anabilim dalları kurumsal, akademik ve eğitim öğretim ile ilgili gereksinimler sebebiyle belirli aralıklarla toplantılar yapılır. Kurum, mensuplarının yönetim süreçlerine katılmalarına büyük önem verir. Bireysel farklılıkları, fikirleri ve birikimleri ortak idealler çerçevesinde yönetim süreçlerine entegre etmeyi ilke edinir.\nKurum, vizyon ve misyonu doğrultusunda şeffaf ve hesap verebilir bir yönetim anlayışını, etkili yönetişim ve liderlik anlayışı doğrultusunda, eğitim, araştırma ve topluma hizmette sürekli gelişim ve ilerlemeyi öncelemektedir. Bunun için nitelikli akademik ve idari personelin istihdam edilmesini, dini mirası sağlam dayanaklarla yorumlama becerisine sahip, hayat boyu öğrenme yeterlilikleri ve 21. yüzyılın gerektirdiği becerilerle donatılmış ilahiyatçılar yetiştirmeyi hedeflemektedir. Tüm kaynaklarının etkinlik ve verimlilik odaklı kullanılmasındaki süreçleri titizlikle izleyen, kurumsal bilginin korunmasını ve güvenirliğini güvence altına alan bir yönetim sistemi politikasını izlemektedir. Kurum, yönetim sistemleri kapsamında hizmet verilen tüm paydaşların memnuniyetini sağlamayı; Eğitim-öğretim ve araştırma-geliştirme alanlarında gerekli yönetsel ve teknolojik altyapının geliştirilmesini, sürdürülebilirlik ve sürekli iyileştirmeyi hedefleyen yönetim sistemi çalışmalarını sistematik olarak yürütmeyi amaçlamaktadır. Yönetsel sistem ve süreçlerin etkili bir şekilde kullanan iyi uygulama örneklerini araştırmayı ve kuruma kazandırmayı önemser. Yönetim sistemlerine ilişkin faaliyetlerin güvence altına alınmasını sağlayacak aksiyomlar geliştirir.\n","uygulama_alanlari":"Fakülte ve diğer alt birimler","ilk_planlama_tarihi":"2026-06-15","izleme_mekanizmalari":"İç paydaş anketleri (Yönetim yapısı ve modeli ile ilgili sorular) / Dış paydaş anketleri (Yönetim yapısı ve modeli ile ilgili sorular) / İç paydaş personel odak grup görüşmeleri (Yönetim yapısı ve modeli ile ilgili değerlendirmeler)/Dış paydaş odak grup görüşmeleri (Yönetim yapısı ve modeli ile ilgili değerlendirmeler)","uluslararasi_paydaslar":"","performans_gostergeleri":"İç paydaşların yönetim yapısı ve modeli ile ilgili memnuniyet oranı / Dış paydaşların yönetim yapısı ve modeli ile ilgili memnuniyet oranı / Stratejik amaç ve hedeflerinin gerçekleştirme oranı/ Değerlendirme","degerlendirme_iyilestirme_tarihi":"2026-06-15"}'::jsonb) ON CONFLICT (id) DO UPDATE SET olcut_adi = EXCLUDED.olcut_adi, kalite_el_kitabi = EXCLUDED.kalite_el_kitabi;
INSERT INTO public.alt_olcutler (id, kod, olcut_adi, olcut_adi_en, olcut_adi_ar, ana_baslik_id, kalite_el_kitabi) VALUES (57, 'E.1.2', 'Süreç Yönetimi', 'Process Management', 'إدارة العمليات', 5, '{"bgs_yeri":"Fakülte İnternet Sitesi / Google Drive / Kalite Yönetim Sistemi E-Posta Adresi / WhatsApp Grupları","ic_paydaslar":"Akademik ve İdari Personel \n","dis_paydaslar":"Rektörlük ve Birim Danışma Kurulu \n","sorumlu_birim":"Süreç Yönetimin İzlenmesi ve Değerlendirilmesi","aciklama_metni":"E.1.2. Süreç yönetimi\nKurumda eğitim-öğretim, araştırma-geliştirme, toplumsal katkı, idari ve teknik hizmetler, uluslararasılaşma vb. tüm faaliyetler tanımlı süreçlere bağlı olarak gerçekleştirilmektedir. Süreç yönetiminde akademik ve idari işleyişin verimliliğini artırmak, kalite standartlarını sürekli geliştirmek ve paydaşların memnuniyetini sağlamak temel hedeftir. Süreç yönetimi, fakültenin hedeflerine ulaşması için gerekli olan tüm akademik, idari ve mali süreçlerin analiz edilmesi, izlenmesi ve sürekli iyileştirilmesini içermektedir. Süreçlerin performansı, aksiyonlar, iç/dış değerlendirme sonuçları, süreç performans gösterge sonuçları, faaliyet raporları, iç/dış paydaş memnuniyet anketleri ve öneriler vb. doğrultusunda farklı sıklıklarda çeşitli yöntemlerle takip edilmektedir. Fakültede kurumsal olarak uygulanan tüm yönetim yaklaşımları, iç kontrol standartları ile uyumlu olarak yapılır. Kurum eylem planları, planların izlenmesi ve değerlendirilmesi bu çerçevede gerçekleştirilir. Bunun yanı sıra iç kontrol öz değerlendirme anketi, yıllık durum değerlendirmesine imkân sağlar. İlgili eylem planları ise birimler bazında hazırlanır. Süreç yönetiminden Dekanlık sorumludur. Birim Kalite Koordinatörlüğü süreci kalite açısından takip eder. Koordinatörlük sürece ilişkin tespit ve tekliflerini Haziran ve Kasım aylarında Kalite Komisyonunda görüşülmek üzere Dekanlığa sunar. Komisyon, Temmuz ve Aralık aylarında toplanıp koordinatörlüklerden gelen raporları inceleyerek değerlendirmelerini Dekanlığa bildirir. Dekanlık, komisyonun değerlendirmeleri doğrultusunda dış paydaşların da görüşlerini alarak gerekli iyileştirmeleri yapar. Kurumda tüm birimleri ve alanları kapsayacak şekilde yönetilen süreçlere ilişkin sonuçlar, performans göstergeleriyle sistematik olarak izlenmekte, paydaşların görüşleri alınmakta ve izlem sonuçları paydaşlarla birlikte değerlendirilerek önlemler alınmakta ve ihtiyaçlar/talepler doğrultusunda güncellemeler gerçekleştirilmektedir. Süreç performans göstergeleri, Kalite Koordinatörlüğü tarafından belirlenen periyotlarda raporlanır, gerektiğinde sürecin iyileştirilmesi yönünde teklifler hazırlar.\n","aciklama_metni_en":"","uygulama_alanlari":"Tüm Alt Ölçütler / Tüm Birim ve Alanlar","ilk_planlama_tarihi":"2026-06-15","izleme_mekanizmalari":"Akademik Personel Anketleri / İdari Personel Anketleri / Öğrenci Anketleri Dış paydaş Anketleri (Fakültede Süreç Yönetimin Olup Olmadığına Dair Sorular) / İç ve Dış Paydaş Odak Grup Görüşmeleri / Öz Değerlendirme Raporu / Akreditasyon Değerlendirme Süreçleri","uluslararasi_paydaslar":"","performans_gostergeleri":"İç ve Dış Paydaş Memnuniyet Oranları / Odak Grup Görüşme Memnuniyet Oranları / Rubrik’in her bir alt ölçütü için verdiği olgunluk düzeyi / İç kontrol öz değerlendirme anketi verileri, süreç yönetimi el kitabına uygunluk karşılaştırma verileri","degerlendirme_iyilestirme_tarihi":"2027-06-15"}'::jsonb) ON CONFLICT (id) DO UPDATE SET olcut_adi = EXCLUDED.olcut_adi, kalite_el_kitabi = EXCLUDED.kalite_el_kitabi;
INSERT INTO public.alt_olcutler (id, kod, olcut_adi, olcut_adi_en, olcut_adi_ar, ana_baslik_id, kalite_el_kitabi) VALUES (58, 'E.2.1', 'İnsan Kaynakları Yönetimi', 'Human Resources Management', 'إدارة الموارد البشرية', 5, '{"bgs_yeri":"Yönetim sistemi/ E.2. Kaynakların Yönetimi/ E2.1. İnsan Kaynakları Yönetimi","ic_paydaslar":"Dekanlık\nPersonel İşleri Şefliği\nBirim\tKalite\tKoordinatörlüğü","dis_paydaslar":"Birim Danışma Kurulu\nİç Denetim Birim Başkanlığı\nRektörlük\nPersonel Daire Başkanlığı\n","sorumlu_birim":"İnsan\tKaynaklarının\tYönetimine\tDair Süreçler","aciklama_metni":"Eskişehir Osmangazi Üniversitesi İlahiyat Fakültesi, insan kaynakları yönetimi politikasını ve hedeflerini Eskişehir Osmangazi Üniversitesi Kalite Yönetim Sistemi Kalite El Kitabı’nda belirlenmiş tanımlı süreçlere uygun olarak yürütülmektedir. Bu kapsamda insan kaynakları politikaları ve uygulamaları Üniversite tarafından belirlenen usul ve esaslar doğrultusunda gerçekleştirilmektedir. (KANIT: 1). Eskişehir Osmangazi Üniversitesi Rektörlüğü, adil, şeffaf ve ahlaki değerler doğrultusunda, sosyal sorumluluk yaklaşımı bilinci ile, çalışanının yetişmesini, öğrenmesini, bilgi aktarımını, takım çalışmasını ve yeteneklerinin geliştirmesini teşvik ederek, paydaşlara değer katılmasını sağlar.\nİnsan kaynakları yönetiminde, Eskişehir Osmangazi Üniversitesinin İnsan Kaynakları Yönergesi (KANIT: 2) ile İnsan Kaynakları Politikası (KANIT: 3) esasları temel alınmaktadır. Fakültede insan kaynakları; akademik (KANIT: 4) ve idari personel (KANIT: 5) olmak üzere iki ana grupta yönetilmektedir. İdari personel ihtiyacı, birimler tarafından belirlenerek gerekçeleri ile birlikte Rektörlük ve Personel Daire Başkanlığı’na bildirilmektedir. (KANIT: 6). Ataması yapılan personel, ilgili mevzuat hükümleri çerçevesinde uygun kadro ve unvanlara yerleştirilmektedir. (KANIT: 7)\nFakülte, mevcut personelinin hizmet içi eğitimler alarak donanımlı hâle gelmesine önem vermiştir. İdari kadroların gerekli yetkinliğe sahip olması konusunda Eskişehir Osmangazi Üniversitesi Kalite Yönetim Sistemi Kalite El Kitabı’nda belirlenen politikaları esas almıştır. Bu doğrultuda hem mevcut idari personelin hem de yeni atananların geliştirme ve değerlemesiyle ilgili düzenlemeler yapmıştır. (Personelin mesleki gelişimini desteklemek amacıyla hizmet içi eğitim faaliyetlerine katılım sağlanmakta olup, bu süreçler Rektörlük tarafından planlanan eğitim programları doğrultusunda yürütülmektedir. Eğitimlere ilişkin katılım bilgileri ve sertifikalar ilgili sistemler üzerinden takip edilmektedir.) Nitekim idari personelin 2035-2026 yıllarında eğitim ihtiyacının giderilmesi ve kariyerlerinin geliştirilmesine yönelik Rektörlük bünyesinde gerçekleştirilen hizmet içi eğitim kurslarına katılımları sağlanmıştır (KANIT: 8) Personelimizin hizmet içi eğitim süreci Rektörlüğün planlaması dahilinde yürütülmektedir. ","uygulama_alanlari":"Tüm akademik ve idari personel","ilk_planlama_tarihi":"2026-06-15","izleme_mekanizmalari":"2026  yılı  akademik ve idari  personel  anketi ","uluslararasi_paydaslar":"","performans_gostergeleri":"Atanma ve yükseltilme kriterlerinin fakülte bazlı düşünülerek fakültenin ihtiyaç ve beklentilerine göre düzenlenmesi teklif edilmiştir.","degerlendirme_iyilestirme_tarihi":"2026-09-01"}'::jsonb) ON CONFLICT (id) DO UPDATE SET olcut_adi = EXCLUDED.olcut_adi, kalite_el_kitabi = EXCLUDED.kalite_el_kitabi;
INSERT INTO public.alt_olcutler (id, kod, olcut_adi, olcut_adi_en, olcut_adi_ar, ana_baslik_id, kalite_el_kitabi) VALUES (59, 'E.2.2', 'Finansal Kaynakların Yönetimi', 'Management of Financial Resources', 'إدارة الموارد المالية', 5, '{"bgs_yeri":"Yönetim sistemi/ E.2. Kaynakların Yönetimi/ E.2.2. Finans Kaynaklarının Yönetimi","ic_paydaslar":"Akademik ve idari personel, öğrenciler, Maaş İşleri Bürosu, Tahakkuk Birimi, \nHarcama Yetkilisi, Gerçekleştirme Görevlisi, Taşınır Kayıt Yetkilisi ve Taşınır Kontrol Yetkilisi\n","dis_paydaslar":"Rektörlük,\tEskişehir Osmangazi Üniversitesi\tStrateji Geliştirme Daire Başkanlığı, Birim Danışma Kurulu, T.C. Hazine ve Maliye Bakanlığı\n\n\n","sorumlu_birim":"Dekanlık Birim\tKalite\tKoordinatörlüğü","aciklama_metni":"Fakültede öğrencilerin, akademisyenlerin, araştırmacıların, bilimsel çalışma yapanların, toplumun, kurum ve kuruluşlar ile çalışanların memnuniyetini artırmak için gerekli olan iç ve dış finansal kaynaklar, insan kaynakları, alt yapı (tesis, bina, makina, teçhizat, cihaz, donanım, ulaşım), doğal kaynaklar, teknoloji, bilgi, çalışma ortamı kaynaklarını belirlemek, finansal kaynakların yönetimini uygulamak, sürdürmek ve etkinliğini sürekli iyileştirmek konusunda İstanbul Üniversitesi Kalite Yönetim Sistemi Kalite El Kitabı’nda belirlenen esaslara göre hareket eder.\nBu çerçevede fakülte, çalışan personeline maaş ödemesi yanında, ek ders ücretleri, harcırah, fazla mesai ve proje ödemeleri gibi kalemler adı altında ödemeler yapmaktadır. Kurumda yapılan harcamalar için tanımlanmış süreçler mevcuttur. Bütün ödeme ve harcamalar bu süreçlere göre işletilmiştir. Maaş, tahakkuk, taşınır gibi ödeme kalemlerinde bulunan birimler harcamalara dair planlarını yapmış (KANIT: 1) ve bunlar Dekanlık tarafından Rektörlüğe sunulmuştur. Rektörlük, Maliye Bakanlığı tarafından tahsis edilen kaynağı Fakültelere dağıtmış, bütün harcamalar buna göre katma bütçeden yapılmıştır.\nAyrıca kurumun başta elektrik, su, doğalgaz, telefon, internet, bakım-onarım olmak üzere başka bazı genel harcamaları da olmuştur. Bunlar doğrudan Fakülte bütçesinden karşılanmıştır. Fakültedeki mali işlerden sorumlu görevliler, önceki yılların verileri ve enflasyon beklentileri gibi faktörleri dikkate alarak bütçenin kalemlere göre tahmini dağılımını yapmıştır. Kurum, 2025 yılı sonunda gelecek iki yılın bütçe planlamasını yapmış ve bunu üniversiteye bildirmiştir (KANIT: 2).\nFakültede hizmet veren idari ve akademik personelin maaşlarının nasıl hesaplanıp ödeneceğine dair süreç, Mali İşler Bürosu tarafından planlanmıştır. Mali İşler Bürosu, bir memurun göreve başlama yazısının Personel İşleri Bürosuna intikalinden sonra o personele maaş ödemesiyle ilgili nelerin yapılacağını adım adım planlamış ve bu plana göre hareket etmiştir. Mali İşler Bürosu, maaşların ödenmesiyle ilgili bütün iş ve işlemleri takip ederek ortaya çıkan aksamaları gidermiş ve bunların bir daha olmaması için önlemini almış; maaş işleriyle ilgili sürecin kendiliğinden yürümesi, süreklilik ve sürdürülebilirlik ilkelerine uygun olarak işlemesini sağlamıştır (KANIT: 3).\nFakültede akademik ve idari personelin ek ders ücretleri, fazla mesai ücretleri, yolluklar, yevmiyeler ve diğer tahakkuklara dair süreç, Tahakkuk Birimi tarafından yürütülmektedir. Birim bunun için planlamalar yapmakta ve bu plan çerçevesinde hareket etmektedir. Tahakkuk Birimi planlamasını yaptığı bu işlerin uygulamada nasıl işlediğini kontrol etmektedir. Birim, sorumlu olduğu işlerle ilgili süreçlerin kendiliğinden işlemesi, süreklilik ve sürdürülebilirlik ilkelerine uygun olarak yürümesini temin etmektedir. (KANIT: 4).\n","uygulama_alanlari":"Tüm Fakülte Bütçesi","ilk_planlama_tarihi":"2026-06-15","izleme_mekanizmalari":"2026 Akademik ve İdari Personel anketi","uluslararasi_paydaslar":"","performans_gostergeleri":"","degerlendirme_iyilestirme_tarihi":"2026-12-15"}'::jsonb) ON CONFLICT (id) DO UPDATE SET olcut_adi = EXCLUDED.olcut_adi, kalite_el_kitabi = EXCLUDED.kalite_el_kitabi;
INSERT INTO public.alt_olcutler (id, kod, olcut_adi, olcut_adi_en, olcut_adi_ar, ana_baslik_id, kalite_el_kitabi) VALUES (60, 'E.3.1', 'Entegre Bilgi Yönetim Sistemi', 'Integrated Information Management System', 'نظام إدارة المعلومات المتكامل', 5, '{"bgs_yeri":"Üniversite Bilgi Yönetim Sistemi, Entegre Bilgi Sistemi → Kalite Yönetim Modülü → Kalite El Kitabı","ic_paydaslar":"Akademik ve İdari Personel / Öğrenciler / İç Denetim Birimi","dis_paydaslar":"Rektörlük Birimleri, Diyanet İşleri Başkanlığı","sorumlu_birim":"Dekanlık, Birim Kalite Koordinatörlüğü (İzleme ve Değerlendirme)","aciklama_metni":"Entegre Bilgi Yönetim Sistemi kapsamında fakültenin eğitim-öğretim, araştırma, yönetim ve idari süreçlerine ilişkin veriler elektronik ortamda toplanmakta, analiz edilmekte ve raporlanmaktadır. Bilgi yönetimi; Öğrenci Bilgi Sistemi (OBS), Elektronik Belge Yönetim Sistemi (EBYS), Akademik Bilgi Sistemi (ABS), ESUZEM, kurumsal e-posta ve fakülte web sayfası üzerinden bütünleşik olarak yürütülmektedir. Üniversite Bilgi Sistemi''nde üretilen veriler düzenli olarak yedeklenmekte, yazılım ve donanım altyapısı değişen mevzuat ve teknolojik ihtiyaçlar doğrultusunda güncellenmektedir. Kurumsal bilgi ve kalite dokümanları tanımlı süreçler çerçevesinde yönetilmekte; performans göstergeleri, değerlendirme raporları ve diğer kurumsal veriler kalite güvence süreçlerinde etkin biçimde kullanılmaktadır. Ayrıca fakülte, ÖSYM, YÖK ve Kimlik Paylaşım Sistemi gibi ulusal bilgi sistemleriyle entegre çalışarak veri doğruluğu ve süreçlerin güvenilirliğini sağlamaktadır.","aciklama_metni_en":"","uygulama_alanlari":"Tüm süreçler (öğrenme ve öğretme, araştırma ve geliştirme, toplumsal katkı,\nkalite güvencesi)","ilk_planlama_tarihi":"2025-01-01","izleme_mekanizmalari":"Akademik, idari personel ve öğrenci anketler,\nAnketlerde entegre bilgi sistemin olup olmadığına dair sorulan sorular\nBazı yönetim süreçlerinin kâğıt veya internet üzerinden olup olmadığına\ndair sorulan sorular","uluslararasi_paydaslar":"Erasmus ve uluslararası iş birliği kurumları","performans_gostergeleri":"Görüşme ve Toplantı raporları ile anket sonuçları, Zamanında veri giriş oranı (%), eksiksiz kanıt yükleme oranı, doğrulanan veri oranı, güncellenen süreç sayısı, PUKÖ tamamlanma oranı","degerlendirme_iyilestirme_tarihi":"0026-01-07"}'::jsonb) ON CONFLICT (id) DO UPDATE SET olcut_adi = EXCLUDED.olcut_adi, kalite_el_kitabi = EXCLUDED.kalite_el_kitabi;
INSERT INTO public.alt_olcutler (id, kod, olcut_adi, olcut_adi_en, olcut_adi_ar, ana_baslik_id, kalite_el_kitabi) VALUES (61, 'E.3.2', 'Bilgi Güvenliği ve Güvenilirliği', 'Information Security and Reliability', 'أمن المعلومات والموثوقية', 5, '{"bgs_yeri":"Üniversite Bilgi Sistemleri / Fakülte İnternet Sitesi / Google Drive\nKalite Yönetim Sistemi E-Posta Adresi / WhatsApp Grupları","ic_paydaslar":"Akademik ve İdari Personel / Öğrenciler / İç Denetim Birimi","dis_paydaslar":"Bilgi İşlem Daire Başkanlığı","sorumlu_birim":"Dekanlık, Birim Kalite Koordinatörlüğü (İzleme ve Değerlendirme)","aciklama_metni":"Bilgi güvenliği ve güvenirliği süreçleri, Dekanlık sorumluluğunda yürütülmektedir. Sürecin kalite güvencesi açısından izlenmesi ve değerlendirilmesi Birim Kalite Koordinatörlüğü tarafından gerçekleştirilmektedir. Koordinatörlük, bilgi güvenliği ve veri yönetimine ilişkin izleme sonuçları, tespitler ve iyileştirme önerilerini Haziran ve Kasım aylarında hazırladığı raporlarla Kalite Komisyonunun değerlendirmesine sunmaktadır. Kalite Komisyonu ise Temmuz ve Aralık aylarında yaptığı toplantılarda bu raporları değerlendirerek alınan karar ve önerileri Dekanlığa iletmektedir. Dekanlık, Komisyon değerlendirmeleri ile iç ve dış paydaşlardan elde edilen geri bildirimleri dikkate alarak bilgi güvenliği ve veri yönetimi süreçlerine yönelik gerekli iyileştirme ve önleyici faaliyetleri planlamakta ve uygulamaktadır. Böylece bilgi güvenliği ve güvenirliği süreçleri, PUKÖ (Planla-Uygula-Kontrol Et-Önlem Al) döngüsü esas alınarak sistematik biçimde izlenmekte, değerlendirilmekte ve sürekli iyileştirilmektedir.","aciklama_metni_en":"","uygulama_alanlari":"Tüm veri kaynakları","ilk_planlama_tarihi":"2025-01-01","izleme_mekanizmalari":"Öğrenci memnuniyet anketleri (konu ile ilgili sorular)\nAkademik personel memnuniyet anketleri (Konu ile ilgili sorular)\nİdari personel (Konu ile ilgili sorular)\nÖğrenci, akademik ve idari personel odak grup görüşmeleri\nBilgi ve veri araçları","uluslararasi_paydaslar":"-","performans_gostergeleri":"Öğrenci, akademik ve idari personel memnuniyet oranları\nBilgi güvenliği ve güvenilirliğine dair anket verileri","degerlendirme_iyilestirme_tarihi":"2026-07-01"}'::jsonb) ON CONFLICT (id) DO UPDATE SET olcut_adi = EXCLUDED.olcut_adi, kalite_el_kitabi = EXCLUDED.kalite_el_kitabi;
INSERT INTO public.alt_olcutler (id, kod, olcut_adi, olcut_adi_en, olcut_adi_ar, ana_baslik_id, kalite_el_kitabi) VALUES (62, 'E.4.1', 'Hizmet ve Malların Uygunluğu, Kalitesi ve Sürekliliği', 'Suitability, Quality and Continuity of Services and Goods', 'الملاءمة والجودة واستمرارية الخدمات والسلع', 5, '{"bgs_yeri":"Google Drive, Kamu Harcama ve Muhasebe Bilişim Sistemi (KBS) Taşınır Kayıt ve Yönetim Sistemi (TKYS)","ic_paydaslar":"Akademik ve İdari Personel / Öğrenciler / İç Denetim Birimi","dis_paydaslar":"Kamu ve özel kurumlar ile tedarikçiler","sorumlu_birim":"Dekanlık ve Birim Kalite Koordinatörlüğü (İzleme ve Değerlendirme)","aciklama_metni":"Kurumda satın alma ve ihale işlemleri; şeffaflık, verimlilik, saydamlık, gizlilik ve hesap verilebilirlik ilkeleri doğrultusunda yapılmaktadır. Hizmet ve malların uygunluğu, kalitesi, performansı ve sürekliliğini sağlayan mekanizmalar izlenmekte ve ilgili paydaşların geri bildirimleri alınarak iyileştirilmektedir. Hizmet alımlarında Kamu İhale Mevzuatı gereğince; \n\nhttps://www.mevzuat.gov.tr/mevzuat?MevzuatNo=12918&MevzuatTur=7&MevzuatTertip=5\n\nhazırlanırken hizmetten yararlanacak kişi ya da sorumlu birimlerin görüşleri dikkate alınmaktadır. Buna göre;\n\n1. Talep edilen birim tarafından ürünün veya hizmetin Teknik Şartnamesine bağlı kalınarak sözleşmeler yapılmaktadır.\n\n2. En uygun firmalar ve ürünler tercih edilmektedir. \n\n3. Mal ve hizmet alımlarının temin sürekliliği, sözleşmelerde belirtilen, garanti süresi, teminat bedeli, teknik ve idari şartnamelere yapılan atıflar, alım sonrası bakım ve güncelleme ile desteklenmekte ve güvence altına alınmaktadır.\n\n4. Birimler tarafından ihtiyaç duyulan satın almalar Harcama Yetkilisine (Fakülte Dekanına) bildirilir. \n\n5. Birimlerden gelen satın alma talepleri yaklaşık maliyet yönüyle değerlendirilir. \n\n6. Her yıl yeni bütçede belirlenen rakam doğrultusundaki satın almalara Harcama Yetkilisi (Fakülte Dekanı) karar verebilir.\n\n7. Tedarikçilerden (onaylı ve/veya yeni tedarikçi) teklif alınır. \n\n8. Gerek görülen ürünlerden numune talep edilir.\n\n9. Toplanan teklifler ve onaylanan numuneler Muayene Komisyonunca değerlendirilerek Harcama Yetkilisine sunulur.\n\n10. Harcama yetkilisinin seçtiği tedarikçiden ürün/hizmet talep edilir.\n\n11. Tüm alımlarda düzenlenen dokümanlarda, isteklilerin üzerinde ihale kalan mal ve hizmetleri hangi süreçlerde teslim edileceği belirtilir ve her bir tedarikçi belirlenen süreçlerde mal ve hizmetini teslim etmiş olur. Aksi halde ilgili yasalarda belirtilen müeyyidelerle karşılaşır. \n\nhttps://www.ogu.edu.tr/Web/IhaleDetay?kategori=6. \n \nDöner Sermaye İşletmesi tarafından alınan idari ve/veya destek hizmetlerinin tedarik sürecine ilişkin kriterleri, Eskişehir Osmangazi Üniversitesi Döner Sermaye İşletme Müdürlüğü tarafından uygulanan “Mal ve Hizmet Alma Süreci” ile belirlenmiştir. Buna göre;\n\n1. Kurumda, dışarıdan temin edilen destek hizmetlerinin ve malların uygunluğunu, kalitesini ve sürekliliğini güvence altına almak üzere bazı tanımlı süreçler ve mekanizmalar (tedarik süreci, uygunluk ve kalite kriterleri gibi) bulunmaktadır. \n\n2. Destek hizmetleri, 4734 sayılı Kamu İhale Kanunu, 4735 sayılı Kamu İhaleleri Sözleşme Kanunu, 5018 sayılı Kamu Mali Yönetimi ve Kontrol Kanunu ve diğer ilgili mevzuat çerçevesinde yürütülür.\n\n3. Fakültede, hizmet ve malların uygunluğu, kalitesi ve sürekliliğinin yönetiminden Dekanlık sorumludur. \n\n4. Birim Kalite Koordinatörlüğü personel ve öğrencilere yönelik Memnuniyet Anketi düzenlenerek sürdürülen hizmetlerin kalitesini ölçmeye ve gerekli iyileştirmeleri gerçekleştirmeye yönelik çalışmalar yapar.\n\n5. Koordinatörlük sürece ilişkin tespit ve tekliflerini Haziran ve Kasım aylarında Kalite Komisyonunda görüşülmek üzere Dekanlığa sunar. Komisyon, Temmuz ve Aralık aylarında toplanıp koordinatörlüklerden gelen raporları inceleyerek değerlendirmelerini Dekanlığa bildirir.\n\n6. Dekanlık, komisyonun değerlendirmeleri doğrultusunda paydaşların da görüşlerini alarak gerekli iyileştirmeleri yapar.\n\n7. Kurum, hizmet ve malların uygunluğu, kalitesi ve sürekliliğini sağlayan mekanizmaları izlemektedir.\n","aciklama_metni_en":"","uygulama_alanlari":"Fakülte''nin tümü","ilk_planlama_tarihi":"2025-10-01","izleme_mekanizmalari":"Akademik, idari ve öğrenci memnuniyet anketleri","uluslararasi_paydaslar":"-","performans_gostergeleri":"Öğrenci memnuniyet oranları / Akademik ve idari personel alınan mal ve hizmetlerden memnuniyet oranı / Tedarikçilerin hizmet ve mal sağlama sisteminden memnuniyet oranları","degerlendirme_iyilestirme_tarihi":"2026-07-31"}'::jsonb) ON CONFLICT (id) DO UPDATE SET olcut_adi = EXCLUDED.olcut_adi, kalite_el_kitabi = EXCLUDED.kalite_el_kitabi;
INSERT INTO public.alt_olcutler (id, kod, olcut_adi, olcut_adi_en, olcut_adi_ar, ana_baslik_id, kalite_el_kitabi) VALUES (63, 'E.5.1', 'Kamuoyunu Bilgilendirme', 'Public Information', 'المعلومات العامة', 5, '{"bgs_yeri":"","ic_paydaslar":"Kamuoyunu Bilgilendirme ve Hesap Verilebilirlik ( Akademik Personel)","dis_paydaslar":"","sorumlu_birim":"Akreditasyon Yönetim Komisyonu","aciklama_metni":"Amaç: Kamuoyunu bilgilendirme faaliyetlerinin kalitesini ölçen anketin, fakültenin güncel Kalite El Kitabı standartlarına ve ilkelerine uyumunun kontrol edilmesi.\n\nİçerik/Eylem: Ankette yer alan soruların, kurumun şeffaflık, hesap verilebilirlik ve kamuoyuna doğru bilgi aktarma misyonuyla örtüşüp örtüşmediği incelenir. Gerekirse anket genel usul ve esasları el kitabına göre güncellenir.","aciklama_metni_en":"Objective: To verify the alignment of the survey—which measures the quality of public information activities—with the faculty''s current Quality Handbook standards and principles.\n\nContent/Action: The questions included in the survey are reviewed to determine whether they align with the institution''s mission regarding transparency, accountability, and the accurate dissemination of information to the public. If necessary, the survey is updated in accordance with the general procedures and principles outlined in the handbook.","uygulama_alanlari":"","ilk_planlama_tarihi":"2026-06-30","izleme_mekanizmalari":"","uluslararasi_paydaslar":"","performans_gostergeleri":"","degerlendirme_iyilestirme_tarihi":"2026-06-30"}'::jsonb) ON CONFLICT (id) DO UPDATE SET olcut_adi = EXCLUDED.olcut_adi, kalite_el_kitabi = EXCLUDED.kalite_el_kitabi;
INSERT INTO public.alt_olcutler (id, kod, olcut_adi, olcut_adi_en, olcut_adi_ar, ana_baslik_id, kalite_el_kitabi) VALUES (64, 'E.5.2', 'Hesap Verme Yöntemleri', 'Methods of Accountability', 'أساليب المساءلة', 5, NULL) ON CONFLICT (id) DO UPDATE SET olcut_adi = EXCLUDED.olcut_adi, kalite_el_kitabi = EXCLUDED.kalite_el_kitabi;
